-- Part 4 (200 recipes)
insert into public.recipes (id, doc, status) values ('turkey_shepherds_pie', '{"id":"turkey_shepherds_pie","name":"Skillet Turkey Shepherd''s Pie","emoji":"🥧","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":55,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"milk","q":60},{"f":"butter","q":25},{"f":"ground_turkey","q":400},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"carrots","q":150},{"f":"garlic","q":0.2},{"f":"flour","q":10},{"f":"broth","q":200},{"f":"peas_frozen","q":100},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 minutes until a fork slides in without protest, then mash them with the butter, warm milk, and a good pinch of salt until smooth and spoonable.","Meanwhile brown the turkey in oil in an ovenproof skillet over medium-high heat for 5 minutes, then add the onion, diced carrots, and garlic and cook 5 minutes more until softening.","Sprinkle the flour and oregano over the meat, stir for a minute to cook off the raw taste, then pour in the broth and simmer 3 to 4 minutes until it thickens into a glossy gravy that coats the vegetables.","Fold in the peas, season with salt and pepper, then spread the mash over the filling in an even blanket and drag a fork across the top to raise ridges.","Broil 5 to 8 minutes until the ridges brown like toasted marshmallow and the gravy bubbles up around the edges; rest 5 minutes before serving so it slices instead of slides."],"tip":"Those fork ridges on the mash are not decoration — every peak is a future crispy bit, so rake generously."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_dan_dan_noodles', '{"id":"turkey_dan_dan_noodles","name":"Turkey Dan Dan-Style Peanut Noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"ground_turkey","q":350},{"f":"olive_oil","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":35},{"f":"peanut_butter","q":45},{"f":"sesame_oil","q":15},{"f":"sugar","q":5},{"f":"chili_powder","q":3},{"f":"spinach","q":100},{"f":"scallions","q":1}],"steps":["Soak or boil the rice noodles according to the package until just tender, then rinse briefly and reserve a cup of their cooking water.","Whisk the peanut butter, soy sauce, sesame oil, sugar, chili powder, and 100 ml of the hot noodle water into a sauce the texture of heavy cream.","Fry the turkey in olive oil over high heat for 6 to 7 minutes, pressing and scraping until the crumbles turn deeply browned and almost crispy — this is the crunchy topping, so push past golden.","Add the minced garlic and ginger to the meat for the last minute, then wilt the spinach into the pan just until it collapses.","Toss the noodles with the peanut sauce, loosening with extra noodle water if it tightens, then pile the crispy turkey and spinach on top and finish with sliced scallions."],"tip":"The sauce will seize into paste the moment it cools, so keep that noodle water close like a sous chef with a squeeze bottle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_pork_stir_fry', '{"id":"honey_garlic_pork_stir_fry","name":"Honey-Garlic Pork Loin Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"broccoli","q":400},{"f":"rice","q":120},{"f":"soy_sauce","q":45},{"f":"honey","q":30},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.4},{"f":"olive_oil","q":15}],"steps":["Start the rice in simmering water so it finishes while you cook, and slice the pork loin against the grain into thin strips no thicker than a pencil.","Heat the olive oil in your widest skillet over high heat until it shimmers, then sear the pork in a single layer for 2 minutes per side until the edges brown and crisp; work in two batches so it sizzles instead of steams.","Push the pork aside, add the broccoli florets with a splash of water, and cover for 3 minutes until they turn vivid green and just tender at the stem.","Whisk the soy sauce, honey, and minced garlic together, pour it over everything, and toss for 90 seconds until the sauce bubbles, thickens, and clings glossily to the meat.","Kill the heat, drizzle in the sesame oil for that toasty finishing aroma, and pile it all over the steamed rice."],"tip":"Freeze the pork for 15 minutes before slicing and it cuts into ribbons instead of squirming under your knife."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_loin_street_tacos', '{"id":"pork_loin_street_tacos","name":"Charred Pork Loin Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"tortillas","q":4},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Cut the pork loin into small half-inch cubes and season them aggressively with salt, cumin, and chili powder so every piece wears a rusty red coat.","Get the olive oil ripping hot in a cast-iron skillet over high heat, then spread the pork out and leave it alone for 3 minutes until the bottoms are deeply charred before tossing.","Add the sliced onion and bell pepper and cook 4 to 5 minutes more, until the peppers blister and the onions pick up sweet blackened edges.","Warm the tortillas directly over a burner flame for 20 seconds a side until they puff and catch a few toasty spots.","Pile the pork mixture into the tortillas, crown with mashed avocado, and finish with a hard squeeze of lime over everything."],"tip":"A screaming-hot pan is your marinade substitute — char is a flavor, and it works in half the time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_pork_penne', '{"id":"tuscan_pork_penne","name":"Tuscan Pork Loin Penne with Spinach","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"penne","q":160},{"f":"spinach","q":100},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"parmesan","q":30},{"f":"olive_oil","q":20}],"steps":["Drop the penne into well-salted boiling water and cook until just shy of al dente, reserving a cup of the starchy water before you drain.","Meanwhile, slice the pork loin into thin medallions, season with salt, pepper, and dried oregano, and sear in olive oil over medium-high heat for 2 to 3 minutes per side until golden with a blush of pink inside.","Lower the heat, add the sliced garlic and chopped tomatoes, and cook 4 minutes until the tomatoes slump into a rough, jammy sauce.","Tumble in the spinach by the handful and stir until it wilts to a silky dark green, about 1 minute.","Add the penne with a splash of pasta water and half the parmesan, tossing until the sauce turns creamy and coats every tube, then serve with the rest of the cheese showered on top."],"tip":"That reserved pasta water is liquid gold — it turns three ingredients into a sauce that tastes like it took all afternoon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_loin_yogurt_curry', '{"id":"pork_loin_yogurt_curry","name":"Pork Loin Tikka-Style Yogurt Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"greek_yogurt","q":150},{"f":"onion","q":1},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"spinach","q":100},{"f":"rice","q":120},{"f":"olive_oil","q":15}],"steps":["Cube the pork loin and toss it with a third of the yogurt, salt, garam masala, and turmeric, letting it sit while you prep — even 15 minutes tenderizes noticeably.","Cook the rice, then heat the olive oil in a deep pan over medium heat and fry the finely chopped onion for 8 minutes until deeply golden and smelling sweet, not just soft.","Add the minced garlic and chopped tomatoes and cook them down for 5 minutes, mashing occasionally, until the mixture darkens and the oil separates at the edges.","Add the pork with its marinade and simmer gently for 12 to 15 minutes, stirring now and then, until the meat is just cooked through and the sauce thickens to coat a spoon.","Stir in the spinach and remaining yogurt off the heat so it stays creamy rather than curdling, then serve the curry over the rice."],"tip":"Take the yogurt off direct heat before stirring it in — a broken curry tastes fine but looks like a science experiment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_souvlaki_pita_wraps', '{"id":"pork_souvlaki_pita_wraps","name":"Pork Souvlaki Pitas with Yogurt Sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"pita","q":2},{"f":"greek_yogurt","q":100},{"f":"cucumber","q":0.5},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":15}],"steps":["Cut the pork loin into one-inch chunks and marinate with olive oil, half the lemon''s juice, dried oregano, salt, and pepper for at least 15 minutes.","Grate the cucumber, squeeze it dry in your fist like you mean it, and stir it into the yogurt with a pinch of salt and the remaining lemon juice for a quick tzatziki-style sauce.","Thread the pork onto skewers and grill or broil on high for 10 to 12 minutes, turning twice, until the edges char and the centers are just barely blush.","Warm the pitas in a dry skillet for 30 seconds a side until soft and steamy.","Slather each pita with the yogurt sauce, pile on the pork, sliced tomatoes, and thin half-moons of onion, then fold and eat over a plate — there will be drips."],"tip":"Squeeze the grated cucumber until your forearm complains; watery tzatziki is the number-one wrap crime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_pork_potato_stew', '{"id":"mexican_pork_potato_stew","name":"Smoky Mexican Pork and Potato Stew","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":4,"ing":[{"f":"pork_loin","q":600},{"f":"broth","q":1000},{"f":"potatoes","q":500},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"lime","q":1},{"f":"olive_oil","q":20}],"steps":["Cube the pork loin, season with salt, paprika, and cumin, and brown it in olive oil over medium-high heat in a heavy pot until every side has a mahogany crust, about 6 minutes total.","Lift the pork out, then soften the chopped onion, bell peppers, and garlic in the same pot for 5 minutes, scraping up the browned bits stuck to the bottom — that fond is the soul of the stew.","Return the pork, pour in the broth, and bring to a simmer, skimming any foam that rises.","Add the potatoes cut into bite-size chunks and simmer uncovered for 25 to 30 minutes, until they are fork-tender and the broth has reduced to something silky.","Squeeze in the lime juice, taste for salt, and ladle into bowls while it steams."],"tip":"Brown the pork in batches even when you''re hungry — a crowded pot makes gray stew meat and gray stew meat makes sad soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_glazed_pork_sheet_pan', '{"id":"maple_glazed_pork_sheet_pan","name":"Maple-Glazed Pork Loin Sheet-Pan Dinner","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"sweet_potatoes","q":400},{"f":"broccoli","q":300},{"f":"maple_syrup","q":40},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 425°F (220°C) and cut the sweet potatoes into one-inch chunks, tossing them with half the olive oil and a big pinch of salt on a large sheet pan.","Roast the sweet potatoes alone for 15 minutes to get a head start — they always take longer than they claim.","Rub the pork loin with the remaining oil, minced garlic, salt, and plenty of black pepper, then nestle it in the center of the pan and scatter the broccoli florets around it.","Brush the pork with maple syrup and roast 20 to 25 minutes more, brushing once again halfway, until the glaze lacquers to a bronze shine and a thermometer in the center reads 145°F (63°C).","Rest the pork for 5 minutes before slicing thick — the juices need a moment to settle back where they belong."],"tip":"That 5-minute rest is not optional; carve early and you''ll watch your dinner''s juices run away across the cutting board."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_pork_noodle_soup', '{"id":"gingery_pork_noodle_soup","name":"Pork Loin and Rice Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"pork_loin","q":500},{"f":"rice_noodles","q":200},{"f":"broth","q":1500},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15}],"steps":["Slice the pork loin into paper-thin strips and the mushrooms into thick slabs while the broth comes to a gentle simmer in a large pot.","Add the smashed garlic and soy sauce to the broth and let it burble for 10 minutes so the liquid picks up a deep, savory backbone.","Slide in the mushrooms and simmer 5 minutes until they turn slippery and bob willingly in the broth.","Add the pork strips and cook just 2 to 3 minutes — thin slices poach fast, and overcooked loin turns to erasers — then stir in the spinach until it collapses.","Meanwhile, soak the rice noodles in hot water until pliable, divide them among four bowls, ladle the soup over top, and finish each bowl with a fragrant drizzle of sesame oil."],"tip":"Keep the noodles out of the pot until serving time, or by tomorrow your soup will be a casserole."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_pork_milanese', '{"id":"crispy_pork_milanese","name":"Crispy Pork Loin Milanese with Lemony Spinach","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"flour","q":60},{"f":"eggs","q":2},{"f":"parmesan","q":40},{"f":"spinach","q":100},{"f":"lemon","q":1},{"f":"olive_oil","q":30}],"steps":["Slice the pork loin into four cutlets and pound each between plastic wrap to a quarter-inch thickness — you want them thin enough to cook before the crust burns.","Set up two dishes: seasoned flour mixed with half the grated parmesan in one, beaten eggs in the other, then dredge each cutlet through flour, egg, and flour again, pressing so the coating hugs the meat.","Heat the olive oil in a large skillet over medium-high until a pinch of flour sizzles instantly, then fry the cutlets 2 to 3 minutes per side until deeply golden, crackly, and cooked through.","Drain them on a rack, not paper towels, and hit them with flaky salt while they''re still glistening.","Toss the fresh spinach with lemon juice, a thread of oil, and the remaining parmesan, then pile it right on top of the hot cutlets so it wilts ever so slightly."],"tip":"A rack keeps the crust crisp; paper towels steam the underside and undo all your good frying work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smothered_pork_mushroom_skillet', '{"id":"smothered_pork_mushroom_skillet","name":"Smothered Pork Loin with Mushroom Gravy and Mash","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"mushrooms","q":250},{"f":"potatoes","q":500},{"f":"onion","q":1},{"f":"broth","q":250},{"f":"butter","q":30},{"f":"milk","q":100}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 to 18 minutes until a knife slides through without resistance, then mash with the milk and half the butter until fluffy and keep warm.","Season two thick pork loin steaks with salt and pepper and sear them in the remaining butter over medium-high heat for 3 to 4 minutes per side, until burnished brown, then set aside on a plate.","In the same skillet, cook the sliced mushrooms and onion for 8 minutes, resisting the urge to stir constantly, until the mushrooms release their water and then brown at the edges.","Pour in the broth and scrape the skillet clean, simmering 5 minutes until the liquid reduces by half into a loose, savory gravy.","Return the pork and its plate juices, spoon the mushrooms over top, and simmer 2 gentle minutes before serving the whole affair over the mash."],"tip":"Mushrooms brown only after their water cooks off, so let them sputter and shrink in peace before you judge them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_black_bean_rice_bowl', '{"id":"pork_black_bean_rice_bowl","name":"Cumin Pork and Black Bean Rice Bowl","emoji":"🥑","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"rice","q":120},{"f":"black_beans","q":200},{"f":"avocado","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Get the rice simmering, then dice the pork loin into small cubes and toss with salt, cumin, and a little chili powder until evenly dusted.","Heat the olive oil in a skillet over medium-high and cook the pork with the diced onion for 6 to 8 minutes, stirring occasionally, until the cubes are browned outside and just cooked through.","Add the black beans with a splash of water and warm them 2 minutes, mashing a few against the pan so they get creamy and bind to the pork.","Dice the tomatoes and toss with lime juice and a pinch of salt for a thirty-second salsa.","Build the bowls: rice on the bottom, the pork and beans in the middle, then the tomato salsa and fanned slices of avocado on top with a last squeeze of lime."],"tip":"Mash a spoonful of the beans into the pan and suddenly your bowl has a sauce nobody had to make."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_herb_pork_loin_roast', '{"id":"lemon_herb_pork_loin_roast","name":"Lemon-Herb Pork Loin Roast with Vegetables","emoji":"🍖","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"potatoes","q":400},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":25}],"steps":["Heat the oven to 400°F (200°C) and rub the pork loin all over with half the olive oil, minced garlic, lemon zest, dried rosemary, salt, and cracked pepper.","Sear the roast in a hot ovenproof pan for 2 to 3 minutes per side until the whole surface is golden and your kitchen smells like a taverna.","Toss the chunked potatoes, thick carrot coins, and onion wedges with the rest of the oil and scatter them around the pork.","Roast for 35 to 45 minutes, turning the vegetables once, until the potatoes are crusty at the edges and the pork''s center hits 145°F (63°C) on a thermometer.","Rest the roast under foil for 10 minutes, squeeze the lemon over the pan vegetables, and carve into thick, juicy slices."],"tip":"Buy a meat thermometer; pork loin gives you about a five-degree window between succulent and shoe leather."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_pork_feta_spinach_salad', '{"id":"warm_pork_feta_spinach_salad","name":"Warm Pork Loin, Feta, and Spinach Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"spinach","q":150},{"f":"feta","q":60},{"f":"tomato","q":2},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":25}],"steps":["Slice the pork loin into medallions, season with salt, pepper, and dried oregano, and sear in half the olive oil over medium-high heat for 3 minutes per side until golden with just a whisper of pink inside.","While the pork rests, pile the spinach into a wide bowl with the chopped tomatoes, sliced cucumber, and paper-thin onion.","Whisk the remaining olive oil with the lemon juice, a pinch of salt, and pepper until it emulsifies into a cloudy dressing.","Slice the rested pork and lay it warm over the salad so the spinach softens slightly under the heat.","Drizzle the dressing over everything, crumble the feta on top, and toss gently at the table so the cheese stays in proud chunks."],"tip":"Warm meat plus cold crisp salad is the whole trick here, so dress and serve it the minute the pork is sliced."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_glazed_salmon_sheet_pan', '{"id":"maple_glazed_salmon_sheet_pan","name":"Maple-Glazed Salmon Sheet Pan with Sweet Potatoes","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":40,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"sweet_potatoes","q":450},{"f":"broccoli","q":300},{"f":"olive_oil","q":20},{"f":"maple_syrup","q":30},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 425F and cut the sweet potatoes into 2cm cubes, tossing them on a rimmed sheet pan with half the olive oil and a good pinch of salt.","Roast the sweet potatoes alone for 15 minutes until the edges just start to caramelize, then push them to one side of the pan.","Add the broccoli florets tossed in the remaining oil, nestle the salmon fillets skin-side down in the center, and brush the fish with maple syrup whisked with the minced garlic.","Roast everything for 12 to 14 minutes more, until the glaze is bubbling at the edges and the salmon flakes when nudged with a fork but still looks rosy in the thickest part.","Rest the pan for 3 minutes so the juices settle, then spoon any syrupy pan drippings back over the fish before serving."],"tip":"Give the sweet potatoes their 15-minute head start or you will eat perfect salmon with crunchy disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('teriyaki_salmon_rice_bowl', '{"id":"teriyaki_salmon_rice_bowl","name":"Sticky Teriyaki Salmon Rice Bowl","emoji":"🍣","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"rice","q":150},{"f":"broccoli","q":300},{"f":"soy_sauce","q":30},{"f":"honey","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Rinse the rice until the water runs clear, then simmer it covered with 300ml of water for 15 minutes and let it steam off the heat while you cook everything else.","Whisk the soy sauce, honey, and minced garlic in a small bowl until the honey dissolves into a glossy glaze.","Sear the salmon fillets skin-side down in the sesame oil over medium-high heat for 4 minutes, until the skin crackles and releases from the pan on its own.","Flip the fish, pour in the glaze, and let it bubble and reduce for 2 to 3 minutes, spooning it over the salmon until it coats the fillets like lacquer.","Steam the broccoli florets for 4 minutes until bright green with a slight bite, then pile everything over the rice and drizzle with the pan sauce."],"tip":"Do not touch the salmon while the skin sears; it will release from the pan the moment it is actually crisp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_spinach_yogurt_curry', '{"id":"salmon_spinach_yogurt_curry","name":"Salmon and Spinach Yogurt Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":40,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"greek_yogurt","q":150},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"butter","q":15},{"f":"rice","q":120}],"steps":["Start the rice simmering in salted water, then melt the butter in a deep skillet and cook the sliced onion over medium heat for 8 minutes until deeply golden and sweet-smelling.","Stir in the minced garlic with a generous spoonful of curry spices and toast for 60 seconds, until the pan smells warm and slightly nutty.","Add the spinach in handfuls with a splash of water, letting each batch collapse into a silky green tangle before adding the next.","Cut the salmon into large chunks, nestle them into the greens, cover, and simmer gently for 6 to 7 minutes until the fish turns opaque and flakes at a poke.","Pull the pan off the heat, wait 2 minutes, then stir in the yogurt until the sauce turns pale and creamy, and serve it spooned over the rice."],"tip":"Stir the yogurt in off the heat or it will split into curds and regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_salmon_penne', '{"id":"lemon_salmon_penne","name":"Lemon Salmon Penne with Wilted Spinach","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"penne","q":150},{"f":"spinach","q":100},{"f":"parmesan","q":40},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1}],"steps":["Boil the penne in aggressively salted water until just shy of al dente, and scoop out a mugful of the starchy cooking water before you drain.","Meanwhile, sear the salmon in olive oil over medium-high heat for 3 minutes per side until golden outside and barely translucent within, then break it into large flakes on a plate.","Soften the sliced garlic in the same pan for 30 seconds, add the spinach, and toss until it wilts into glossy ribbons.","Return the pasta to the pan with the lemon zest, lemon juice, and a generous splash of pasta water, tossing over the heat until the liquid turns silky.","Fold in the grated parmesan and the flaked salmon gently, loosening with more pasta water until the sauce clings to every tube, and serve immediately."],"tip":"Fold the salmon in last and gently, unless you enjoy expensive fish confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_salmon_couscous_plate', '{"id":"greek_salmon_couscous_plate","name":"Greek Salmon and Feta Couscous Plate","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"couscous","q":120},{"f":"cucumber","q":1},{"f":"feta","q":60},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Pour 150ml of boiling salted water over the couscous, cover the bowl with a plate, and leave it for 5 minutes before fluffing with a fork into light, separate grains.","Rub the salmon with half the olive oil, salt, and dried oregano, and roast at 400F for 12 minutes until it flakes but still glistens at the center.","Dice the cucumber small and toss it through the couscous with the lemon zest, lemon juice, and the remaining olive oil.","Crumble the feta over the couscous so it stays in creamy, briny pockets rather than dissolving.","Set the salmon fillets on top, spoon over any roasting juices, and finish with a final squeeze of lemon and a crack of black pepper."],"tip":"Fluff couscous with a fork, never a spoon, unless your dinner plans include edible spackle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('blackened_salmon_tacos', '{"id":"blackened_salmon_tacos","name":"Blackened Salmon Tacos with Avocado Crema","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"tortillas","q":4},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"romaine","q":0.5},{"f":"lemon","q":1}],"steps":["Mash the avocado with the sour cream, half the lemon juice, and a pinch of salt until it is smooth enough to drizzle but thick enough to cling.","Coat the salmon generously with paprika, cumin, and salt, pressing the spices on so they form a crust.","Sear the fillets in a screaming-hot dry skillet for 3 minutes per side, until the spice crust turns nearly black and fragrant and the fish flakes into big juicy pieces.","Char the tortillas directly over a flame or in the empty skillet for 20 seconds a side, until puffed and speckled brown.","Shred the romaine finely, pile it into the warm tortillas, top with chunks of blackened salmon, and finish with the crema and the last squeeze of lemon."],"tip":"Blackened means bold and smoky, not a smoke-alarm serenade, so open a window before the skillet gets loud."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_salmon_potato_chowder', '{"id":"smoky_salmon_potato_chowder","name":"Smoky Salmon and Potato Chowder","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"potatoes","q":600},{"f":"milk","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3}],"steps":["Melt the butter in a heavy pot and sweat the diced onion with a pinch of salt over medium heat for 6 minutes, until translucent and sweet but not browned.","Stir in the minced garlic and a big pinch of paprika, then add the potatoes cut into 2cm chunks with 400ml of water and a teaspoon of salt.","Simmer for 15 minutes until a knife slides through the potatoes, then mash a few chunks against the side of the pot to thicken the broth naturally.","Pour in the milk, bring it back to a bare shiver of a simmer, and slide in the salmon cut into large bite-sized pieces.","Poach gently for 5 to 6 minutes, until the fish turns pale pink and flakes without resistance, then season with black pepper and serve while it steams."],"tip":"Chowder rewards patience: keep it at a whisper of a simmer after the milk goes in and it will keep its silk instead of curdling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_salmon_noodle_stirfry', '{"id":"sesame_salmon_noodle_stirfry","name":"Sesame Salmon Noodle Stir-Fry","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"rice_noodles","q":150},{"f":"broccoli","q":250},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":12},{"f":"honey","q":15},{"f":"garlic","q":0.3}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still slightly firm, then drain and rinse under cold water so they do not clump.","Cut the salmon into 3cm cubes and sear them in half the sesame oil over high heat for 2 minutes per side, until golden at the edges, then set them aside.","Stir-fry the broccoli florets and sliced bell pepper in the remaining oil for 3 to 4 minutes, until the pepper blisters and the broccoli turns emerald with charred tips.","Add the minced garlic for 30 seconds, then toss in the noodles with the soy sauce and honey, dragging everything through the pan until the noodles turn glossy.","Return the salmon cubes, toss once or twice with a light hand so they stay intact, and serve straight from the smoking-hot pan."],"tip":"A stir-fry waits for no one, so chop everything before the pan even thinks about heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('herbed_salmon_burgers', '{"id":"herbed_salmon_burgers","name":"Herbed Salmon Burgers with Lemon-Yogurt Sauce","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","eggs","gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"eggs","q":1},{"f":"bread","q":2},{"f":"greek_yogurt","q":100},{"f":"romaine","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":15}],"steps":["Tear the bread into crumbs and pulse or finely chop the salmon until it holds together like coarse ground meat, leaving a few larger flakes for texture.","Mix the salmon with the crumbs, egg, lemon zest, salt, and pepper, then chill the mixture for 10 minutes so the patties firm up.","Shape two thick patties and pan-fry them in the olive oil over medium heat for 4 minutes per side, until deeply golden with an interior that is just cooked through and still moist.","Stir the yogurt with the lemon juice and a pinch of salt into a bright, tangy sauce while the burgers rest for 2 minutes.","Serve the patties on crisp romaine leaves with the sauce spooned generously on top."],"tip":"Chill the patties before frying; warm salmon mix flops like a handshake from a jellyfish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_souvlaki_skewers', '{"id":"salmon_souvlaki_skewers","name":"Salmon Souvlaki Skewers with Yogurt Sauce and Pita","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"greek_yogurt","q":120},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.2},{"f":"pita","q":2}],"steps":["Cut the salmon into 3cm cubes and toss them with the olive oil, lemon zest, half the minced garlic, oregano, and salt, marinating for 15 minutes while you prep the rest.","Grate the cucumber, squeeze out the water with your fists, and stir it into the yogurt with the remaining garlic and a squeeze of lemon for a quick tzatziki-style sauce.","Thread the salmon onto skewers alternating with chunks of bell pepper and onion, packing them snugly so nothing spins.","Grill or broil the skewers 4 minutes per side, until the edges char and the fish turns opaque but still yields to gentle pressure.","Warm the pitas on the grill for 30 seconds a side and serve the skewers on top with the cold yogurt sauce and the last lemon wedges."],"tip":"Squeeze the grated cucumber like it owes you money, or your sauce becomes soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_kedgeree_skillet', '{"id":"salmon_kedgeree_skillet","name":"Salmon Kedgeree with Soft-Boiled Eggs","emoji":"🍳","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","eggs","dairy"],"time":40,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"rice","q":140},{"f":"eggs","q":2},{"f":"butter","q":20},{"f":"onion","q":1},{"f":"spinach","q":100}],"steps":["Lower the eggs into boiling water for exactly 7 minutes, then plunge them into cold water so the yolks stay jammy, and peel and halve them.","Simmer the rice in salted water until just tender, drain it well, and spread it out to steam dry so the grains stay distinct.","Melt the butter in a wide skillet and fry the sliced onion with a heaped teaspoon of curry powder for 8 minutes, until golden and intensely fragrant.","Lay the salmon on top of the onions with a splash of water, cover, and steam for 6 minutes until it flakes, then break it into chunks right in the pan.","Fold in the rice and spinach and toss over medium heat until the leaves wilt and every grain turns turmeric-gold, then crown with the halved eggs and plenty of black pepper."],"tip":"Seven minutes for the eggs, not eight; kedgeree deserves yolks that flow, not sulk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('seared_salmon_avocado_salad', '{"id":"seared_salmon_avocado_salad","name":"Seared Salmon and Avocado Salad","emoji":"🥑","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"cucumber","q":1},{"f":"olive_oil","q":25},{"f":"lemon","q":1}],"steps":["Pat the salmon bone-dry, season it boldly with salt and pepper, and sear it skin-side down in a hot skillet with a third of the olive oil for 5 minutes, until the skin shatters like a chip.","Flip and cook 2 minutes more, until the sides look opaque but the center stays blushing, then rest the fillets on a plate.","Whisk the remaining olive oil with the lemon juice, a pinch of salt, and black pepper until the dressing looks cloudy and unified.","Chop the romaine into ribbons and toss it with the sliced cucumber and the dressing until every leaf glistens.","Fan the sliced avocado over the salad, break the warm salmon into large pieces on top, and grate over the lemon zest to finish."],"tip":"Warm fish plus cold crisp lettuce is the whole trick, so dress the leaves before the salmon cools."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_salmon_foil_packets', '{"id":"lemon_garlic_salmon_foil_packets","name":"Lemon-Garlic Salmon Foil Packets with Baby Potatoes","emoji":"🔥","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":45,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"potatoes","q":450},{"f":"spinach","q":100},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"lemon","q":1}],"steps":["Heat the oven to 425F and parboil the potatoes, halved, in salted water for 10 minutes so they finish cooking in step with the fish.","Lay out two large sheets of foil and divide the potatoes, a handful of spinach, and the sliced garlic between them, drizzling each pile with olive oil.","Set a salmon fillet on each mound, top with thin lemon slices, season with salt, pepper, and dried herbs, and crimp the foil into tightly sealed packets.","Bake the packets on a sheet pan for 15 to 17 minutes, until they puff slightly and hiss with steam.","Open each packet at the table carefully, letting the lemony garlic steam billow out, and spoon the pooled juices over everything."],"tip":"Crimp the foil like you mean it; a leaky packet steals both the steam and the drama."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baja_shrimp_tacos', '{"id":"baja_shrimp_tacos","name":"Baja Shrimp Tacos with Lime Crema","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"tortillas","q":4},{"f":"cabbage","q":0.3},{"f":"avocado","q":1},{"f":"greek_yogurt","q":60},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"chili_powder","q":4},{"f":"cumin","q":2},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Pat the shrimp bone-dry, then toss with chili powder, cumin, minced garlic, and half the salt until every curl is rusty red.","Stir the greek yogurt with the zest and juice of half the lime plus a pinch of salt to make a quick crema, and shred the cabbage into fine ribbons.","Heat the olive oil in a heavy skillet over medium-high until it shimmers, then sear the shrimp in a single layer for 90 seconds per side, until pink with charred edges.","Warm the tortillas directly over a burner flame or in a dry pan for 20 seconds a side until puffed and lightly blistered.","Pile each tortilla with cabbage, shrimp, sliced avocado, a drizzle of crema, torn cilantro, and a squeeze of the remaining lime, and serve while everything is still steaming."],"tip":"Shrimp go from succulent to eraser in about 45 seconds, so pull them the instant the tails curl into a loose C."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_spaghetti', '{"id":"shrimp_scampi_spaghetti","name":"Garlic Butter Shrimp Scampi Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":170},{"f":"shrimp","q":300},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"garlic","q":0.5},{"f":"lemon","q":1},{"f":"broth","q":100},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Boil the spaghetti in generously salted water until just shy of al dente, about 9 minutes, and scoop out a mug of the starchy cooking water before draining.","Meanwhile, warm the olive oil and half the butter in a wide skillet over medium heat, add the thinly sliced garlic, and cook 60 to 90 seconds until fragrant and pale gold, not brown.","Raise the heat, add the shrimp with the salt and black pepper, and sear about 2 minutes total until they blush pink, then lift them out to a plate.","Pour the broth and the juice of the lemon into the pan, scraping up any golden bits, and simmer 2 minutes until slightly reduced.","Return the shrimp with the drained pasta, remaining butter, and a splash of pasta water, tossing hard over the heat until the sauce turns glossy and clings to every strand.","Shower with chopped parsley and lemon zest, and serve straight from the skillet."],"tip":"If your garlic goes brown, start over — burnt garlic will bully every other flavor in the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_lime_shrimp_noodles', '{"id":"peanut_lime_shrimp_noodles","name":"Peanut-Lime Shrimp Rice Noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["shellfish","nuts","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"shrimp","q":300},{"f":"peanut_butter","q":45},{"f":"soy_sauce","q":30},{"f":"lime","q":1},{"f":"honey","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"bell_pepper","q":1},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still slightly chewy, then drain and rinse under cool water so they stop cooking.","Whisk the peanut butter, soy sauce, honey, lime juice, and 3 tablespoons of warm water into a sauce the texture of heavy cream.","Heat the sesame oil in a wok over high heat and stir-fry the shrimp with the grated ginger and garlic for about 2 minutes, until pink and fragrant.","Add the sliced bell pepper and julienned carrots and toss another 2 minutes, keeping them crisp enough to snap.","Add the noodles and peanut sauce and toss with tongs for a final minute until every noodle is slicked and the sauce bubbles at the edges, then finish with sliced scallions and extra lime."],"tip":"Rice noodles keep drinking sauce after plating, so leave the mixture looking a touch too saucy in the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_masala_skillet_curry', '{"id":"shrimp_masala_skillet_curry","name":"Shrimp Masala with Fragrant Rice","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"rice","q":140},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"crushed_tomatoes","q":300},{"f":"coconut_milk","q":150},{"f":"garam_masala","q":5},{"f":"turmeric","q":2},{"f":"cumin","q":3},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Start the rice simmering in salted water so it finishes alongside the curry, about 15 minutes covered, then rest it off the heat.","Cook the finely diced onion in the olive oil over medium heat for 8 to 10 minutes, stirring, until deeply golden at the edges — this is where the sauce gets its sweetness.","Add the grated ginger, minced garlic, garam masala, turmeric, cumin, and chili powder and fry 60 seconds until the spices smell toasty and darken a shade.","Pour in the crushed tomatoes and simmer 8 minutes until the sauce thickens and the oil beads at the edges, then stir in the coconut milk.","Slide in the shrimp and poach gently for 3 to 4 minutes, just until opaque, then scatter with cilantro and serve over the fluffed rice."],"tip":"The curry is only as good as the onions — if they are pale, you quit five minutes too early."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_soup_2', '{"id":"coconut_lime_shrimp_soup_2","name":"Coconut-Lime Shrimp Noodle Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":500},{"f":"broth","q":1000},{"f":"coconut_milk","q":400},{"f":"rice_noodles","q":120},{"f":"mushrooms","q":200},{"f":"ginger","q":25},{"f":"garlic","q":0.4},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Warm the oil in a soup pot over medium heat and sizzle the sliced ginger and smashed garlic for a minute until the kitchen smells sharp and citrusy.","Pour in the broth and coconut milk, bring to a bare simmer, and let the aromatics steep for 10 minutes — do not boil hard or the coconut milk will split.","Add the sliced mushrooms and simmer 5 minutes until they turn silky and sink.","Drop in the rice noodles and cook 4 to 5 minutes until tender, then add the shrimp and poach 3 minutes, just until they curl and go opaque.","Kill the heat, season with salt and the juice of both limes until the broth tastes bright as well as rich, and ladle into bowls topped with scallions and cilantro."],"tip":"Add the lime juice off the heat — boiled lime turns bitter and sulky."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_couscous_sunshine_bowl', '{"id":"shrimp_couscous_sunshine_bowl","name":"Mediterranean Shrimp Couscous Bowls","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"shrimp","q":300},{"f":"cherry_tomatoes","q":150},{"f":"cucumber","q":0.5},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"oregano","q":2},{"f":"parsley","q":0.3},{"f":"salt","q":3}],"steps":["Pour boiling salted water over the couscous, cover, and let it steam for 5 minutes, then fluff with a fork and dress with a third of the olive oil and half the lemon juice.","Toss the shrimp with the minced garlic, oregano, and a pinch of salt while a skillet gets hot over medium-high heat.","Sear the shrimp in a little of the oil for about 2 minutes per side until they take on golden freckles and smell sweet.","Halve the cherry tomatoes, dice the cucumber, and fold them through the couscous with the olives, chopped parsley, and remaining oil and lemon.","Mound the couscous into bowls, crown with the hot shrimp and crumbled feta, and grind black pepper generously over the top."],"tip":"Dress the couscous while it is warm — cold grains absorb dressing about as well as gravel does."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_shrimp_greek_salad', '{"id":"charred_shrimp_greek_salad","name":"Charred Shrimp Greek Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein","gluten-free","low-carb"],"allergens":["shellfish","dairy"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"romaine","q":1},{"f":"feta","q":50},{"f":"olives","q":40},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Toss the shrimp with a spoonful of the olive oil, half the oregano, salt, and pepper, and let them sit while you get a cast-iron pan screaming hot.","Sear the shrimp without moving them for 2 minutes until deeply charred on one side, flip, and give them 60 seconds more, then set aside.","Chop the romaine into wide ribbons and pile it into a big bowl with the sliced cucumber, tomato wedges, paper-thin onion, and olives.","Whisk the remaining olive oil with the lemon juice, remaining oregano, and a pinch of salt until it looks cloudy and thick.","Toss the salad with the dressing until every leaf glistens, top with the warm shrimp and big crumbles of feta, and eat before the lettuce loses its crunch."],"tip":"A hot dry pan and patient hands make the char — poke the shrimp early and you get steam, not sear."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_boil_sheet_pan', '{"id":"shrimp_boil_sheet_pan","name":"Sheet-Pan Shrimp Boil with Corn and Potatoes","emoji":"🍤","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"potatoes","q":400},{"f":"corn_frozen","q":200},{"f":"butter","q":40},{"f":"olive_oil","q":15},{"f":"paprika","q":5},{"f":"chili_powder","q":2},{"f":"oregano","q":2},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 425F and cut the potatoes into 2-centimeter chunks so they cook through in the time allotted.","Toss the potatoes on a sheet pan with the olive oil, half the paprika, and half the salt, and roast 20 minutes until the edges start to brown and crisp.","Melt the butter with the minced garlic, remaining paprika, chili powder, and oregano until it smells like a seafood shack in the best way.","Push the potatoes to one side, add the shrimp and corn to the pan, pour the spiced butter over everything, and toss to coat.","Roast 8 to 10 minutes more, until the shrimp are pink and the corn has toasty spots, then squeeze the lemon over the whole pan and shower with parsley.","Serve straight off the sheet pan with plenty of napkins."],"tip":"Give the potatoes their 20-minute head start — shrimp and raw potatoes finish on completely different clocks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_shrimp_lettuce_cups', '{"id":"ginger_shrimp_lettuce_cups","name":"Ginger Shrimp Lettuce Cups with Cashews","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free","low-carb"],"allergens":["shellfish","soy","gluten","sesame","nuts"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"romaine","q":1},{"f":"mushrooms","q":150},{"f":"carrots","q":100},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"cashews","q":30}],"steps":["Chop the shrimp into rough thumbnail-sized pieces and finely dice the mushrooms and carrots so everything spoons neatly into a leaf.","Separate the romaine into whole leaves, keeping the crisp inner cups for serving and saving floppy outer leaves for another salad.","Heat the olive oil in a wok over high heat, stir-fry the mushrooms 3 minutes until their moisture cooks off and they brown, then add the carrots, ginger, and garlic for 1 minute more.","Add the shrimp and soy sauce and stir-fry 2 minutes until the shrimp turn opaque and the sauce reduces to a light glaze.","Take the pan off the heat, stir in the sesame oil and sliced scallions, then spoon into the lettuce cups and top with roughly chopped cashews for crunch."],"tip":"Sesame oil is a finishing perfume, not a cooking fat — add it off the heat or it goes flat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_shrimp_parmesan_risotto', '{"id":"lemon_shrimp_parmesan_risotto","name":"Lemon Shrimp Risotto-Style Rice","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":150},{"f":"shrimp","q":300},{"f":"broth","q":700},{"f":"butter","q":20},{"f":"parmesan","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"peas_frozen","q":100},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2},{"f":"salt","q":3}],"steps":["Keep the broth warm in a small pot on the back burner — cold broth stalls the rice every time you add it.","Soften the finely diced onion in the olive oil over medium heat for 4 minutes, add the garlic and rice, and toast, stirring, until the grains turn translucent at the edges, about 2 minutes.","Add the warm broth a ladleful at a time, stirring often and waiting until each addition is nearly absorbed, for 18 to 20 minutes until the rice is creamy but still has a gentle bite.","Stir in the peas and the raw shrimp with the last ladle of broth and cook 3 to 4 minutes, until the shrimp are pink and the peas bright green.","Off the heat, beat in the butter, grated parmesan, lemon zest, and juice until the rice ripples like slow lava, then season with salt and plenty of black pepper.","Serve immediately in warm bowls — risotto waits for no one."],"tip":"Proper risotto should spread lazily when you shake the bowl; if it stands in a proud mound, loosen it with one more splash of broth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_veracruz_style_skillet', '{"id":"salmon_veracruz_style_skillet","name":"Salmon Veracruz-Style Skillet","emoji":"🫒","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"crushed_tomatoes","q":300},{"f":"olives","q":50},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"rice","q":130},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Get the rice simmering in salted water, covered, for 15 minutes, then let it rest off the heat while the sauce comes together.","Warm the olive oil in a deep skillet over medium heat and cook the sliced onion and bell pepper for 6 minutes until soft and just starting to caramelize.","Stir in the garlic, oregano, and chili powder for 30 seconds, then add the crushed tomatoes and sliced olives and simmer 8 minutes until the sauce thickens enough to hold a spoon-trail.","Nestle the salmon pieces into the sauce, cover, and cook 6 to 8 minutes, until they flake easily and turn opaque all the way through.","Brighten with lime juice, taste for salt — the olives carry plenty — and serve ladled over the rice with cilantro on top."],"tip":"Taste before salting; olives are little sodium grenades and they already went off in your sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_pea_pulao', '{"id":"shrimp_pea_pulao","name":"One-Pot Shrimp and Pea Pulao","emoji":"🍚","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"rice","q":160},{"f":"shrimp","q":300},{"f":"peas_frozen","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"turmeric","q":3},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"cinnamon","q":1},{"f":"olive_oil","q":20},{"f":"broth","q":400},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3}],"steps":["Rinse the rice in a sieve until the water runs nearly clear — this is the difference between distinct grains and porridge.","In a lidded pot, fry the sliced onion in the olive oil over medium heat for 8 minutes until golden brown and sweet, then bloom the ginger, garlic, cumin, turmeric, garam masala, and cinnamon for 45 seconds.","Stir in the rice to coat every grain in the spiced oil, pour in the broth, and bring to a boil.","Cover, drop the heat to its lowest setting, and cook 12 minutes without peeking, then quickly scatter the shrimp and peas over the surface and re-cover for 5 minutes more so they steam through.","Rest the pot off the heat for 5 minutes, then fold everything together gently with a fork, finishing with lemon juice and chopped cilantro."],"tip":"Every lid-lift costs you steam and even cooking, so trust the timer and keep your curiosity to yourself."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('new_england_shrimp_rolls', '{"id":"new_england_shrimp_rolls","name":"New England-Style Shrimp Salad Rolls","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"bread","q":4},{"f":"greek_yogurt","q":80},{"f":"celery","q":60},{"f":"scallions","q":0.3},{"f":"lemon","q":1},{"f":"butter","q":15},{"f":"romaine","q":0.2},{"f":"black_pepper","q":2},{"f":"salt","q":3}],"steps":["Poach the shrimp in barely simmering salted water for 2 to 3 minutes, just until pink and curled, then plunge them into ice water so they stay snappy.","Pat the shrimp very dry, chop into chunky bites, and fold with the greek yogurt, finely diced celery, sliced scallions, lemon zest and juice, salt, and a heavy grind of black pepper.","Chill the salad for 10 minutes while you butter the bread on both sides.","Toast the buttered bread in a skillet over medium heat until golden and crisp, about 2 minutes per side, folding each slice gently into a roll shape while warm.","Line each toasted roll with a crisp romaine leaf, pile the shrimp salad high, and serve cold filling against warm bread — the contrast is the whole point."],"tip":"Wet shrimp make weepy salad, so blot them like you are drying evidence."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('open_face_tuna_melt', '{"id":"open_face_tuna_melt","name":"Broiler-Blistered Open-Face Tuna Melt","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":220},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.5},{"f":"lemon","q":0.5},{"f":"butter","q":20}],"steps":["Set the broiler to high and position a rack about 15 centimeters below the element.","Drain the tuna firmly, then fold it with the greek yogurt, finely minced onion, a squeeze of lemon, and a good pinch of salt and black pepper until it holds together like a rough spread.","Butter the bread slices and toast them under the broiler for 2 minutes, until the edges turn golden and crisp so they can carry the filling without sagging.","Pile the tuna mixture onto the toasted sides, blanket each slice with cheddar all the way to the crust, and broil 3 to 4 minutes until the cheese bubbles and blisters with brown freckles.","Rest the melts for 1 minute so the cheese sets, then finish with cracked pepper and eat while the toast still crackles."],"tip":"Cheese to the very edge is non-negotiable — naked crust burns while covered crust caramelizes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tuna_oat_patties', '{"id":"crispy_tuna_oat_patties","name":"Crispy Lemon-Herb Tuna Patties","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein","gluten-free"],"allergens":["fish","eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"eggs","q":2},{"f":"oats","q":60},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"greek_yogurt","q":100}],"steps":["Pulse the oats briefly or crush them in a bag until they resemble coarse crumbs, then stir them with the well-drained tuna, eggs, grated onion, minced garlic, the zest of the lemon, and a generous pinch of salt.","Rest the mixture for 10 minutes so the oats drink up the moisture — it should pack like damp sand, not batter.","Shape into 6 patties about 2 centimeters thick, pressing firmly so they survive the flip.","Heat the olive oil in a heavy skillet over medium heat until it shimmers, then fry the patties 3 to 4 minutes per side until deeply golden and crusted, flipping only once.","Whisk the greek yogurt with the lemon''s juice and a pinch of salt, and serve the hot patties dolloped with the tangy sauce."],"tip":"If a test patty falls apart in the pan, the fix is patience, not more egg — give the oats five more minutes to hydrate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_nicoise_potato_salad', '{"id":"tuna_nicoise_potato_salad","name":"Pantry Nicoise-Style Tuna and Potato Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":30,"servings":2,"ing":[{"f":"tuna_canned","q":200},{"f":"potatoes","q":400},{"f":"eggs","q":3},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"broccoli","q":150},{"f":"olive_oil","q":40},{"f":"lemon","q":1}],"steps":["Simmer the potatoes whole in well-salted water for 15 to 18 minutes until a knife slides in without resistance, adding the eggs for the final 9 minutes and the broccoli florets for the final 3.","Drain everything, shock the eggs and broccoli in cold water, then slice the still-warm potatoes into thick coins so they soak up dressing greedily.","Whisk the olive oil with the lemon''s juice, a pinch of salt, and plenty of black pepper into a sharp, glossy dressing.","Toss the warm potatoes and broccoli with half the dressing and let them sit 5 minutes to absorb it.","Arrange torn romaine and sliced cucumber on a platter, mound the potatoes, flaked tuna, and quartered eggs on top, and spoon over the remaining dressing so every layer glistens."],"tip":"Dress the potatoes while warm — cold potatoes shrug off vinaigrette like a raincoat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_tuna_spaghetti', '{"id":"lemon_garlic_tuna_spaghetti","name":"Lemon-Garlic Tuna Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"tuna_canned","q":200},{"f":"olive_oil","q":40},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":40},{"f":"spinach","q":100}],"steps":["Boil the spaghetti in aggressively salted water until just shy of al dente, about 8 minutes, and reserve a full cup of the starchy cooking water before draining.","Meanwhile, warm the olive oil and thinly sliced garlic in a wide skillet over medium-low heat for 2 to 3 minutes until the garlic turns pale gold and smells sweet, not sharp.","Add the drained tuna in large flakes with the lemon zest and a pinch of chili flakes if you have them, warming it gently so it stays tender.","Tip in the spaghetti with a generous splash of pasta water and the spinach, tossing vigorously over medium heat until the sauce turns silky and clings to every strand, about 2 minutes.","Kill the heat, shower in the parmesan and lemon juice, toss once more, and serve immediately while the sauce is still glossy."],"tip":"The pasta water is the sauce — hoard it like it costs money."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheesy_tuna_broccoli_rice_bake', '{"id":"cheesy_tuna_broccoli_rice_bake","name":"Cheesy Tuna and Broccoli Rice Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":45,"servings":2,"ing":[{"f":"rice","q":150},{"f":"tuna_canned","q":220},{"f":"broccoli","q":300},{"f":"cheddar","q":100},{"f":"milk","q":200},{"f":"butter","q":20},{"f":"flour","q":15},{"f":"onion","q":0.5}],"steps":["Heat the oven to 200C and cook the rice in salted water until just tender, about 12 minutes, since it will bake again.","Melt the butter in a saucepan over medium heat, soften the diced onion for 4 minutes until translucent, then stir in the flour and cook 1 minute until it smells faintly nutty.","Whisk in the milk gradually and simmer 3 minutes until the sauce coats the back of a spoon, then melt in two-thirds of the cheddar with a big pinch of salt and pepper.","Fold the sauce through the rice, flaked tuna, and raw broccoli florets, spread the mixture into a baking dish, and top with the remaining cheddar.","Bake 18 to 20 minutes until the edges bubble furiously and the top turns golden and crusty, then rest 5 minutes so the sauce thickens before serving."],"tip":"Raw broccoli going into the oven is the move — pre-cooked florets emerge as sad green mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_tuna_couscous_bowl', '{"id":"mediterranean_tuna_couscous_bowl","name":"Mediterranean Tuna Couscous Bowl with Feta","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"tuna_canned","q":200},{"f":"cucumber","q":1},{"f":"feta","q":80},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":80}],"steps":["Pour boiling salted water over the couscous just to cover, clamp on a lid, and let it steam for 5 minutes off the heat until every grain is tender.","While it steams, soak the thinly sliced onion in the lemon''s juice with a pinch of salt for 5 minutes to tame its bite into something bright and pickled.","Fluff the couscous thoroughly with a fork, breaking up any clumps, then fold in the olive oil while the grains are still warm.","Add the flaked tuna, diced cucumber, roughly chopped spinach, and the onion with all its lemony juices, tossing until everything is evenly distributed.","Crumble the feta over the top in big craggy chunks, grind over black pepper, and serve at room temperature when the flavors are loudest."],"tip":"Fluff couscous like you mean it — timid forking leaves you with one sad grain-brick."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_edamame_fried_rice', '{"id":"tuna_edamame_fried_rice","name":"Tuna and Edamame Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["fish","eggs","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice","q":150},{"f":"tuna_canned","q":200},{"f":"eggs","q":2},{"f":"edamame_frozen","q":150},{"f":"carrots","q":150},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Cook the rice, spread it on a plate, and chill it for at least 15 minutes — dry, cold grains fry, wet ones steam.","Get a large skillet or wok screaming hot, add half the sesame oil, and scramble the beaten eggs for 30 seconds until just set in soft folds, then scoop them out.","Add the remaining oil with the diced onion, carrots, and garlic and stir-fry 3 minutes until the carrots blister at the edges but keep a little crunch.","Tip in the cold rice and edamame, pressing the rice against the hot pan and letting it sit 60 seconds at a time so it crackles and toasts.","Return the eggs, add the drained tuna and soy sauce around the edge of the pan so it sizzles and caramelizes, toss for a final minute, and serve straight from the skillet."],"tip":"Day-old rice is the secret handshake of fried rice — plan tonight''s leftovers for tomorrow''s triumph."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_stuffed_avocados', '{"id":"tuna_stuffed_avocados","name":"Zesty Tuna-Stuffed Avocados","emoji":"🥑","cuisine":"Mexican","meal":["lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":15,"servings":2,"ing":[{"f":"avocado","q":2},{"f":"tuna_canned","q":200},{"f":"greek_yogurt","q":80},{"f":"lemon","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":0.3}],"steps":["Halve and pit the avocados, then scoop a spoonful of flesh from each half to widen the crater, saving what you remove.","Mash the scooped avocado with the greek yogurt, half the lemon''s juice, and a pinch of salt until creamy but still a little chunky.","Fold in the drained tuna, finely diced bell pepper, and minced onion, tasting and sharpening with more lemon and a whisper of chili powder or cumin if you like heat.","Brush the avocado halves with the remaining lemon juice so they stay vividly green, then mound the filling high into each one.","Finish with cracked pepper and serve immediately, while the contrast between cool creamy filling and buttery avocado is at its best."],"tip":"Buy avocados that yield like a stress ball, not a stone — no filling can rescue an unripe one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spicy_tuna_tortilla_tacos', '{"id":"spicy_tuna_tortilla_tacos","name":"Ten-Minute Spicy Tuna Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"tuna_canned","q":220},{"f":"sour_cream","q":80},{"f":"avocado","q":1},{"f":"romaine","q":0.5},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":15}],"steps":["Stir the drained tuna with the olive oil, half the lemon''s juice, a big pinch of chili powder, cumin, and salt, breaking it into rough shreds seasoned all the way through.","Warm a dry skillet over medium-high heat and toast each tortilla 30 to 45 seconds per side until puffed in spots and lightly charred at the edges.","Whisk the sour cream with the remaining lemon juice and a pinch of salt into a pourable crema.","Sear the tuna mixture in the hot skillet for 2 minutes without stirring so the bottom crisps and catches golden-brown edges.","Load each tortilla with shredded romaine, the crisped tuna, sliced avocado, and minced onion, then zigzag the crema over the top and serve while the tortillas are still warm and pliable."],"tip":"A tortilla straight from the bag is a sad handshake — thirty seconds on a hot pan turns it into a proper greeting."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_hummus_pita_pockets', '{"id":"tuna_hummus_pita_pockets","name":"Tuna and Hummus Pita Pockets","emoji":"🫓","cuisine":"Mediterranean","meal":["lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","sesame"],"time":10,"servings":2,"ing":[{"f":"pita","q":2},{"f":"tuna_canned","q":200},{"f":"hummus","q":100},{"f":"cucumber","q":1},{"f":"spinach","q":60},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10}],"steps":["Warm the pitas in a dry skillet or toaster for about a minute per side until soft and steamy, then halve them and gently open the pockets.","Toss the drained tuna with the olive oil, a squeeze of lemon, and plenty of black pepper so every flake is seasoned.","Slice the cucumber into thin half-moons and pat them dry — wet cucumber is the number one cause of soggy pockets.","Spread a thick layer of hummus inside each pita half, working it into the corners like mortar.","Pack the pockets with spinach leaves, the lemony tuna, and cucumber, pressing gently so each bite gets all three, and eat immediately over a plate."],"tip":"Hummus on both inner walls is structural engineering — it waterproofs the bread and glues the filling in place."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_spinach_yogurt_curry', '{"id":"tuna_spinach_yogurt_curry","name":"Creamy Tuna and Spinach Curry with Rice","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":35,"servings":2,"ing":[{"f":"tuna_canned","q":220},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"greek_yogurt","q":150},{"f":"butter","q":25},{"f":"rice","q":140}],"steps":["Start the rice in salted water so it finishes as the curry does, about 12 minutes at a gentle simmer.","Melt the butter in a deep skillet over medium heat and cook the finely diced onion for 8 to 10 minutes, stirring occasionally, until deeply golden and jammy — this is the backbone of the sauce, so do not rush it.","Add the minced garlic with a tablespoon of curry powder or garam masala and a pinch of salt, toasting 60 seconds until intensely fragrant.","Pile in the spinach with a splash of water and cook 3 minutes until fully wilted and glossy, then fold in the drained tuna in large chunks.","Pull the pan off the heat, stir in the greek yogurt one spoonful at a time so it stays creamy instead of splitting, warm through gently, and serve ladled over the rice."],"tip":"Yogurt added over raging heat curdles into cottage-cheese regret — off the flame, one spoonful at a time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_noodle_bowl', '{"id":"sesame_tofu_noodle_bowl","name":"Cold Sesame Tofu Noodle Bowl","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":150},{"f":"tofu","q":300},{"f":"cucumber","q":1},{"f":"carrots","q":150},{"f":"peanut_butter","q":30},{"f":"sesame_oil","q":20},{"f":"soy_sauce","q":25},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2}],"steps":["Cook the rice noodles according to the package, usually 4 to 6 minutes, then rinse them under cold water until completely cool and toss with a teaspoon of the sesame_oil so they do not weld together.","Pat the tofu very dry, cut it into 2-centimeter cubes, and sear it in a hot nonstick skillet with a teaspoon of the sesame oil for 6 to 8 minutes, turning until every side is golden and crisp.","Whisk the peanut butter, soy sauce, maple syrup, remaining sesame oil, grated garlic, and 2 to 3 tablespoons of warm water into a dressing the texture of heavy cream.","Cut the cucumber and carrots into thin matchsticks — the crunch against the slippery noodles is the whole point.","Toss the noodles with two-thirds of the dressing until every strand is coated and glossy, then top with the crisp tofu and vegetables, drizzle over the rest of the dressing, and finish with a pinch of chili flakes if you want a slow burn."],"tip":"Peanut sauce always seizes into cement at first — keep whisking in warm water a spoonful at a time and it will loosen into silk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_potato_breakfast_hash', '{"id":"tuna_potato_breakfast_hash","name":"Crispy Tuna and Potato Breakfast Hash","emoji":"🍳","cuisine":"American","meal":["breakfast","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":30,"servings":2,"ing":[{"f":"potatoes","q":450},{"f":"tuna_canned","q":180},{"f":"eggs","q":4},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":30}],"steps":["Dice the potatoes into 1-centimeter cubes and parboil them in salted water for 5 minutes, then drain and let them steam dry — dry surfaces are what crisp.","Heat the olive oil in a large cast-iron or heavy skillet over medium-high heat and spread the potatoes in a single layer, leaving them untouched for 4 minutes until the undersides are deeply browned.","Toss, then add the diced bell pepper and onion and cook 5 more minutes, stirring occasionally, until the vegetables soften and the potatoes are crusty on most sides.","Fold in the drained tuna with a generous pinch of paprika or black pepper and press everything flat to crisp for 2 minutes.","Make four wells in the hash, crack an egg into each, cover the pan, and cook 3 to 4 minutes until the whites are set but the yolks still shiver, then serve straight from the skillet."],"tip":"Resist the urge to stir — a hash gets its crust from neglect, not attention."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_chili', '{"id":"smoky_black_bean_chili","name":"Smoky Black Bean Chili","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":4},{"f":"black_beans","q":800},{"f":"lime","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion and bell peppers for 8 minutes, until the edges pick up a little char and the onion turns translucent.","Stir in the minced garlic with a generous pinch of smoked seasoning and toast for 60 seconds, just until the pot smells sweet and heady rather than raw.","Add the chopped tomatoes and cook 5 minutes, mashing them against the side of the pot until they collapse into a rough, brick-red sauce.","Tip in the black beans with a splash of their liquid, bring to a lazy simmer, and cook uncovered for 20 minutes, stirring occasionally, until the chili thickens enough that a spoon dragged across the bottom leaves a trail.","Crush a ladleful of beans against the pot wall to thicken things further, then finish with lime juice and taste for salt before serving hot."],"tip":"A chili that tastes flat almost always needs acid, not more heat, so squeeze before you spice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_saag_chickpea_curry', '{"id":"chana_saag_chickpea_curry","name":"Chana Saag Chickpea Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"tomato","q":3},{"f":"chickpeas","q":700},{"f":"spinach","q":300},{"f":"greek_yogurt","q":100},{"f":"rice","q":300}],"steps":["Rinse the rice and simmer it, covered, in double its volume of salted water for 15 minutes, then let it steam off the heat while you build the curry.","Heat the oil in a wide pan over medium-high and fry the sliced onion for 10 minutes until deeply golden at the edges, because that browning is where the curry''s sweetness lives.","Add the minced garlic and grated ginger and sizzle for 1 minute, then stir in the chopped tomatoes and cook 6 to 8 minutes until the oil separates and pools at the edges of the sauce.","Fold in the chickpeas with a splash of water and simmer 10 minutes so they drink up the masala, then pile in the spinach by the handful and let it wilt to a glossy dark green.","Pull the pan off the heat, swirl in the yogurt so it stays silky instead of splitting, and serve ladled over the fluffed rice."],"tip":"Yogurt curdles when boiled, so treat it like a guest who arrives after the party calms down."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_white_bean_kale_soup', '{"id":"tuscan_white_bean_kale_soup","name":"Tuscan White Bean and Kale Soup","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"white_beans","q":700},{"f":"kale","q":1},{"f":"parmesan","q":40}],"steps":["Sweat the diced onion, carrot, and celery in the olive oil over medium heat for 8 to 10 minutes, until the vegetables are soft and the bottom of the pot glistens.","Add the sliced garlic and chopped tomatoes and cook 4 minutes, until the tomatoes slump and stain everything a pale coral.","Pour in the white beans with about a liter of water, season assertively with salt, and simmer gently for 15 minutes so the flavors knit together.","Mash a cupful of beans right in the pot to give the broth a creamy body, then stir in the torn kale and cook 5 more minutes until it is tender but still forest green.","Ladle into bowls and shower each with grated parmesan and a final thread of good olive oil."],"tip":"The soup is even better tomorrow, so consider making it yesterday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_tacos', '{"id":"black_bean_avocado_tacos","name":"Black Bean and Avocado Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"black_beans","q":400},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"tomato","q":1},{"f":"romaine","q":0.3}],"steps":["Heat the oil in a skillet over medium and cook half the diced onion with the minced garlic for 4 minutes, until soft and fragrant.","Add the black beans with a splash of water and a big pinch of cumin-style seasoning, simmer 6 to 8 minutes, then smash roughly half of them with a fork so the filling is creamy with plenty of whole beans left for texture.","While the beans bubble, mash the avocado with lime juice and salt, and toss the remaining raw onion with the diced tomato for a quick pico.","Char the tortillas directly over a flame or in a dry pan for 30 seconds per side, until blistered and pliable with dark freckles.","Swipe each tortilla with avocado, pile on the smashed beans, and finish with pico and shredded romaine while everything is still hot."],"tip":"A cold tortilla is a sad envelope, so char them last and serve immediately."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_feta_shakshuka', '{"id":"chickpea_feta_shakshuka","name":"Chickpea and Feta Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":4},{"f":"chickpeas","q":300},{"f":"eggs","q":4},{"f":"feta","q":60}],"steps":["Soften the sliced onion and bell pepper in olive oil over medium heat for 7 minutes, until sweet and slightly caught at the edges.","Stir in the minced garlic with a pinch of paprika-style seasoning, cook 1 minute, then add the chopped tomatoes and simmer 8 to 10 minutes until they break down into a thick, spoonable sauce.","Fold in the chickpeas and let them warm through for 3 minutes so they soak up the pepper-stained sauce.","Make four wells with the back of a spoon, crack an egg into each, cover, and cook 5 to 7 minutes, until the whites are just set but the yolks still shiver when you nudge the pan.","Crumble the feta over the top, let it slump in the residual heat, and bring the whole skillet to the table."],"tip":"Pull the pan when the eggs look one minute underdone, because carryover heat has no mercy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_white_bean_spinach_penne', '{"id":"lemony_white_bean_spinach_penne","name":"Lemony White Bean and Spinach Penne","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"white_beans","q":300},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"spinach","q":150},{"f":"lemon","q":1},{"f":"parmesan","q":40}],"steps":["Boil the penne in well-salted water until just shy of al dente, about 9 minutes, and scoop out a cup of the starchy cooking water before draining.","Meanwhile, warm the olive oil with the thinly sliced garlic in a wide skillet over medium-low heat until the slices turn pale gold and smell nutty, about 2 minutes.","Add the white beans with a splash of pasta water and simmer 4 minutes, crushing about a third of them so they melt into a light, creamy sauce.","Tumble in the drained penne and the spinach, tossing over medium heat until the leaves wilt and the sauce clings glossily to every tube, loosening with more pasta water as needed.","Off the heat, stir in the lemon zest, a big squeeze of juice, and the parmesan, tossing until the sauce turns silky, then serve straight away."],"tip":"Pasta water is free sauce insurance, so hoard it like a nonna."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_black_bean_burgers', '{"id":"crispy_black_bean_burgers","name":"Crispy Black Bean Burgers","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"oats","q":50},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"bread","q":4},{"f":"cheddar","q":60},{"f":"tomato","q":1},{"f":"romaine","q":0.3}],"steps":["Spread the drained black beans on a tray and blot them very dry, then mash three-quarters of them to a coarse paste, leaving the rest whole for texture.","Mix the mash with the oats, egg, finely grated onion, minced garlic, and a confident amount of salt and smoky seasoning, then chill the mixture for 10 minutes so it firms up.","Shape two thick patties and sear them in the olive oil over medium heat for 4 to 5 minutes per side, resisting the urge to move them until a deep, crackly crust forms.","Lay the cheddar on the patties for the final minute and cover the pan so it melts into every crevice.","Toast the bread in the same pan, then stack each burger with romaine and thick tomato slices and press gently before the first bite."],"tip":"Wet beans make sad, steamy burgers, so dry them like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_couscous_mezze_bowls', '{"id":"chickpea_couscous_mezze_bowls","name":"Chickpea Couscous Mezze Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","dairy","sesame"],"time":25,"servings":2,"ing":[{"f":"couscous","q":120},{"f":"chickpeas","q":350},{"f":"olive_oil","q":20},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"feta","q":60},{"f":"hummus","q":80}],"steps":["Pour boiling salted water over the couscous just to cover, seal the bowl with a plate, and let it steam for 5 minutes before fluffing with a fork into light, separate grains.","Sizzle the chickpeas in half the olive oil over medium-high heat for 6 to 8 minutes, shaking the pan until they turn golden and lightly crisp at the seams.","Dice the cucumber, tomatoes, and onion into small, even pieces and dress them with lemon juice, the remaining oil, and a pinch of salt so they release their juices.","Build each bowl with a bed of couscous, a generous swoosh of hummus up one side, the crisped chickpeas, and the chopped salad.","Crumble feta over everything and finish with lemon zest and a last drizzle of oil."],"tip":"The swoosh of hummus is not decoration, it is the sauce, so be generous with the swoosh."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_soy_chickpea_stirfry', '{"id":"ginger_soy_chickpea_stirfry","name":"Ginger-Soy Chickpea Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":150},{"f":"chickpeas","q":300},{"f":"broccoli","q":400},{"f":"edamame_frozen","q":150},{"f":"garlic","q":0.3},{"f":"ginger","q":20},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Simmer the rinsed rice, covered, in one and a half times its volume of water for 12 minutes, then rest it off the heat with the lid on.","Get a wok or large skillet screaming hot, add the olive oil, and sear the drained chickpeas for 5 minutes until they blister and pop like tiny popcorn.","Add the broccoli florets with a splash of water and stir-fry 4 minutes, until the water evaporates and the florets are bright green with charred tips but still snappy.","Toss in the edamame, minced garlic, and grated ginger and cook 2 minutes, keeping everything moving so the aromatics never scorch.","Pour in the soy sauce, let it bubble and glaze everything for 30 seconds, then kill the heat, finish with sesame oil, and serve over the steamed rice."],"tip":"Sesame oil is a finishing perfume, not a frying fat, so add it after the flames are out."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_sweet_potato_hash_2', '{"id":"black_bean_sweet_potato_hash_2","name":"Black Bean and Sweet Potato Hash","emoji":"🍠","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":300},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"eggs","q":4}],"steps":["Dice the sweet potatoes into 1-centimeter cubes and cook them in the olive oil in a large cast-iron skillet over medium heat for 12 to 15 minutes, turning only occasionally so they develop caramelized, crusty faces.","Add the diced onion and bell pepper and cook 5 more minutes, until the onion softens and picks up color from the fond in the pan.","Stir in the garlic and black beans with a pinch of smoked seasoning and cook 3 minutes, pressing the hash flat so the bottom crisps.","Nestle four wells into the hash, crack in the eggs, cover, and cook 4 to 6 minutes, until the whites set opaque while the yolks stay molten.","Season generously and serve straight from the skillet while the edges are still sizzling."],"tip":"Flipping the hash constantly is how you get mush, so channel your inner statue."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_white_bean_toasts', '{"id":"garlicky_white_bean_toasts","name":"Garlicky White Bean Toasts with Wilted Spinach","emoji":"🍞","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":20,"servings":2,"ing":[{"f":"bread","q":4},{"f":"white_beans","q":400},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"spinach","q":150},{"f":"tomato","q":1}],"steps":["Warm two-thirds of the olive oil with the sliced garlic in a skillet over medium-low heat until the garlic just turns golden and the kitchen smells like an Italian grandmother''s, about 2 minutes.","Add the white beans with a splash of water, simmer 5 minutes, then smash them roughly with a fork into a rustic, creamy spread and brighten with lemon zest, juice, and plenty of salt.","In the same pan, wilt the spinach in 1 minute flat with a pinch of salt, then set it aside.","Toast the bread until deeply golden and audibly crisp, then rub each slice with the cut tomato so it soaks in like a quick pan con tomate.","Pile the warm bean smash onto the toasts, drape the spinach over the top, and finish with the remaining oil and a crack of pepper."],"tip":"Toast pale enough to fold is toast that will collapse under beans, so aim for crouton-adjacent."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_stuffed_peppers', '{"id":"white_bean_stuffed_peppers","name":"White Bean and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"rice","q":120},{"f":"white_beans","q":300},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"mozzarella","q":80}],"steps":["Heat the oven to 200C and simmer the rice in salted water for 12 minutes until just tender, then drain well.","Halve the peppers through the stem, scoop out the seeds, rub with a little of the oil, and roast cut-side up for 10 minutes so they get a head start on softening.","Meanwhile, cook the diced onion and garlic in the remaining oil for 4 minutes, then add the chopped tomatoes and white beans and simmer 5 minutes into a thick, saucy filling.","Fold the rice into the beans, taste for salt, and mound the filling into the pepper halves, packing it in with the back of a spoon.","Cap each pepper with torn mozzarella and bake 18 to 20 minutes, until the cheese is bronzed and bubbling and a knife slides through the pepper walls without resistance."],"tip":"Par-roasting the empty peppers is the difference between tender boats and crunchy disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_baked_white_beans_feta', '{"id":"greek_baked_white_beans_feta","name":"Greek Baked White Beans with Feta","emoji":"🇬🇷","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":55,"servings":4,"ing":[{"f":"white_beans","q":800},{"f":"tomato","q":5},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"feta","q":100},{"f":"spinach","q":150}],"steps":["Heat the oven to 190C and, in an ovenproof pot, cook the sliced onion in most of the olive oil over medium heat for 8 minutes until soft and sweet.","Add the minced garlic, then the chopped tomatoes with a big pinch of salt and a whisper of dried herbs, and simmer 10 minutes until the sauce thickens and turns a deep, jammy red.","Stir in the white beans and a splash of water, fold through the spinach until it wilts, and level the surface with a spoon.","Slide the pot uncovered into the oven and bake 25 to 30 minutes, until the top is blistered in spots and the sauce bubbles thickly at the edges.","Crumble the feta over the hot beans, drizzle with the reserved oil, and rest 5 minutes so the sauce settles from lava to luscious."],"tip":"Gigantes-style beans reward patience, so let the bake go until the edges genuinely caramelize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spaghetti_lentil_bolognese', '{"id":"spaghetti_lentil_bolognese","name":"Spaghetti with Lentil Bolognese","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["gluten","dairy"],"time":50,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"spaghetti","q":340},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"celery","q":80},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"parmesan","q":40},{"f":"oregano","q":2},{"f":"basil","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Finely dice the onion, carrots, and celery, then sweat them in the olive oil over medium heat for 8 minutes until the onion turns translucent and the carrots smell sweet.","Stir in the minced garlic and oregano and cook 1 minute more, just until fragrant but not browned.","Add the lentils, crushed tomatoes, and 750 ml of water, season with salt and pepper, and simmer uncovered for 30 to 35 minutes, stirring occasionally, until the lentils are tender and the sauce is thick enough to hold a spoon trail.","Meanwhile, boil the spaghetti in well-salted water until just shy of al dente, then reserve a cup of the starchy water before draining.","Toss the spaghetti with the lentil ragu, loosening with splashes of pasta water until the sauce clings glossily to every strand.","Serve in warm bowls showered with grated parmesan and torn basil leaves."],"tip":"The ragu tastes even better tomorrow, so make a double batch and let the fridge do the seasoning."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_lentil_kale_soup', '{"id":"tuscan_lentil_kale_soup","name":"Tuscan Lentil and Kale Soup","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":400},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"kale","q":1},{"f":"olive_oil","q":30},{"f":"oregano","q":2},{"f":"salt","q":6},{"f":"black_pepper","q":2},{"f":"lemon","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion, carrots, and celery for 8 to 10 minutes until softened and just starting to catch golden at the edges.","Add the minced garlic and oregano and stir for 1 minute until the kitchen smells like a trattoria.","Pour in the lentils, crushed tomatoes, and 1.5 liters of water, bring to a boil, then lower the heat and simmer partly covered for 30 minutes until the lentils are creamy-tender.","Strip the kale from its stems, tear it into bite-size pieces, and stir it in for the final 5 minutes so it wilts to a deep glossy green.","Season with salt and pepper, then brighten the whole pot with the juice of the lemon just before ladling into bowls."],"tip":"That squeeze of lemon at the end is not optional; it is the difference between brown soup and dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_red_lentil_curry', '{"id":"coconut_red_lentil_curry","name":"Creamy Coconut Lentil Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":350},{"f":"coconut_milk","q":300},{"f":"rice","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"crushed_tomatoes","q":250},{"f":"spinach","q":150},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"garam_masala","q":4},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Start the rice in a small pot with 400 ml of water, cover, and let it steam quietly on low while you build the curry.","Heat the oil in a deep skillet over medium heat and fry the diced onion for 6 minutes until golden, then add the garlic, grated ginger, curry powder, and turmeric and stir for 1 minute until the spices bloom and darken slightly.","Add the lentils, crushed tomatoes, coconut milk, and 900 ml of water, then simmer uncovered for 25 to 30 minutes, stirring now and then, until the lentils collapse into a thick, spoon-coating stew.","Fold in the spinach by the handful and let it wilt into the curry, about 2 minutes.","Turn off the heat, stir in the garam masala and salt, and rest the pot 5 minutes so the spices settle in before serving over the rice."],"tip":"Adding garam masala off the heat keeps its perfume intact instead of boiling it away."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_sloppy_joes', '{"id":"lentil_sloppy_joes","name":"Lentil Sloppy Joes","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":300},{"f":"chili_powder","q":5},{"f":"cumin","q":3},{"f":"maple_syrup","q":15},{"f":"balsamic_vinegar","q":15},{"f":"bread","q":4},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Simmer the lentils in plenty of water for about 20 minutes until tender but still holding their shape, then drain.","Meanwhile, sauté the diced onion and bell pepper in the olive oil over medium-high heat for 6 minutes until the edges char slightly and the pepper smells sweet.","Stir in the garlic, chili powder, and cumin for 30 seconds, then add the crushed tomatoes, maple syrup, balsamic, and drained lentils.","Simmer for 10 minutes, mashing a few lentils against the pot wall, until the mixture is thick, glossy, and sloppy in the technical sense.","Toast the bread until golden and pile the lentil mixture high on top, letting it cascade over the edges as tradition demands."],"tip":"Napkins are an ingredient here; the drips down your wrist are proof you seasoned it right."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_walnut_burgers', '{"id":"lentil_walnut_burgers","name":"Lentil Walnut Burgers","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free","high-protein"],"allergens":["gluten","eggs","nuts"],"time":50,"servings":2,"ing":[{"f":"lentils_dry","q":120},{"f":"walnuts","q":30},{"f":"oats","q":40},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"olive_oil","q":15},{"f":"bread","q":4},{"f":"avocado","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Boil the lentils for 22 to 25 minutes until fully soft, then drain them very well and spread on a plate for 10 minutes to dry out, because wet lentils make sad, crumbly burgers.","Toast the walnuts and oats in a dry skillet for 3 minutes until nutty-smelling, then chop the walnuts fine.","Mash the lentils roughly with a fork, then mix in the walnuts, oats, egg, finely minced onion and garlic, cumin, paprika, salt, and pepper until the mixture holds together when squeezed.","Shape into two thick patties and chill for 10 minutes so they firm up.","Pan-fry in the olive oil over medium heat for 4 to 5 minutes per side until deeply browned and crusty, flipping only once.","Serve each patty between toasted bread slices with fanned avocado on top."],"tip":"Resist the urge to poke and flip; a patty left alone builds the crust that keeps it in one piece."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_lentil_tacos', '{"id":"smoky_lentil_tacos","name":"Smoky Lentil Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":130},{"f":"tortillas","q":4},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"paprika","q":3},{"f":"salsa","q":100},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Simmer the lentils in salted water for about 20 minutes until just tender, then drain thoroughly.","Heat the olive oil in a skillet over medium-high heat, fry the diced onion for 4 minutes until browned at the edges, then add the garlic, chili powder, cumin, and paprika and toast for 30 seconds until the spices smell smoky and rich.","Add the lentils and salsa and cook for 5 minutes, mashing lightly, until the filling sizzles and darkens like good taco meat should.","Char the tortillas directly over a flame or in a dry pan for 20 seconds per side until blistered and pliable.","Fill each tortilla with the lentil mixture, top with sliced avocado and torn cilantro, and finish with a hard squeeze of lime over everything."],"tip":"A slightly ugly, charred tortilla beats a pale steamed one every single Tuesday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('campfire_lentil_chili', '{"id":"campfire_lentil_chili","name":"Campfire Lentil Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"black_beans","q":250},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"chili_powder","q":12},{"f":"cumin","q":6},{"f":"paprika","q":4},{"f":"corn_frozen","q":150},{"f":"olive_oil","q":20},{"f":"salt","q":6}],"steps":["Heat the oil in your biggest pot over medium-high heat and cook the diced onion and bell peppers for 7 minutes until softened and flecked with brown.","Add the garlic, chili powder, cumin, and paprika and stir constantly for 1 minute; the spices should coat the vegetables in a brick-red paste and smell almost like barbecue.","Pour in the lentils, crushed tomatoes, and 1.2 liters of water, bring to a boil, then simmer partly covered for 30 minutes, stirring occasionally so nothing sticks.","Stir in the black beans and corn and simmer 10 minutes more, until the chili is thick enough that a wooden spoon stands up for a second before falling.","Season with salt, then let the pot rest off the heat for 5 minutes; chili always tastes better after it has had a moment to think."],"tip":"If your spoon falls over immediately, keep simmering; proper chili has structural integrity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_lentil_feta_salad', '{"id":"greek_lentil_feta_salad","name":"Greek Lentil and Feta Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":140},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":80},{"f":"olives","q":40},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Simmer the lentils in generously salted water for 18 to 20 minutes until tender but still distinct and slightly firm to the bite, then drain and spread them out to cool for 10 minutes.","While they cool, dice the cucumber, halve the cherry tomatoes, and roughly chop the olives and parsley.","Whisk the lemon juice, olive oil, oregano, salt, and pepper into a sharp dressing that makes you wince slightly when you taste it straight.","Toss the warm lentils with the dressing first so they drink it in, then fold in the vegetables, olives, and parsley.","Crumble the feta over the top in big craggy chunks and give one final gentle toss before serving."],"tip":"Dressing the lentils while warm is the whole trick; cold lentils absorb nothing and forgive nothing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_lentil_rice_bowl', '{"id":"ginger_lentil_rice_bowl","name":"Ginger-Scallion Lentil Rice Bowl","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"rice","q":150},{"f":"carrots","q":100},{"f":"cabbage","q":0.3},{"f":"scallions","q":0.5},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"maple_syrup","q":10}],"steps":["Cook the rice in 300 ml of water, covered, on low for 15 minutes, then let it steam off the heat while you handle everything else.","Simmer the lentils in water for 20 minutes until tender, then drain well.","Stir-fry the shredded cabbage and julienned carrots in the olive oil over high heat for 3 to 4 minutes until the cabbage picks up charred spots but keeps its crunch.","Add the grated ginger, minced garlic, and lentils, then pour in the soy sauce and maple syrup and toss for 2 minutes until everything glistens and the pan hisses.","Pile the mixture over the rice, drizzle with sesame oil, and shower with thinly sliced scallions before serving."],"tip":"Sesame oil is a finishing perfume, not a cooking fat; add it at the end or lose it entirely."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_rice_stuffed_peppers', '{"id":"lentil_rice_stuffed_peppers","name":"Lentil and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":60,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"lentils_dry","q":100},{"f":"rice","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"salsa","q":120},{"f":"corn_frozen","q":80},{"f":"cheddar","q":60},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Heat the oven to 200 C and simmer the lentils and rice together in salted water for 18 minutes until both are just tender, then drain.","Halve the peppers through the stem, scoop out the seeds, rub with a little of the oil, and roast cut-side down for 10 minutes until they begin to slump and blister.","Meanwhile, sauté the diced onion in the remaining oil for 5 minutes, add the garlic, cumin, and chili powder for 30 seconds, then stir in the lentil-rice mixture, salsa, and corn until everything is stained brick red.","Flip the peppers over, pack them generously with the filling, and top each with a handful of cheddar.","Bake for 15 minutes until the cheese is bubbling and bronzed at the edges, then scatter with cilantro and serve hot."],"tip":"Pre-roasting the empty peppers is the secret handshake; nobody likes a stuffed pepper that crunches like a raw one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_eggplant_lentil_stew', '{"id":"greek_eggplant_lentil_stew","name":"Greek Eggplant and Lentil Stew","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"eggplant","q":1},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"olive_oil","q":45},{"f":"oregano","q":3},{"f":"cinnamon","q":1},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Cut the eggplant into 2 cm cubes and brown it in batches in most of the olive oil over medium-high heat, about 4 minutes per batch, until golden and creamy at the center; set aside.","In the same pot, soften the diced onion for 6 minutes, then add the garlic, oregano, and cinnamon and stir for 1 minute until the cinnamon makes the kitchen smell faintly of a Greek taverna.","Add the lentils, crushed tomatoes, and 1 liter of water, bring to a boil, and simmer partly covered for 25 minutes until the lentils are tender.","Return the eggplant to the pot and simmer gently for 10 more minutes so it soaks up the tomato broth without falling apart.","Season with salt and pepper, finish with lemon juice and a flood of chopped parsley, and serve in deep bowls with the remaining oil drizzled over the top."],"tip":"Brown the eggplant properly and it turns to silk; rush it and it turns to sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mujadara_lentils_rice', '{"id":"mujadara_lentils_rice","name":"Mujadara with Crispy Onions","emoji":"🧅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"rice","q":120},{"f":"onion","q":2},{"f":"olive_oil","q":30},{"f":"cumin","q":4},{"f":"cinnamon","q":1},{"f":"greek_yogurt","q":100},{"f":"parsley","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Slice both onions into thin half-moons and cook them in the olive oil over medium heat for 20 to 25 minutes, stirring occasionally, until deep mahogany and crisp at the edges; patience here is the entire dish.","Meanwhile, simmer the lentils in water for 15 minutes until just shy of tender.","Add the rice, cumin, cinnamon, salt, and enough fresh water to cover by 2 cm, then cover and cook on low for 15 minutes until both grains are tender and the water is absorbed.","Let the pot rest off the heat for 5 minutes, then fluff and fold in half the crispy onions.","Serve mounded on plates, topped with cool dollops of yogurt, the remaining onions, chopped parsley, and a grind of black pepper."],"tip":"The onions are done five minutes after you think they are done; hold your nerve until they are truly bronze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_mushroom_lettuce_wraps', '{"id":"lentil_mushroom_lettuce_wraps","name":"Lentil Mushroom Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame","nuts"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":150},{"f":"mushrooms","q":150},{"f":"romaine","q":1},{"f":"carrots","q":80},{"f":"scallions","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"maple_syrup","q":10},{"f":"cashews","q":30},{"f":"lime","q":1}],"steps":["Simmer the lentils for 18 to 20 minutes until tender but intact, then drain very well.","Finely chop the mushrooms and sear them in the olive oil over high heat for 5 minutes without stirring much, until their water evaporates and they brown and squeak against the pan.","Add the minced garlic and grated ginger for 30 seconds, then tip in the lentils, soy sauce, and maple syrup and toss for 2 to 3 minutes until the mixture is glossy and sticky.","Off the heat, stir in the sesame oil, grated carrot, sliced scallions, and roughly chopped cashews.","Separate the romaine into cup-shaped leaves, spoon the warm filling into each, and finish with wedges of lime for squeezing at the table."],"tip":"Dry lentils and dry lettuce are the difference between a wrap and a lap full of filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_satay_rice_bowl', '{"id":"chicken_satay_rice_bowl","name":"Chicken satay rice bowl","emoji":"🥜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["nuts","soy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":300},{"f":"rice","q":160},{"f":"peanut_butter","q":40},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"lime","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":8},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Start the rice so it finishes as the chicken does, about 15 minutes at a bare simmer.","Whisk the peanut butter, soy sauce, honey, half the lime juice, minced garlic and grated ginger with 3–4 tablespoons of hot water until it pours like heavy cream.","Cut the chicken thighs into bite-size pieces and sear them in the oil over medium-high heat, 6–7 minutes, until deeply browned at the edges and cooked through.","Pour half the peanut sauce into the skillet and toss for 30 seconds, just until it clings and bubbles at the rim.","Pile rice into bowls, top with the glazed chicken, ribbons of cucumber and shaved carrot, then drizzle the remaining sauce over everything.","Finish with torn cilantro and the last lime wedge squeezed over the top."],"tip":"If your peanut sauce seizes into paste, don''t panic — hot water and patient whisking will loosen it every time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_salmon_rice_bowl', '{"id":"chili_lime_salmon_rice_bowl","name":"Chili-lime salmon rice bowl","emoji":"🐟","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":280},{"f":"rice","q":150},{"f":"corn_frozen","q":120},{"f":"avocado","q":1},{"f":"lime","q":1.5},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"olive_oil","q":10},{"f":"cilantro","q":0.3},{"f":"scallions","q":0.5}],"steps":["Get the rice simmering, then rub the salmon all over with chili powder, cumin, a pinch of salt and half the lime juice.","Char the corn in a dry skillet over high heat, 4–5 minutes without stirring much, until it smells toasty and picks up blackened spots; tip it into a bowl.","Add the oil to the same skillet and sear the salmon over medium-high, 4 minutes on the first side until a spiced crust forms, then 2–3 minutes on the second.","Toss the charred corn with sliced scallions, chopped cilantro and a squeeze of lime to make a quick salsa.","Flake the salmon into big pieces over bowls of rice, spoon on the corn salsa, and fan sliced avocado alongside with the last lime wedge."],"tip":"A fish fillet will tell you when to flip — if it fights the spatula, give it another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_rice_bowl', '{"id":"shrimp_scampi_rice_bowl","name":"Shrimp scampi rice bowl","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"rice","q":160},{"f":"butter","q":30},{"f":"olive_oil","q":10},{"f":"garlic","q":0.8},{"f":"lemon","q":1},{"f":"spinach","q":150},{"f":"parmesan","q":20},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Cook the rice while you pat the shrimp bone-dry and season them with salt and plenty of black pepper.","Melt the butter with the olive oil over medium heat and sizzle the sliced garlic 60–90 seconds, until fragrant and barely golden — not brown.","Raise the heat, add the shrimp in one layer, and cook about 90 seconds per side until they curl into loose commas and turn pink.","Squeeze in the lemon juice, add the spinach by the handful, and toss just until it collapses into the garlicky butter.","Spoon everything over the rice, making sure the pan juices soak in, then shower with grated parmesan and chopped parsley."],"tip":"Shrimp curled into a tight O are overcooked — pull them at the C stage and let the pan finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_glazed_tofu_rice_bowl', '{"id":"sesame_glazed_tofu_rice_bowl","name":"Sesame-glazed crispy tofu rice bowl","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":20},{"f":"sesame_oil","q":15},{"f":"ginger","q":10},{"f":"garlic","q":0.4},{"f":"broccoli","q":300},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"olive_oil","q":10}],"steps":["Press the tofu between towels under a heavy pan for 10 minutes while the rice cooks, then tear it into craggy bite-size chunks.","Stir the soy sauce, maple syrup, sesame oil, grated ginger and minced garlic into a glaze.","Sear the tofu in the olive oil over medium-high heat, undisturbed 3–4 minutes per side, until the ragged edges turn deep golden and crackly.","Push the tofu aside, add the broccoli florets with a splash of water, cover, and steam 3 minutes until vivid green with a little bite.","Pour the glaze over everything and toss 60 seconds until it bubbles, thickens and lacquers the tofu.","Serve over rice with shaved carrots and a flurry of sliced scallions."],"tip":"Torn tofu beats cubed — all those rough edges are extra real estate for the glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bulgogi_style_beef_rice_bowl', '{"id":"bulgogi_style_beef_rice_bowl","name":"Bulgogi-style beef rice bowl","emoji":"🥩","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"sugar","q":15},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.6},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"spinach","q":150},{"f":"carrots","q":100}],"steps":["Set the rice going, then stir together the soy sauce, sugar, sesame oil, minced garlic and grated ginger until the sugar dissolves.","Brown the ground beef in a hot, dry skillet over high heat, pressing it flat and leaving it alone 2–3 minutes so it develops a crusty, sizzling underside before you break it up.","Pour in the sauce and let it bubble hard for 2 minutes, until it reduces to a glossy coating that clings to every crumble.","Stir in the spinach and most of the scallions off the heat, letting the residual warmth wilt the greens.","Serve over rice with matchstick carrots on one side and the remaining scallions scattered over the top."],"tip":"Resist the urge to stir early — the crusty browned bits are where all the bulgogi magic lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_rice_bowl', '{"id":"turkey_taco_rice_bowl","name":"Turkey taco rice bowl","emoji":"🌮","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":320},{"f":"rice","q":160},{"f":"salsa","q":150},{"f":"chili_powder","q":8},{"f":"cumin","q":4},{"f":"corn_frozen","q":100},{"f":"cheddar","q":40},{"f":"sour_cream","q":60},{"f":"romaine","q":0.3},{"f":"lime","q":0.5},{"f":"olive_oil","q":10}],"steps":["Simmer the rice while you heat the oil in a wide skillet over medium-high heat.","Brown the turkey with the chili powder, cumin and a big pinch of salt, breaking it into small crumbles, 6–7 minutes until no pink remains and the spices smell toasted.","Stir in the salsa and corn and simmer 4–5 minutes, until the mixture thickens from soupy to spoonable and coats the meat like a proper taco filling.","Loosen the sour cream with the lime juice and a spoonful of water until it drizzles from a spoon.","Layer bowls with rice, the saucy turkey, shredded romaine and cheddar, then zigzag the lime crema over the top."],"tip":"Taste the turkey before assembling — under-salted taco meat is the silent killer of otherwise great bowls."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_balsamic_pork_rice_bowl', '{"id":"maple_balsamic_pork_rice_bowl","name":"Maple-balsamic pork rice bowl","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"rice","q":160},{"f":"maple_syrup","q":30},{"f":"balsamic_vinegar","q":30},{"f":"garlic","q":0.4},{"f":"green_beans","q":250},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Start the rice, then slice the pork loin into thin medallions and season generously with salt and pepper.","Sear the pork in half the oil over medium-high heat, about 2 minutes per side until golden with a blush of pink inside, then rest it on a plate.","In the same pan, soften the sliced onion and green beans in the remaining oil, 5–6 minutes, until the beans blister and the onion turns sweet at the edges.","Add the minced garlic, then the maple syrup and balsamic; let the mixture boil 1–2 minutes until it turns syrupy and coats the back of a spoon.","Return the pork and its juices to the pan, turning each piece through the dark, glossy glaze, and serve over the rice."],"tip":"The glaze goes from syrup to candy fast — pull it the moment your spoon leaves a trail across the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_egg_donburi_bowl', '{"id":"mushroom_egg_donburi_bowl","name":"Soy-butter mushroom and egg donburi","emoji":"🍳","cuisine":"Asian","meal":["dinner","breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"mushrooms","q":300},{"f":"rice","q":160},{"f":"soy_sauce","q":25},{"f":"butter","q":20},{"f":"sugar","q":5},{"f":"sesame_oil","q":5},{"f":"scallions","q":1}],"steps":["Cook the rice, then sear the thickly sliced mushrooms in the butter over high heat, undisturbed for 3 minutes, until their cut sides are mahogany and the pan hisses.","Add the soy sauce and sugar and toss 1 minute, letting the mushrooms drink up the salty-sweet glaze until barely any liquid remains.","Beat the eggs loosely with a fork — streaky, not uniform — and pour them over the mushrooms.","Drop the heat to low and drag a spatula slowly through the eggs, 60–90 seconds, stopping while they are still glossy and slightly wet on top.","Slide the whole soft tangle over bowls of hot rice, drizzle with sesame oil, and bury it in sliced scallions."],"tip":"Take the eggs off when they look one minute undercooked — the ride from pan to bowl finishes them perfectly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_crema_bowl', '{"id":"black_bean_avocado_crema_bowl","name":"Cumin black bean bowl with avocado crema","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"rice","q":160},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"lime","q":1},{"f":"cumin","q":6},{"f":"chili_powder","q":4},{"f":"garlic","q":0.4},{"f":"onion","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Get the rice cooking, then sweat the diced onion in the oil over medium heat, 4–5 minutes, until translucent and sweet-smelling.","Add the minced garlic, cumin and chili powder and fry 30 seconds until the spices bloom and darken a shade.","Tip in the black beans with a splash of water and simmer 8 minutes, mashing about a third of them against the pan so the pot turns thick and creamy.","Meanwhile blend or mash the avocado with the sour cream, lime juice and a pinch of salt into a smooth, pale-green crema.","Build bowls of rice and beans, spoon the crema generously over the top, and finish with halved cherry tomatoes and torn cilantro."],"tip":"Mashing a few beans is free thickener — never let a watery bean pot happen to good rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_chickpea_rice_bowl', '{"id":"mediterranean_chickpea_rice_bowl","name":"Crispy chickpea rice bowl with lemon-hummus sauce","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["sesame","dairy"],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":350},{"f":"rice","q":140},{"f":"hummus","q":70},{"f":"lemon","q":1},{"f":"cucumber","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":50},{"f":"olives","q":40},{"f":"oregano","q":3},{"f":"paprika","q":3},{"f":"olive_oil","q":10}],"steps":["Start the rice, then dry the chickpeas thoroughly on a towel — wet chickpeas steam instead of crisp.","Fry them in the oil over medium-high heat with the paprika, oregano and a pinch of salt, shaking the pan occasionally for 8–10 minutes, until they rattle and blister golden.","Whisk the hummus with the lemon juice and 2–3 tablespoons of warm water into a pourable, silky sauce.","Dice the cucumber and halve the cherry tomatoes, seasoning them with a little salt so they glisten.","Spread the lemon-hummus sauce over bowls of rice, pile on the hot crackly chickpeas, then top with the salad, crumbled feta and olives."],"tip":"Sauce under the toppings, not over — every forkful of rice drags through it on the way up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_lentil_rice_bowl', '{"id":"curried_lentil_rice_bowl","name":"Coconut-curried lentil rice bowl","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":140},{"f":"rice","q":130},{"f":"coconut_milk","q":120},{"f":"curry_powder","q":10},{"f":"turmeric","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"tomato","q":1},{"f":"spinach","q":150},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Simmer the rinsed lentils in plenty of water with the turmeric for 20–22 minutes, until tender but not mushy, then drain; cook the rice alongside.","Meanwhile fry the diced onion in the oil over medium heat, 6–8 minutes, until golden at the edges and jammy in the middle.","Add the minced garlic, grated ginger and curry powder and sizzle 1 minute, until the whole kitchen smells like a curry house.","Stir in the chopped tomato and cook 3–4 minutes until it slumps, then add the lentils and coconut milk and simmer 5 minutes into a loose, spoonable curry.","Fold in the spinach until it wilts, season with salt, and ladle over the rice with a shower of cilantro."],"tip":"Lentils keep drinking liquid as they sit — leave the curry a touch soupier than seems right."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_sesame_tuna_rice_bowl', '{"id":"soy_sesame_tuna_rice_bowl","name":"Soy-sesame tuna rice bowl","emoji":"🍱","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"rice","q":160},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":12},{"f":"honey","q":10},{"f":"ginger","q":8},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"scallions","q":0.5}],"steps":["Cook the rice and let it steam off the heat for 5 minutes so the grains stay distinct and fluffy.","Whisk the soy sauce, sesame oil, honey and finely grated ginger into a dressing that tastes sharp, nutty and a little sweet.","Drain the tuna well and flake it into big chunks, folding in a third of the dressing so every piece gets seasoned.","Slice the cucumber into thin half-moons and shave the carrots into ribbons with a peeler.","Mound the warm rice into bowls, arrange the tuna and vegetables in neat piles, then spoon the remaining dressing over and finish with sliced scallions."],"tip":"Warm rice plus cold crunchy vegetables is the whole point — don''t let either side go lukewarm."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('green_goddess_edamame_rice_bowl', '{"id":"green_goddess_edamame_rice_bowl","name":"Green goddess edamame rice bowl","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["soy","dairy"],"time":25,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"rice","q":150},{"f":"greek_yogurt","q":150},{"f":"basil","q":0.5},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"cucumber","q":0.5},{"f":"spinach","q":100},{"f":"cherry_tomatoes","q":100}],"steps":["Cook the rice, then blanch the edamame in salted boiling water for 3–4 minutes until bright green and just tender; drain and toss with a pinch of salt.","Blend the greek yogurt, basil leaves, lemon juice, garlic, olive oil and a pinch of salt until the sauce turns a pale spring green and tastes bright and herbal.","Fold the spinach into the hot rice so it wilts into silky ribbons.","Dice the cucumber and halve the cherry tomatoes for crunch and acidity.","Swoosh a thick layer of green goddess sauce around each bowl, mound in the spinach rice, and top with edamame, cucumber and tomatoes."],"tip":"Blend the sauce longer than feels necessary — flecks of basil are pretty, but pale green velvet is better."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_herb_chicken_quinoa_bowl', '{"id":"lemon_herb_chicken_quinoa_bowl","name":"Lemon Herb Chicken Quinoa Bowl","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_breast","q":320},{"f":"quinoa","q":140},{"f":"zucchini","q":2},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"spinach","q":100},{"f":"feta","q":50}],"steps":["Heat the oven to 425°F and rinse the quinoa until the water runs clear, then simmer it in double its volume of water for 15 minutes until the germ spirals loose.","Toss thick half-moons of zucchini, strips of bell pepper, and onion wedges with half the olive oil, then roast 20 minutes until the edges char and turn sweet.","Season the chicken breasts generously, sear them in the remaining oil over medium-high heat for 5 to 6 minutes per side until deeply golden and 165°F inside, then rest 5 minutes before slicing against the grain.","Squeeze the lemon over the warm quinoa along with the minced garlic and a big pinch of salt, folding until fragrant and glossy.","Pile quinoa into bowls, wilt the spinach under the hot roasted vegetables, fan the chicken on top, and finish with crumbled feta and any resting juices."],"tip":"Resting the chicken is not optional — slice it early and you will watch your sauce run away across the cutting board."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_soy_glazed_salmon_quinoa_bowl', '{"id":"honey_soy_glazed_salmon_quinoa_bowl","name":"Honey-Soy Glazed Salmon Quinoa Bowl","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"quinoa","q":140},{"f":"broccoli","q":300},{"f":"carrots","q":150},{"f":"soy_sauce","q":40},{"f":"honey","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Start the quinoa simmering in salted water for 15 minutes while the oven heats to 425°F.","Spread broccoli florets and thin carrot coins on a sheet pan with half the sesame oil and roast 18 minutes until the broccoli tips crisp and brown.","Whisk the soy sauce, honey, minced garlic, and remaining sesame oil into a glaze, then simmer it in a small pan for 2 minutes until it coats a spoon.","Sear the salmon fillets skin-side down in a hot skillet for 4 minutes until the skin crackles and releases, flip, and cook 2 minutes more.","Brush the glaze thickly over the salmon in its last minute so it turns lacquered and sticky, then serve everything over the fluffed quinoa with extra glaze drizzled around the bowl."],"tip":"If the salmon fights you when you try to flip it, it is not ready — patience releases the skin, spatula violence does not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_shrimp_quinoa_bowl', '{"id":"chili_lime_shrimp_quinoa_bowl","name":"Chili-Lime Shrimp Quinoa Bowl","emoji":"🍤","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"quinoa","q":140},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"olive_oil","q":25}],"steps":["Simmer the quinoa in salted water for 15 minutes, then fluff it with the zest and juice of one lime.","Roast the bell pepper strips and onion wedges at 450°F with half the olive oil for 18 minutes until blistered and sweet at the edges.","Pat the shrimp bone-dry, toss them with minced garlic, a heavy dusting of chili powder and paprika, and the remaining oil.","Sear the shrimp in a screaming-hot skillet for 90 seconds per side, just until they curl into loose Cs and turn opaque pink.","Build bowls of citrusy quinoa, charred peppers, and shrimp, then crown with sliced avocado and wedges of the second lime for squeezing at the table."],"tip":"A shrimp curled into a tight O is overcooked and telling on you — pull them at a relaxed C every time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_sesame_tofu_quinoa_bowl', '{"id":"maple_sesame_tofu_quinoa_bowl","name":"Maple-Sesame Crispy Tofu Quinoa Bowl","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame","nuts"],"time":45,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"quinoa","q":140},{"f":"mushrooms","q":200},{"f":"carrots","q":150},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":20},{"f":"garlic","q":0.3},{"f":"cashews","q":40}],"steps":["Press the tofu between paper towels under a heavy pan for 15 minutes, then tear it into rough bite-size chunks — the craggy edges crisp better than clean cubes.","Roast the tofu, halved mushrooms, and carrot coins on a sheet pan at 425°F with the sesame oil for 25 minutes, flipping once, until the tofu is golden and the mushrooms have shrunk and concentrated.","Meanwhile simmer the quinoa in salted water for 15 minutes and toast the cashews in a dry pan until they smell nutty.","Whisk the soy sauce, maple syrup, and minced garlic, then pour it over the hot sheet pan for the final 3 minutes so it bubbles into a sticky glaze.","Spoon everything over the quinoa, scraping up every dark caramelized bit from the pan, and scatter the cashews on top for crunch."],"tip":"Torn tofu has more surface area than cubed tofu, and surface area is just a nerdy word for crispiness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_chickpea_couscous_bowl', '{"id":"moroccan_spiced_chickpea_couscous_bowl","name":"Moroccan-Spiced Chickpea Couscous Bowl","emoji":"🥕","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","nuts"],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":350},{"f":"couscous","q":140},{"f":"carrots","q":250},{"f":"zucchini","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":20},{"f":"maple_syrup","q":15},{"f":"lemon","q":1},{"f":"almonds","q":25}],"steps":["Heat the oven to 425°F and toss the drained chickpeas, carrot batons, zucchini half-moons, and onion wedges with the olive oil, cumin, cinnamon, and a pinch of cayenne.","Roast for 25 minutes until the chickpeas rattle drily on the pan and the carrots wrinkle and caramelize at the tips.","Drizzle the maple syrup over the vegetables for the last 5 minutes so it bubbles into a light glaze rather than burning.","Pour boiling water over the couscous with a pinch of salt, cover for 5 minutes, then rake it with a fork until every grain separates.","Fold the lemon zest and juice into the couscous, top with the spiced vegetables and chickpeas, and shower with toasted sliced almonds."],"tip":"Couscous rewards a fork and punishes a spoon — stir it and you get paste, rake it and you get clouds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_quinoa_burrito_bowl', '{"id":"smoky_black_bean_quinoa_burrito_bowl","name":"Smoky Black Bean Quinoa Burrito Bowl","emoji":"🌯","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"quinoa","q":140},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":20}],"steps":["Simmer the quinoa in salted water for 15 minutes, then fluff and hold it covered off the heat.","Roast the bell pepper strips and onion wedges at 450°F with half the oil for 18 minutes until the edges blacken fajita-style.","Warm the remaining oil in a saucepan, bloom the minced garlic with paprika and cumin for 30 seconds until fragrant, then add the black beans and diced tomatoes.","Simmer the beans for 8 minutes, mashing a few against the pot wall so the mixture thickens into something saucy and glossy.","Layer quinoa, smoky beans, and charred vegetables into bowls, then finish with sliced avocado and a hard squeeze of lime to wake everything up."],"tip":"Mashing a quarter of the beans is the free thickener nobody talks about — no cream, no flour, just physics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_turkey_couscous_bowl', '{"id":"tuscan_turkey_couscous_bowl","name":"Tuscan Turkey and Tomato Couscous Bowl","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"couscous","q":140},{"f":"tomato","q":3},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"parmesan","q":40}],"steps":["Brown the ground turkey in half the olive oil over medium-high heat for 6 minutes, pressing it flat and leaving it alone so it develops a deep golden crust before you break it up.","Add the diced onion and cook 4 minutes until translucent, then stir in the minced garlic, fennel seed, and chili flakes until fragrant.","Tumble in the chopped tomatoes and simmer 8 minutes until they collapse into a rough, rusty sauce that coats the meat.","Steep the couscous in boiling salted water, covered, for 5 minutes, then fluff it with a fork and a thread of the remaining oil.","Fold the spinach into the hot turkey sauce until it just wilts, spoon everything over the couscous, and grate the parmesan generously over the top while it steams."],"tip":"Fennel seed is the cheat code that makes plain turkey taste like Italian sausage without the sausage."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spiced_beef_couscous_bowl_with_yogurt', '{"id":"spiced_beef_couscous_bowl_with_yogurt","name":"Spiced Beef Couscous Bowl with Garlic Yogurt","emoji":"🥩","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"couscous","q":140},{"f":"zucchini","q":1},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"greek_yogurt","q":150},{"f":"lemon","q":0.5}],"steps":["Stir one grated garlic clove and the lemon juice into the yogurt with a pinch of salt and let it sit so the raw bite mellows.","Roast the zucchini half-moons at 425°F with the olive oil for 15 minutes until bronzed and tender.","Brown the beef hard in a dry skillet over high heat for 5 minutes until crusty, then stir in the diced onion, remaining garlic, cinnamon, cumin, and allspice.","Add the chopped tomatoes and simmer 6 minutes until the pan smells like a spice market and the juices turn thick and dark.","Steep the couscous in boiling water for 5 minutes, fluff, then bowl it up with the spiced beef, roasted zucchini, and generous swoops of the cold garlic yogurt."],"tip":"Cinnamon in savory beef feels wrong right up until the first bite, at which point it feels like a secret you should have known years ago."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sunrise_quinoa_breakfast_bowl', '{"id":"sunrise_quinoa_breakfast_bowl","name":"Sunrise Quinoa Breakfast Bowl","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"quinoa","q":120},{"f":"sweet_potatoes","q":300},{"f":"kale","q":0.5},{"f":"avocado","q":1},{"f":"olive_oil","q":20},{"f":"garlic","q":0.1}],"steps":["Roast small cubes of sweet potato at 425°F with half the olive oil and paprika for 22 minutes until the corners caramelize and give easily to a fork.","Simmer the quinoa in salted water for 15 minutes while the potatoes roast, then fluff and keep warm.","Sauté the torn kale with the minced garlic in the remaining oil for 3 minutes until it turns glossy and deep green, seasoning with salt and a pinch of chili flakes.","Fry the eggs in the same skillet over medium heat until the whites are set and lacy at the edges but the yolks still tremble.","Assemble bowls of quinoa, sweet potatoes, and kale, slide two eggs onto each, and fan the avocado alongside so the yolk becomes the sauce."],"tip":"The runny yolk is the dressing — cook it hard and you will be eating a perfectly nice bowl that is missing its whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_quinoa_bowl', '{"id":"sesame_edamame_quinoa_bowl","name":"Sesame Edamame Quinoa Bowl","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"quinoa","q":140},{"f":"carrots","q":200},{"f":"cucumber","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2}],"steps":["Simmer the quinoa in salted water for 15 minutes until the grains uncurl, then spread it on a plate to cool slightly so it stays distinct rather than gummy.","Roast the carrot coins at 425°F with a third of the sesame oil for 18 minutes until browned and bendy-sweet.","Blanch the edamame in boiling water for 3 minutes, drain well, and pat dry.","Whisk the soy sauce, maple syrup, remaining sesame oil, and grated garlic into a dressing that tastes salty-sweet with a raw garlicky edge.","Toss the quinoa, edamame, roasted carrots, and thin cucumber half-moons with the dressing, tasting as you go until every bite pops."],"tip":"Dress this bowl while the quinoa is still warm — warm grains drink dressing, cold grains just wear it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_tuna_couscous_bowl_2', '{"id":"mediterranean_tuna_couscous_bowl_2","name":"Mediterranean Tuna Couscous Bowl","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"couscous","q":140},{"f":"tomato","q":2},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"hummus","q":100}],"steps":["Roast the quartered tomatoes at 450°F with half the olive oil for 15 minutes until their edges blister and their juices turn jammy.","Steep the couscous in boiling salted water, covered, for 5 minutes, then fluff it with a fork and the remaining oil.","Fold the lemon zest, half the juice, and plenty of black pepper into the couscous while it is still steaming.","Drain the tuna well and flake it into big shameless chunks with a splash of the remaining lemon juice.","Swipe hummus around each bowl, mound the lemony couscous in the center, and top with tuna, roasted tomatoes, and cool cucumber half-moons for contrast."],"tip":"Roasting the tomatoes takes 15 minutes and upgrades canned tuna from desk lunch to something you would photograph."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_tomato_mozzarella_quinoa_bowl', '{"id":"roasted_tomato_mozzarella_quinoa_bowl","name":"Roasted Tomato and Mozzarella Quinoa Bowl","emoji":"🧀","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"mozzarella","q":150},{"f":"quinoa","q":140},{"f":"tomato","q":4},{"f":"zucchini","q":2},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"spinach","q":100}],"steps":["Heat the oven to 450°F and toss the quartered tomatoes and thick zucchini half-moons with the olive oil, smashed garlic, dried oregano, and salt.","Roast for 22 minutes until the tomatoes slump and leak sweet, concentrated juice and the zucchini picks up brown spots.","Simmer the quinoa in salted water for 15 minutes while the vegetables roast, then fluff it well.","Fold the spinach into the hot quinoa so it wilts from residual heat alone.","Top the bowls with the roasted vegetables and every drop of pan juice, then tear the mozzarella over the top so it softens into milky pockets against the heat."],"tip":"The pan juice is the sauce — tip the sheet pan over each bowl like you mean it, because that is where the flavor went."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_cauliflower_chickpea_quinoa_bowl', '{"id":"curried_cauliflower_chickpea_quinoa_bowl","name":"Curried Cauliflower Quinoa Bowl","emoji":"🍛","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":0.8},{"f":"chickpeas","q":200},{"f":"quinoa","q":140},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"greek_yogurt","q":150},{"f":"lemon","q":0.5}],"steps":["Heat the oven to 450°F and toss the cauliflower florets, drained chickpeas, and onion wedges with the oil, curry powder, turmeric, and salt until everything is stained gold.","Roast for 25 to 28 minutes, flipping halfway, until the cauliflower tips char nearly black in places — that bitterness against the sweet spice is the whole dish.","Simmer the quinoa in salted water for 15 minutes while the pan roasts, then fluff.","Stir the grated garlic and lemon juice into the yogurt with a pinch of salt to make a cool, tangy raita-style sauce.","Spoon the roasted cauliflower and chickpeas over the quinoa and drape the garlic yogurt across the top, letting it melt into the hot spiced edges."],"tip":"Crowd the sheet pan and the cauliflower steams instead of chars — give the florets personal space and they will reward you with crispy edges."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avgolemono_chicken_rice_soup', '{"id":"avgolemono_chicken_rice_soup","name":"Lemon Chicken and Rice Soup (Avgolemono)","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":450},{"f":"rice","q":180},{"f":"broth","q":1200},{"f":"eggs","q":2},{"f":"lemon","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"olive_oil","q":30}],"steps":["Warm the olive oil in a heavy pot over medium heat and sweat the diced onion, carrots, and celery for 6 to 8 minutes, until the onion turns translucent and smells sweet.","Pour in the broth, bring it to a gentle boil, then slide in the whole chicken breasts and the rice; simmer uncovered for 18 minutes, until the chicken registers 165F and the rice is tender.","Lift out the chicken, shred it with two forks, and return it to the pot off the heat.","Whisk the eggs with the juice of the lemon in a bowl, then ladle in hot broth a splash at a time while whisking, so the eggs warm gently instead of scrambling.","Stir the egg mixture back into the pot and heat over low, stirring, for 2 to 3 minutes until the soup turns pale gold and coats a spoon like thin custard; season generously and serve steaming."],"tip":"If your egg mixture scrambles, you rushed it — avgolemono rewards patience the way a cat rewards ignoring it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hearty_beef_vegetable_soup', '{"id":"hearty_beef_vegetable_soup","name":"Hearty Beef and Potato Vegetable Soup","emoji":"🥣","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":450},{"f":"potatoes","q":400},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":2},{"f":"corn_frozen","q":150},{"f":"broth","q":1000}],"steps":["Brown the ground beef in a dry Dutch oven over medium-high heat for 6 to 7 minutes, breaking it into rough crumbles and letting it develop deep mahogany edges before you stir.","Add the chopped onion, carrots, and celery to the rendered fat and cook 5 minutes, scraping up the browned bits, until the vegetables soften slightly.","Stir in the minced garlic and chopped tomatoes and cook 2 minutes, until the tomatoes slump and turn jammy.","Pour in the broth, add the diced potatoes, and simmer partially covered for 20 minutes, until a fork slides through a potato cube with no resistance.","Stir in the corn, simmer 3 more minutes, then season boldly with salt and plenty of black pepper and serve in wide bowls."],"tip":"Resist stirring the beef too early — the crust it forms is the flavor deposit that pays this soup''s rent."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_kidney_bean_chili_soup', '{"id":"turkey_kidney_bean_chili_soup","name":"Turkey and Kidney Bean Chili Soup","emoji":"🌶️","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":450},{"f":"black_beans","q":400},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"corn_frozen","q":150},{"f":"broth","q":750},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a large pot over medium-high and sear the ground turkey for 5 to 6 minutes, pressing it flat and leaving it alone until it browns and releases from the pan.","Add the diced onion and bell pepper and cook 5 minutes, until the pepper''s edges soften and the onion picks up a little color.","Stir in the garlic and chopped tomatoes with a big pinch of salt and let them cook down for 5 minutes, until the mixture thickens and smells sweet and roasty.","Pour in the broth and the drained kidney beans and simmer uncovered for 15 minutes, until the liquid reduces slightly and turns brick red.","Add the corn, simmer 3 minutes more, then taste — it should be smoky-sweet with a gentle burn — and adjust the seasoning before ladling it out."],"tip":"Chili soup improves overnight, so make it today and take the credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_lentil_coconut_dal_soup', '{"id":"golden_lentil_coconut_dal_soup","name":"Golden Lentil and Coconut Dal Soup","emoji":"🥥","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"coconut_milk","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"olive_oil","q":15}],"steps":["Warm the oil in a wide pot over medium heat and fry the diced onion for 6 minutes, until it turns golden at the edges and smells faintly of caramel.","Add the minced garlic and grated ginger and sizzle 1 minute, then stir in the chopped tomatoes and cook 4 to 5 minutes, until they break down into a rough, glossy paste.","Add the rinsed lentils and 1 liter of water, bring to a boil, then reduce to a lively simmer for 20 minutes, skimming any foam, until the lentils collapse into a rough puree.","Stir in the coconut milk and simmer 5 minutes, until the soup is creamy and thick enough to briefly hold the trail of a spoon.","Fold in the spinach off the heat, let it wilt for 1 minute in the residual warmth, season with salt, and serve with the coconut fat glistening on top."],"tip":"Whisk the pot hard for ten seconds at the end — it fakes an immersion blender and nobody will audit you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_kale_potato_soup', '{"id":"chickpea_kale_potato_soup","name":"Rustic Chickpea, Kale, and Potato Soup","emoji":"🍲","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chickpeas","q":480},{"f":"kale","q":0.8},{"f":"potatoes","q":300},{"f":"tomato","q":2},{"f":"carrots","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45}],"steps":["Heat two-thirds of the olive oil in a soup pot over medium heat and cook the chopped onion and carrots for 7 minutes, until soft and sweet-smelling.","Add the sliced garlic and cook 1 minute, just until fragrant, then tip in the chopped tomatoes and simmer 5 minutes, until they slump into a loose sauce.","Add the diced potatoes, drained chickpeas, and 1 liter of water; bring to a boil and simmer 18 minutes, until the potatoes are creamy inside and the broth tastes savory.","Mash a ladleful of chickpeas and potato against the side of the pot to thicken the broth to a silky, rustic body.","Stir in the torn kale and simmer 4 minutes, until it turns deep green and tender, then finish each bowl with the remaining olive oil poured over in a shameless golden ribbon."],"tip":"That final drizzle of raw olive oil is not decoration — it is the soup''s paycheck, so do not skim it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_rice_soup', '{"id":"smoky_black_bean_rice_soup","name":"Smoky Black Bean and Rice Soup","emoji":"🫘","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"black_beans","q":700},{"f":"rice","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"tomato","q":1.5},{"f":"lime","q":1},{"f":"olive_oil","q":30}],"steps":["Heat the olive oil in a Dutch oven over medium heat and cook the diced onion and bell pepper for 6 to 7 minutes, until the pepper chars slightly at the edges and the kitchen smells sweet.","Add the minced garlic and chopped tomatoes and cook 3 minutes, mashing the tomatoes with your spoon until they melt into the vegetables.","Add the drained black beans, rice, and 1.2 liters of water; bring to a boil, then simmer partly covered for 18 minutes, until the rice is tender and the broth has darkened to deep violet-black.","Ladle about a quarter of the soup into a bowl, mash it thoroughly, and stir it back in so the broth turns thick and velvety while whole beans still pop between your teeth.","Squeeze in the lime juice, season assertively with salt, and simmer 2 final minutes before serving — the acid should make the whole pot taste suddenly brighter."],"tip":"Lime at the end is non-negotiable; black beans without acid are a bass line with no melody."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_tofu_noodle_soup', '{"id":"ginger_tofu_noodle_soup","name":"Ginger Tofu and Rice Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":35,"servings":4,"ing":[{"f":"tofu","q":450},{"f":"rice_noodles","q":200},{"f":"mushrooms","q":200},{"f":"edamame_frozen","q":150},{"f":"spinach","q":100},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":30}],"steps":["Heat half the sesame oil in a large pot over medium-high and sear the sliced mushrooms for 5 minutes without crowding, until their edges brown and they squeak less against the spoon.","Add the julienned ginger and sliced garlic and stir for 1 minute, until the pot smells sharp and citrusy.","Pour in 1.4 liters of water and the soy sauce, bring to a rolling simmer, and slide in the tofu cut into large cubes along with the edamame; simmer gently for 8 minutes so the tofu drinks in the broth.","Add the rice noodles and cook 4 to 5 minutes, until they turn silky and translucent but still have a slight chew.","Turn off the heat, wilt in the spinach, and finish with the remaining sesame oil; the broth should taste savory, gingery, and just salty enough to make you go back for more."],"tip":"Cube the tofu big and handle it once — it is delicate, and this soup is not the place for confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_soup_3', '{"id":"coconut_lime_shrimp_soup_3","name":"Coconut-Lime Shrimp and Rice Soup","emoji":"🦐","cuisine":"Asian","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free"],"allergens":["shellfish"],"time":40,"servings":4,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":400},{"f":"rice","q":150},{"f":"mushrooms","q":150},{"f":"bell_pepper","q":1},{"f":"ginger","q":20},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"broth","q":750}],"steps":["Combine the broth, sliced ginger, and minced garlic in a pot and bring to a simmer over medium heat, letting the aromatics steep for 5 minutes until the broth smells warm and peppery.","Add the rice, sliced mushrooms, and thinly sliced bell pepper and simmer 15 minutes, until the rice is tender and the mushrooms have gone plush.","Stir in the coconut milk and heat until it barely trembles at the edges — do not let it boil hard or it will look curdled and sulky.","Add the shrimp and poach 3 to 4 minutes, until they curl into loose commas and turn opaque pink all the way through.","Kill the heat, squeeze in the juice of both limes, season with salt, and serve immediately while the broth is fragrant, creamy, and just tart enough to wake you up."],"tip":"Shrimp go from tender to eraser in about ninety seconds, so set a timer and trust it over your optimism."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_corn_chowder', '{"id":"salmon_corn_chowder","name":"Creamy Salmon and Corn Chowder","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":4,"ing":[{"f":"salmon","q":450},{"f":"potatoes","q":500},{"f":"corn_frozen","q":300},{"f":"milk","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"broth","q":500}],"steps":["Melt the butter in a heavy pot over medium heat and cook the diced onion and celery for 6 minutes, until soft and translucent but not browned.","Add the diced potatoes and broth, bring to a simmer, and cook 15 minutes, until the potato cubes yield completely to a fork.","Mash roughly a third of the potatoes against the pot wall to thicken the base, then stir in the milk and corn and bring back to a bare simmer — small bubbles at the edge, never a boil.","Nestle in the salmon cut into large chunks and poach gently for 5 to 6 minutes, until the fish flakes into rosy petals when nudged.","Season with salt and a heavy hand of black pepper, let the chowder rest off the heat for 5 minutes to settle and thicken, then serve in deep bowls."],"tip":"A chowder that boils is a chowder that breaks — keep it at a lazy shimmer and it will stay silky."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_drop_corn_rice_soup', '{"id":"egg_drop_corn_rice_soup","name":"Silky Egg Drop and Corn Soup","emoji":"🥚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free"],"allergens":["eggs","sesame"],"time":30,"servings":4,"ing":[{"f":"eggs","q":5},{"f":"corn_frozen","q":300},{"f":"rice","q":180},{"f":"broth","q":1200},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"spinach","q":100},{"f":"sesame_oil","q":15}],"steps":["Bring the broth to a boil with the sliced ginger and smashed garlic, then add the rice and simmer 15 minutes, until the grains are tender and the broth has taken on a faint gingery heat.","Add the corn and simmer 3 minutes, until the kernels taste sweet and pop cleanly.","Beat the eggs thoroughly in a spouted cup, then reduce the soup to the gentlest simmer and pour the eggs in a thin, slow stream while stirring the pot in one lazy circle.","Watch the eggs bloom into soft golden ribbons — about 30 seconds — then immediately stop stirring so they stay wispy instead of shredding.","Wilt in the spinach, season with salt, and finish each bowl with a few drops of sesame oil, which should hit your nose before the spoon does."],"tip":"Pour the eggs slow and stir slower — egg drop soup punishes enthusiasm and rewards the half-asleep."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spicy_peanut_sweet_potato_soup', '{"id":"spicy_peanut_sweet_potato_soup","name":"Spicy Peanut and Sweet Potato Soup","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":40,"servings":4,"ing":[{"f":"peanut_butter","q":120},{"f":"sweet_potatoes","q":500},{"f":"coconut_milk","q":200},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":20},{"f":"spinach","q":150}],"steps":["Simmer the diced onion, minced garlic, and grated ginger in a splash of water in a large pot for 4 minutes, until softened and fragrant.","Add the chopped tomatoes and cook 5 minutes, crushing them down until they thicken into a rough, brick-colored base.","Add the sweet potatoes in 2-centimeter cubes and 1 liter of water, bring to a boil, and simmer 15 minutes, until the cubes are fudgy-soft at the center.","Whisk the peanut butter with a ladle of hot broth in a bowl until smooth, then stir it into the pot along with the coconut milk and simmer 5 minutes, until the soup turns thick, glossy, and the color of caramel.","Fold in the spinach until it collapses, season with salt and as much chile heat as you dare, and serve — it should taste rich, nutty, and quietly fiery."],"tip":"Temper the peanut butter with hot broth first, or you will spend ten minutes chasing a stubborn blob around the pot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_potato_cheddar_soup', '{"id":"loaded_potato_cheddar_soup","name":"Loaded Potato and Cheddar Soup","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"potatoes","q":800},{"f":"cheddar","q":120},{"f":"milk","q":500},{"f":"butter","q":40},{"f":"sour_cream","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broccoli","q":200}],"steps":["Melt the butter in a Dutch oven over medium heat and cook the diced onion for 6 minutes, until soft and pale gold, then stir in the garlic for a final fragrant minute.","Add the diced potatoes and 600 ml of water, cover, and simmer 18 minutes, until the potatoes crush effortlessly against the side of the pot.","Mash about half the potatoes right in the pot, then stir in the milk and the broccoli cut into small florets and simmer 5 minutes, until the broccoli is bright green and just tender.","Drop the heat to low and stir in the grated cheddar a handful at a time, letting each melt fully before the next, until the soup is thick, orange-flecked, and glossy.","Remove from the heat, swirl in the sour cream, season with salt and black pepper, and serve before anyone can ask what is taking so long."],"tip":"Add the cheese off a boil and in stages — dump it all in at once and it will seize into a mozzarella-stick impression."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garden_minestrone_penne_soup', '{"id":"garden_minestrone_penne_soup","name":"Garden Minestrone with Penne","emoji":"🇮🇹","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":50,"servings":4,"ing":[{"f":"black_beans","q":400},{"f":"penne","q":200},{"f":"tomato","q":3},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"zucchini","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"parmesan","q":40}],"steps":["Warm the olive oil in a big pot over medium heat and cook the diced onion, carrots, and celery for 8 minutes, until they soften and the bottom of the pot glazes lightly.","Add the minced garlic and chopped tomatoes with a good pinch of salt and simmer 6 to 7 minutes, until the tomatoes collapse into a loose, sweet sauce.","Pour in 1.25 liters of water, add the drained kidney beans, and simmer 10 minutes so the broth picks up body and a rosy color.","Add the penne and diced zucchini and cook 10 to 11 minutes at a steady bubble, until the pasta is al dente and the zucchini is tender but not slumped.","Taste and season — it should be savory and faintly sweet — then ladle into bowls and shower each with grated parmesan while the steam is still rising."],"tip":"Minestrone thickens as it sits, so if you are meal-prepping, keep a little water back and loosen each reheat like a risotto in reverse."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_and_kidney_bean_chili', '{"id":"smoky_beef_and_kidney_bean_chili","name":"Smoky Beef and Kidney Bean Chili","emoji":"🌶️","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"black_beans","q":480},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":15},{"f":"broth","q":250}],"steps":["Heat the olive oil in a heavy Dutch oven over medium-high heat and brown the ground beef for 6 to 8 minutes, breaking it into rough crumbles and letting it develop deep mahogany edges before stirring.","Add the diced onion and bell pepper and cook 5 minutes until the onion turns translucent and the pan smells sweet, then stir in the minced garlic for 30 seconds until fragrant.","Pour in the crushed tomatoes and broth, scraping up the browned bits stuck to the bottom, and bring everything to a lively simmer.","Stir in the drained kidney beans, reduce the heat to low, and simmer uncovered for 35 to 40 minutes, stirring occasionally, until the chili thickens enough that a spoon dragged through leaves a brief trail.","Rest the pot off the heat for 5 minutes so the flavors settle, then taste and ladle into deep bowls."],"tip":"Chili is one of the few dishes that improves by ignoring it overnight, so make it a day ahead and take all the credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hunter_style_chicken_mushroom_stew', '{"id":"hunter_style_chicken_mushroom_stew","name":"Hunter-Style Chicken and Mushroom Stew","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"chicken_breast","q":600},{"f":"mushrooms","q":250},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"olive_oil","q":30},{"f":"broth","q":250}],"steps":["Cut the chicken breast into generous 4-centimeter chunks and sear them in the olive oil over medium-high heat for 3 minutes per side until golden, then transfer to a plate.","Add the sliced mushrooms to the same pot and cook 6 minutes without crowding until their moisture evaporates and they turn nutty brown at the edges.","Stir in the sliced onion, carrots, and garlic and soften for 4 minutes, then pour in the crushed tomatoes and broth and scrape the fond off the bottom.","Return the chicken and its juices to the pot, cover partially, and simmer gently for 25 minutes until the sauce turns glossy and the chicken pulls apart with light fork pressure.","Simmer uncovered for a final 5 minutes to concentrate the sauce, then serve steaming in shallow bowls."],"tip":"Resist stirring the mushrooms early — browning is flavor, and fidgeting is the enemy of browning."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_red_lentil_dal_stew', '{"id":"golden_red_lentil_dal_stew","name":"Golden Red Lentil Dal Stew","emoji":"🍛","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"spinach","q":150}],"steps":["Rinse the lentils in a sieve until the water runs nearly clear, which keeps the finished dal silky rather than gluey.","Warm the olive oil in a wide pot over medium heat and cook the finely chopped onion for 8 minutes until deeply golden and sweet-smelling, then add the minced garlic for 1 minute more.","Stir in the crushed tomatoes and cook 5 minutes until they darken and the oil separates slightly at the edges, a sign the base is properly cooked down.","Add the lentils and 900 milliliters of water, bring to a boil, then simmer uncovered for 20 to 25 minutes, stirring now and then, until the lentils collapse into a thick, spoonable porridge.","Fold in the spinach off the heat and let it wilt for 2 minutes, then whisk the dal briefly to make it creamy before serving."],"tip":"Dal thickens dramatically as it sits, so keep a cup of hot water nearby and loosen it like you''re negotiating with pudding."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_chickpea_spinach_stew', '{"id":"mediterranean_chickpea_spinach_stew","name":"Mediterranean Chickpea and Spinach Stew","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"chickpeas","q":720},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"spinach","q":200},{"f":"feta","q":100}],"steps":["Heat the olive oil in a deep skillet over medium heat and cook the sliced onion for 6 minutes until soft and lightly bronzed at the edges.","Add the thinly sliced garlic and stir for 1 minute until it perfumes the kitchen, taking care it does not brown and turn bitter.","Pour in the crushed tomatoes and simmer 8 minutes until the sauce thickens and turns brick red, then stir in the drained chickpeas and 200 milliliters of water.","Simmer gently for 15 minutes, lightly crushing a few chickpeas against the pan to give the stew body, until the broth clings to the back of a spoon.","Fold in the spinach by the handful until just wilted and glossy, then crumble the feta over the top and serve straight from the pan."],"tip":"Crushing a third of the chickpeas is the difference between a stew and chickpeas floating in disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('midnight_black_bean_sweet_potato_chili', '{"id":"midnight_black_bean_sweet_potato_chili","name":"Midnight Black Bean and Sweet Potato Chili","emoji":"🫘","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"black_beans","q":720},{"f":"sweet_potatoes","q":400},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":30}],"steps":["Warm the olive oil in a large pot over medium heat and sweat the diced onion and bell pepper for 6 minutes until soft and fragrant.","Stir in the minced garlic for 30 seconds, then add the sweet potatoes cut into 2-centimeter cubes and toss to coat them in the aromatics.","Pour in the crushed tomatoes plus 250 milliliters of water, bring to a boil, then reduce to a steady simmer for 15 minutes until the sweet potato yields slightly to a knife tip.","Add the drained black beans and simmer 15 minutes more, stirring occasionally, until the chili turns thick and glossy and the sweet potatoes are fully tender.","Mash a few sweet potato cubes against the side of the pot to thicken the pot naturally, rest 5 minutes off the heat, and serve."],"tip":"Cut the sweet potatoes evenly unless you enjoy a chili where half the cubes are mush and the other half fight back."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_white_chicken_chili', '{"id":"creamy_white_chicken_chili","name":"Creamy White Chicken Chili","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":50,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"chickpeas","q":240},{"f":"broth","q":750},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":15},{"f":"sour_cream","q":120},{"f":"cheddar","q":60}],"steps":["Heat the olive oil in a Dutch oven over medium heat and soften the diced onion and bell pepper for 5 minutes until they smell sweet and lose their crunch.","Add the minced garlic and stir 30 seconds, then nestle in the whole chicken breasts and pour the broth over the top.","Simmer gently, partially covered, for 18 to 20 minutes until the chicken registers cooked through and shreds easily, then lift it out and pull it apart with two forks.","Return the shredded chicken to the pot with the drained chickpeas, mashing a handful of chickpeas first so they thicken the broth, and simmer 8 minutes until slightly creamy.","Take the pot off the heat, stir in the sour cream until the chili turns pale and velvety, and finish each bowl with a snowfall of grated cheddar."],"tip":"Add the sour cream off the heat or it will curdle and your chili will look like it has regrets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('brothy_shrimp_and_feta_tomato_stew', '{"id":"brothy_shrimp_and_feta_tomato_stew","name":"Brothy Shrimp and Feta Tomato Stew","emoji":"🦐","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["shellfish","dairy"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":600},{"f":"crushed_tomatoes","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"feta","q":100}],"steps":["Warm the olive oil in a wide, deep skillet over medium heat and cook the finely chopped onion for 6 minutes until soft and translucent.","Add the sliced garlic and stir 1 minute until fragrant, then pour in the crushed tomatoes and simmer briskly for 12 minutes until the sauce thickens and tastes concentrated rather than tinny.","Season the shrimp, then slide them into the bubbling sauce in a single layer and cook 3 to 4 minutes, turning once, until they curl into loose commas and turn opaque pink.","Scatter the feta over the surface, cover, and let it soften for 2 minutes so the cheese slumps into creamy pockets throughout the stew.","Pull the pan off the heat immediately and serve in warm bowls before the shrimp can even think about overcooking."],"tip":"A shrimp curled into a tight O is overcooked; aim for a relaxed C, like it''s lounging in the sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_salmon_potato_chowder_stew', '{"id":"smoky_salmon_potato_chowder_stew","name":"Smoky Salmon and Potato Chowder Stew","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"potatoes","q":500},{"f":"milk","q":500},{"f":"broth","q":250},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"carrots","q":100},{"f":"butter","q":30}],"steps":["Melt the butter in a heavy pot over medium heat and sweat the diced onion, celery, and carrots for 6 minutes until soft and sweet-smelling, without letting them color.","Add the potatoes cut into 2-centimeter cubes, pour in the broth and milk, and bring to the barest simmer with lazy bubbles just breaking the surface.","Cook gently for 15 minutes, stirring occasionally so the milk does not catch, until the potato cubes are tender enough to crush against the pot wall.","Mash a few potatoes into the liquid to thicken the chowder, then lower in the salmon cut into large chunks and poach 5 to 6 minutes until it flakes into rosy petals.","Rest the pot off the heat for 3 minutes, taste for seasoning, and ladle up, keeping the salmon pieces as intact as your patience allows."],"tip":"Keep the heat whisper-low once the milk goes in, because a boiled chowder breaks and no amount of stirring apologizes for that."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_mushroom_hotpot_stew', '{"id":"tofu_mushroom_hotpot_stew","name":"Savory Tofu and Mushroom Hotpot Stew","emoji":"🍲","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":45,"servings":4,"ing":[{"f":"tofu","q":450},{"f":"mushrooms","q":300},{"f":"rice","q":250},{"f":"carrots","q":150},{"f":"spinach","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.3}],"steps":["Start the rice in a small pot with 500 milliliters of water, cover, and simmer on low for 15 minutes, then rest it off the heat while the stew comes together.","Press the tofu briefly between paper towels, cut it into thick 3-centimeter cubes, and set aside so it holds its shape in the broth.","In a large pot, sizzle the minced garlic in the sesame oil over medium heat for 30 seconds, then add the sliced mushrooms and carrots and cook 5 minutes until the mushrooms release their juices and smell earthy.","Pour in 900 milliliters of water and the soy sauce, bring to a gentle simmer, and slide in the tofu cubes to poach for 10 minutes so they swell and soak up the savory broth.","Stir in the spinach until it wilts to a silky green, then ladle the hotpot over scoops of rice in deep bowls."],"tip":"Treat the tofu cubes like sleeping houseguests — move them gently or they will fall apart and haunt your broth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_peanut_butter_stew', '{"id":"sweet_potato_peanut_butter_stew","name":"Sweet Potato and Peanut Butter Stew","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"sweet_potatoes","q":600},{"f":"peanut_butter","q":120},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"spinach","q":150},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a large pot over medium heat and cook the chopped onion for 6 minutes until golden at the edges, then add the minced garlic for 1 minute more.","Stir in the crushed tomatoes and simmer 5 minutes until they thicken slightly and lose their raw tang.","Add the sweet potatoes cut into 3-centimeter chunks along with 700 milliliters of water, bring to a boil, and simmer 15 minutes until a knife slips into the largest piece with only slight resistance.","Whisk the peanut butter with a ladleful of the hot broth in a bowl until smooth, then stir it back into the pot and simmer 5 minutes until the stew turns thick, glossy, and the color of terracotta.","Fold in the spinach until just wilted, rest the pot for a few minutes off the heat, and serve while the aroma is still doing its best work."],"tip":"Tempering the peanut butter with hot broth first saves you from chasing stubborn peanut clumps around the pot like a carnival game."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_kidney_bean_penne_stew', '{"id":"tuscan_kidney_bean_penne_stew","name":"Tuscan Bean and Penne Stew","emoji":"🍝","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":45,"servings":4,"ing":[{"f":"black_beans","q":480},{"f":"penne","q":250},{"f":"crushed_tomatoes","q":400},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"parmesan","q":40}],"steps":["Warm the olive oil in a large pot over medium heat and cook the finely diced onion, carrots, and celery for 8 minutes until soft, sweet, and lightly golden — this soffritto is the stew''s whole personality.","Add the minced garlic for 1 minute, then stir in the crushed tomatoes and simmer 5 minutes until the sauce darkens a shade.","Add the drained kidney beans and 1 liter of water, mash a quarter of the beans against the pot to lend creaminess, and bring everything to a rolling simmer.","Tip in the penne and cook 11 to 13 minutes, stirring often as the pasta drinks the broth, until the penne is tender and the stew is thick enough to mound gently on a spoon.","Rest for 3 minutes off the heat, then serve with parmesan grated generously over each bowl."],"tip":"The pasta keeps drinking broth after the heat goes off, so serve promptly or embrace the fact that you have made a very noble casserole."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_style_pepper_egg_stew', '{"id":"shakshuka_style_pepper_egg_stew","name":"Shakshuka-Style Pepper and Egg Stew","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":35,"servings":4,"ing":[{"f":"eggs","q":8},{"f":"crushed_tomatoes","q":800},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"feta","q":80}],"steps":["Heat the olive oil in a wide, deep skillet over medium heat and cook the sliced onion and bell peppers for 8 minutes until slumped, sweet, and lightly charred in spots.","Add the minced garlic and stir 1 minute, then pour in the crushed tomatoes and simmer 10 to 12 minutes until the sauce thickens enough to hold a spoon-drawn trench.","Use the back of a spoon to press 8 wells into the sauce, then crack an egg into each hollow.","Cover the pan and cook 6 to 8 minutes over low heat until the whites are just set but the yolks still shimmy when you nudge the pan.","Scatter the crumbled feta over the top, rest 2 minutes off the heat, and bring the whole pan to the table like the trophy it is."],"tip":"The eggs keep cooking under the lid even off the heat, so pull them when they look one minute underdone and trust the physics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hearty_mushroom_black_bean_potato_stew', '{"id":"hearty_mushroom_black_bean_potato_stew","name":"Hearty Mushroom, Black Bean, and Potato Stew","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":55,"servings":4,"ing":[{"f":"mushrooms","q":500},{"f":"black_beans","q":400},{"f":"potatoes","q":600},{"f":"carrots","q":200},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"soy_sauce","q":30}],"steps":["Heat half the olive oil in a Dutch oven over medium-high heat and brown the quartered mushrooms in two batches for 5 to 6 minutes each, until deeply golden and meaty-smelling, then set them aside.","Add the remaining oil with the diced onion, carrots, and celery and cook 6 minutes until softened, then stir in the minced garlic for 30 seconds.","Add the potatoes in 3-centimeter chunks, 900 milliliters of water, and the soy sauce, and bring the pot to a steady simmer.","Cook 20 minutes until the potatoes are fork-tender, then return the mushrooms with the drained black beans and simmer 10 minutes more so the flavors knit together.","Crush a few potato chunks against the side of the pot to thicken the gravy, taste for salt, and serve in wide bowls with plenty of that dark, savory broth."],"tip":"Browning mushrooms in batches feels fussy until you taste the difference between seared and steamed — one is dinner, the other is regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cobb_crunch_salad', '{"id":"chicken_cobb_crunch_salad","name":"Grilled Chicken Cobb Crunch Salad","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"bacon","q":60},{"f":"eggs","q":2},{"f":"romaine","q":1},{"f":"cherry_tomatoes","q":150},{"f":"avocado","q":1},{"f":"cheddar","q":40},{"f":"greek_yogurt","q":60},{"f":"lemon","q":0.5},{"f":"garlic","q":0.1},{"f":"olive_oil","q":15},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Simmer the eggs in boiling water for 9 minutes, then shock them in ice water and peel once cool enough to handle.","Meanwhile, cook the bacon in a cold skillet over medium heat for 8 to 10 minutes until deeply crisp, then drain on a plate and pour off all but a slick of fat.","Season the chicken with salt and pepper, rub with olive oil, and sear in the same skillet over medium-high for 5 to 6 minutes per side until golden and 165F inside; rest 5 minutes before slicing against the grain.","Whisk the greek yogurt with lemon juice, grated garlic, a pinch of salt, and a spoonful of water until it drizzles like heavy cream.","Chop the romaine and spread it over a platter, then arrange the sliced chicken, halved eggs, crumbled bacon, halved tomatoes, diced avocado, and cheddar in neat rows.","Drizzle the dressing over everything, grind on more black pepper, and serve while the chicken is still faintly warm."],"tip":"The neat rows are for the photo; toss it all together before eating like an honest person."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_parmesan_salmon_kale_salad', '{"id":"lemon_parmesan_salmon_kale_salad","name":"Lemon-Parmesan Salmon Kale Salad","emoji":"🐟","cuisine":"Italian","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"kale","q":0.8},{"f":"parmesan","q":30},{"f":"bread","q":2.5},{"f":"cherry_tomatoes","q":100},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Tear the bread into rough cubes, toss with a third of the olive oil and a pinch of salt, and toast in a 400F oven for 8 to 10 minutes until golden and rattling-dry.","Strip the kale from its stems, chop it fine, and massage it firmly with a pinch of salt and a squeeze of lemon for a full minute until it darkens and slumps.","Whisk the remaining olive oil with the rest of the lemon juice, grated garlic, half the parmesan, and plenty of black pepper to make a sharp, cloudy dressing.","Season the salmon and sear it skin-side down in a hot skillet over medium-high for 4 minutes until the skin crackles, then flip and cook 2 to 3 minutes more until just opaque at the center.","Toss the kale with the dressing, croutons, and halved tomatoes, then flake the warm salmon over the top in big glossy pieces.","Shower with the remaining parmesan and serve immediately, while the croutons still crunch."],"tip":"Massaging kale feels ridiculous right up until you taste the difference, so commit to the full minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_shrimp_couscous_salad', '{"id":"lemon_shrimp_couscous_salad","name":"Lemon Shrimp and Couscous Salad","emoji":"🍤","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["shellfish","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"couscous","q":120},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"oregano","q":2},{"f":"olive_oil","q":25},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pour the couscous into a bowl with a pinch of salt, cover with an equal volume of boiling water, seal with a plate, and let it steam for 5 minutes before fluffing with a fork.","Pat the shrimp very dry, toss with minced garlic, oregano, salt, and pepper, and sear in a splash of the olive oil over high heat for about 90 seconds per side until pink and curled into loose commas.","Whisk the remaining olive oil with the lemon juice and zest and a good grind of pepper to make a bright dressing.","Fold the diced cucumber, halved tomatoes, olives, and chopped parsley into the fluffed couscous with most of the dressing.","Pile the shrimp on top, crumble over the feta, and finish with the last spoonful of dressing.","Taste and adjust with more lemon or salt; it should taste like a beach vacation, not a grain bowl."],"tip":"Shrimp go from perfect to pencil erasers in about 40 seconds, so pull them the moment they curl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_tuna_white_bean_salad', '{"id":"tuscan_tuna_white_bean_salad","name":"Tuscan Tuna and White Bean Salad","emoji":"🫘","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"white_beans","q":300},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"celery","q":60},{"f":"olives","q":50},{"f":"parsley","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"salt","q":2},{"f":"black_pepper","q":2}],"steps":["Slice the onion into paper-thin half moons and soak them in ice water for 10 minutes to tame their bite while you prep everything else.","Whisk the olive oil with the lemon juice and zest, salt, and a heavy grind of black pepper in the bottom of a wide serving bowl.","Add the drained white beans, thinly sliced celery, olives, and the drained onions, and toss gently so the beans slick up without breaking apart.","Flake the drained tuna over the top in large chunks and fold it in just once or twice, keeping the pieces bold and visible.","Add the spinach and chopped parsley, toss lightly, and let the salad sit for 5 minutes so the beans drink in the dressing.","Serve at room temperature, when the flavors are loudest."],"tip":"Resist the urge to stir enthusiastically; mashed tuna and bean paste is a different, sadder recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_peanut_crunch_salad', '{"id":"crispy_tofu_peanut_crunch_salad","name":"Crispy Tofu Peanut Crunch Salad","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","nuts","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.5},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":30},{"f":"lime","q":1.5},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"ginger","q":10}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then tear it into rough bite-size chunks; the craggy edges crisp better than neat cubes ever will.","Toss the tofu with half the soy sauce, then pan-fry in the olive oil over medium-high heat for 10 to 12 minutes, turning occasionally, until the pieces are deeply golden and sound hollow when tapped with a spatula.","Whisk the peanut butter with the remaining soy sauce, lime juice, maple syrup, sesame oil, grated ginger, and enough warm water to reach a pourable, ribbon-off-the-whisk consistency.","Shred the cabbage as thin as you can manage, julienne the carrots, and slice the bell pepper and scallions into slivers.","Toss the vegetables with two-thirds of the dressing until everything glistens, then top with the hot tofu and torn cilantro.","Drizzle the remaining dressing over the top and serve while the tofu still crackles against the cold crunch."],"tip":"Torn tofu is the rare case where being lazy and sloppy actively improves the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_kachumber_salad', '{"id":"chickpea_kachumber_salad","name":"Chickpea Kachumber Salad","emoji":"🥒","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"cilantro","q":0.5},{"f":"lime","q":1.5},{"f":"ginger","q":10},{"f":"cumin","q":3},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Toast the cumin in a dry skillet over medium heat for about 60 seconds, swirling constantly, until it smells warm and nutty; tip it out immediately so it does not scorch.","Dice the cucumber, tomatoes, and onion into small, even pieces so every spoonful carries a bit of each.","Warm the olive oil in the same skillet, add the drained chickpeas with the chili powder and a pinch of salt, and fry for 5 to 6 minutes until they blister and turn lightly golden at the edges.","Whisk the lime juice with the grated ginger, toasted cumin, and remaining salt in a large bowl.","Add the warm chickpeas and diced vegetables and toss well, letting the heat of the chickpeas coax the juices out of the tomatoes.","Fold in the chopped cilantro just before serving and taste; it should be bright, spicy, and a little bit rowdy."],"tip":"Warm chickpeas plus cold crunchy vegetables is the whole trick, so do not let the chickpeas sit around cooling off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_feta_walnut_salad', '{"id":"lentil_feta_walnut_salad","name":"Lentil, Feta, and Walnut Salad","emoji":"🌿","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":180},{"f":"feta","q":80},{"f":"walnuts","q":40},{"f":"carrots","q":100},{"f":"celery","q":80},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.1},{"f":"balsamic_vinegar","q":20},{"f":"olive_oil","q":25},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Simmer the lentils in well-salted water for 20 to 25 minutes until tender but still holding their shape with a gentle pop, then drain well.","While they cook, toast the walnuts in a dry skillet over medium heat for 4 to 5 minutes until fragrant, then chop them roughly.","Whisk the balsamic vinegar with the olive oil, grated garlic, oregano, salt, and pepper into a glossy dressing.","Toss the warm lentils with the dressing right away so they absorb it as they cool, about 10 minutes.","Fold in the finely diced carrots, celery, and onion, then the spinach, letting the residual warmth barely wilt the leaves.","Crumble the feta over the top, scatter on the walnuts, and finish with a last grind of pepper."],"tip":"Dressing lentils while warm is non-negotiable; cold lentils absorb flavor about as well as gravel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_lime_salad', '{"id":"black_bean_avocado_lime_salad","name":"Black Bean and Avocado Lime Salad","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"black_beans","q":400},{"f":"avocado","q":1},{"f":"corn_frozen","q":150},{"f":"bell_pepper","q":1},{"f":"romaine","q":0.5},{"f":"onion","q":0.5},{"f":"cilantro","q":0.5},{"f":"lime","q":2},{"f":"cumin","q":2},{"f":"chili_powder","q":2},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Char the corn in a dry skillet over high heat for 4 to 5 minutes without stirring too often, until a good scattering of kernels turns toasty brown.","Whisk the lime juice with the olive oil, cumin, chili powder, and salt in a large bowl until the dressing looks slightly thickened.","Add the drained black beans, charred corn, diced bell pepper, and finely diced onion, and toss until everything is coated.","Let the mixture marinate for 10 minutes so the beans soak up the lime while you chop the romaine.","Fold in the diced avocado and chopped cilantro gently, keeping the avocado in proud green chunks.","Pile the bean mixture over the chopped romaine and serve with extra lime wedges on the side."],"tip":"Char the corn until you are slightly nervous about it; timid corn is just warm corn."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_crunch_salad', '{"id":"beef_taco_crunch_salad","name":"Beef Taco Crunch Salad","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"romaine","q":1},{"f":"tortillas","q":2},{"f":"cheddar","q":50},{"f":"salsa","q":120},{"f":"sour_cream","q":50},{"f":"avocado","q":0.5},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"lime","q":1},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Slice the tortillas into thin strips, toss with the olive oil and a pinch of salt, and bake at 400F for 6 to 8 minutes until golden and shatteringly crisp.","Brown the ground beef in a dry skillet over medium-high heat for 6 to 7 minutes, breaking it into small crumbles and letting it sit undisturbed at the end so it picks up crusty edges.","Add the diced onion, minced garlic, cumin, chili powder, and salt, and cook 3 minutes more until the onion softens and the spices smell toasty, then stir in half the salsa and simmer until it clings.","Whisk the sour cream with the lime juice and a splash of water into a drizzly crema.","Chop the romaine and mound it into bowls, then top with the hot beef, remaining salsa, cheddar, and diced avocado.","Drizzle with the lime crema and crown with the tortilla strips at the very last second so they stay loud."],"tip":"Add the tortilla strips at the table, not in the kitchen, unless you enjoy chewing on regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_noodle_salad', '{"id":"ginger_pork_noodle_salad","name":"Ginger Pork Rice Noodle Salad","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"rice_noodles","q":120},{"f":"cucumber","q":1},{"f":"carrots","q":100},{"f":"cilantro","q":0.5},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"honey","q":20},{"f":"lime","q":1.5},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Slice the pork loin thin, then toss it with half the soy sauce, half the honey, the grated ginger, and the minced garlic; let it sit 10 minutes while you handle the noodles.","Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still springy, then rinse under cold water and drain thoroughly.","Whisk the remaining soy sauce, honey, and lime juice with the sesame oil to make a sweet-sharp dressing.","Sear the pork in the olive oil over high heat in a single layer for about 2 minutes per side, until the edges caramelize and the marinade lacquers into a sticky glaze.","Toss the cold noodles with the dressing, julienned cucumber and carrots, and sliced scallions.","Top with the hot glazed pork and a generous handful of torn cilantro, and eat while the temperatures are still arguing."],"tip":"Crowd the pan and the pork steams; give the slices personal space and they caramelize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_bacon_egg_spinach_salad', '{"id":"warm_bacon_egg_spinach_salad","name":"Warm Bacon and Egg Spinach Salad","emoji":"🍳","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"bacon","q":100},{"f":"spinach","q":200},{"f":"mushrooms","q":150},{"f":"cherry_tomatoes","q":100},{"f":"onion","q":0.5},{"f":"balsamic_vinegar","q":20},{"f":"olive_oil","q":10},{"f":"salt","q":2},{"f":"black_pepper","q":2}],"steps":["Simmer the eggs for 7 minutes for jammy centers, then plunge them into ice water and peel once cool.","Cook the chopped bacon in a skillet over medium heat for 8 minutes until crisp, then scoop it out, leaving every drop of fat behind.","Sear the sliced mushrooms in the bacon fat over medium-high heat for 5 minutes until browned and squeaky-tender, adding the sliced onion for the last 2 minutes.","Pull the pan off the heat, whisk the balsamic vinegar and olive oil into the warm fat with salt and pepper, and let it bubble into a glossy warm dressing.","Pour the hot dressing and mushrooms over the spinach and halved tomatoes in a large bowl, tossing quickly so the leaves wilt just at the edges.","Top with the halved jammy eggs and crisp bacon, and serve immediately, before the wilt turns to surrender."],"tip":"This salad has a five-minute window of greatness, so seat your dinner guests before you dress it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_crunch_salad_2', '{"id":"sesame_edamame_crunch_salad_2","name":"Sesame Edamame Crunch Salad","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","nuts","sesame"],"time":20,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"scallions","q":0.5},{"f":"almonds","q":40},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":15},{"f":"maple_syrup","q":10},{"f":"lime","q":1},{"f":"ginger","q":10}],"steps":["Blanch the edamame in boiling water for 3 to 4 minutes until bright green and tender, then drain and rinse briefly under cold water.","Toast the almonds in a dry skillet over medium heat for 4 minutes, shaking often, until golden and fragrant, then chop them coarsely.","Whisk the soy sauce, sesame oil, maple syrup, lime juice, and grated ginger into a dressing that tastes assertively salty-sweet on its own.","Shred the cabbage into fine ribbons and julienne the carrots and bell pepper so everything is thin enough to tangle together.","Toss the vegetables and edamame with the dressing, squeezing and tossing for a good 30 seconds so the cabbage starts to relax.","Let it sit 5 minutes, then finish with sliced scallions and the toasted almonds right before serving."],"tip":"This salad is actually better after an hour in the fridge, which makes it the rare make-ahead that keeps its crunch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_larb_style_salad', '{"id":"turkey_larb_style_salad","name":"Turkey Larb-Style Lettuce Salad","emoji":"🌶️","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["gluten","soy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.5},{"f":"lime","q":2},{"f":"soy_sauce","q":25},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"chili_powder","q":2},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a large skillet over high heat until it shimmers, then add the ground turkey and press it flat like a burger.","Let it sear undisturbed for 3 minutes until deeply browned underneath, then break it into crumbles and stir in the minced garlic and grated ginger for the final 2 minutes.","Kill the heat and stir in the soy sauce, the juice of both limes, and the chili powder; the mixture should taste sharp, salty, and a little too intense on its own.","Fold in the sliced scallions and most of the cilantro while the turkey is still steaming, letting the herbs wilt slightly into the meat.","Chop the romaine into a wide bowl, scatter over the thinly sliced cucumber, and spoon the hot turkey and all its juices on top.","Finish with the remaining cilantro and serve immediately, scooping the salad up so every bite has hot, cold, and crunch."],"tip":"The dressing should make you wince slightly in the pan, because the mountain of lettuce will dilute it to perfect."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('classic_tuna_melt', '{"id":"classic_tuna_melt","name":"Golden-Crusted Classic Tuna Melt","emoji":"🥪","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"tomato","q":1},{"f":"butter","q":20}],"steps":["Drain the tuna well and fold it with the greek yogurt, finely minced onion, and a big squeeze of lemon until creamy but still chunky.","Butter one side of each bread slice and lay two slices butter-side down in a cold skillet.","Pile the tuna salad onto the bread, shingle on thin tomato slices, blanket with cheddar, and cap with the remaining slices butter-side up.","Set the skillet over medium heat and cook for 4 to 5 minutes per side, pressing gently with a spatula, until the crust is deep golden and crackles when tapped.","Rest the sandwiches for 2 minutes so the molten cheddar sets slightly, then slice on the diagonal and serve hot."],"tip":"A cold skillet start gives the butter time to crisp the bread before the cheese panics and leaks out."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_smash_toast_with_fried_eggs', '{"id":"avocado_smash_toast_with_fried_eggs","name":"Avocado Smash Toast with Crispy-Edged Eggs","emoji":"🥑","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","eggs"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"avocado","q":1},{"f":"eggs","q":4},{"f":"lemon","q":0.5},{"f":"olive_oil","q":15}],"steps":["Toast the bread until it is deeply bronzed and sturdy enough to knock on the counter, about 3 to 4 minutes in a hot toaster or dry skillet.","Halve the avocado and smash the flesh in a bowl with the lemon juice and a pinch of salt, leaving it rubbly rather than smooth.","Heat the olive oil in a nonstick skillet over medium-high until it shimmers, then crack in the eggs and fry for about 3 minutes, until the whites are lacy and crisp at the edges but the yolks still wobble.","Spread the avocado thickly to the very edges of each toast so every bite gets some.","Slide an egg onto each slice, season generously with salt and pepper, and eat immediately while the yolk is still runny enough to sauce the toast."],"tip":"Salt the avocado, not the naked toast, or the seasoning will bounce right off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_hummus_pita_pockets', '{"id":"mediterranean_hummus_pita_pockets","name":"Loaded Mediterranean Hummus Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["gluten","sesame","dairy"],"time":15,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":150},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"feta","q":60},{"f":"spinach","q":40},{"f":"olive_oil","q":10},{"f":"lemon","q":0.5}],"steps":["Warm the pitas in a dry skillet over medium heat for about a minute per side until they puff slightly and smell toasty, then halve them into pockets.","Dice the cucumber and tomato, slice the onion paper-thin, and toss everything with the olive oil, lemon juice, and a pinch of salt so the vegetables glisten.","Swipe a thick layer of hummus inside each pita half, reaching all the way into the seam so no bite is dry.","Stuff the pockets with spinach leaves and the dressed vegetables, packing them snugly but not to bursting.","Crumble the feta over the filling, press the pockets gently closed, and serve while the pita is still warm against the cool crunch inside."],"tip":"Dress the vegetables before stuffing, not after, unless you enjoy chasing lemon juice down your wrist."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('grilled_chicken_pita_with_yogurt_sauce', '{"id":"grilled_chicken_pita_with_yogurt_sauce","name":"Charred Lemon Chicken Pitas with Garlicky Yogurt","emoji":"🍗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"greek_yogurt","q":120},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"cucumber","q":0.5},{"f":"pita","q":2},{"f":"olive_oil","q":15},{"f":"onion","q":0.3},{"f":"tomato","q":1}],"steps":["Slice the chicken into thick strips and toss with the olive oil, the juice of half the lemon, one grated garlic clove, and plenty of salt and pepper.","Sear the chicken in a screaming-hot skillet over medium-high heat for 3 to 4 minutes per side until deeply charred at the edges and cooked through to 165F.","While the chicken rests, grate the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the remaining garlic and lemon juice to make a quick cooling sauce.","Warm the pitas directly over the skillet''s residual heat for 30 seconds per side until soft and pliable.","Slather the yogurt sauce down the center of each pita, pile on the chicken, sliced onion, and chopped tomato, then fold and wrap the bottom in foil or parchment so nothing escapes."],"tip":"Squeezing the cucumber dry feels fussy until the day you skip it and your sauce turns into soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('skillet_tomato_grilled_cheese', '{"id":"skillet_tomato_grilled_cheese","name":"Double-Cheese Grilled Cheese with Jammy Tomato","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"cheddar","q":100},{"f":"mozzarella","q":60},{"f":"tomato","q":1},{"f":"butter","q":30}],"steps":["Slice the tomato thin and let the slices drain on a paper towel for 5 minutes so they concentrate instead of steaming the bread soggy.","Butter the outsides of all four bread slices right to the corners, because a pale corner is a broken promise.","Layer cheddar, tomato, then mozzarella between the slices, putting cheese on both sides of the tomato so it glues the sandwich shut.","Cook in a skillet over medium-low heat for 4 to 5 minutes per side, pressing lightly, until the bread is mahogany and the cheese sighs out at the seams.","Rest for 2 minutes on a rack so the bottom stays crisp, then slice and pull apart slowly to admire the cheese stretch you earned."],"tip":"Medium-low heat is the whole secret; high heat gives you burnt bread hugging cold cheese."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_salmon_flake_toast', '{"id":"lemony_salmon_flake_toast","name":"Lemony Flaked Salmon Toasts with Yogurt Schmear","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"bread","q":4},{"f":"greek_yogurt","q":80},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"spinach","q":60},{"f":"onion","q":0.3}],"steps":["Season the salmon with salt and sear it in half the olive oil over medium-high heat, 4 minutes skin-side down until crisp, then 2 to 3 minutes more until it flakes at a nudge.","While the salmon rests, wilt the spinach in the same pan for about a minute, letting it pick up the savory fond left behind.","Toast the bread until golden and firm, then rub each slice lightly with the cut lemon for a whisper of brightness.","Stir the lemon zest and a squeeze of juice into the yogurt and spread it thickly over the toasts.","Top with the wilted spinach, big flakes of warm salmon, and paper-thin onion, then finish with the remaining olive oil and a crack of black pepper."],"tip":"If the salmon skin sticks, it is not done crisping; give it thirty more seconds and it will release like a gentleman."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('deli_style_egg_salad_sandwich', '{"id":"deli_style_egg_salad_sandwich","name":"Deli-Style Egg Salad Sandwich on Toasted Bread","emoji":"🥚","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"greek_yogurt","q":80},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"bread","q":4},{"f":"romaine","q":0.3}],"steps":["Lower the eggs into boiling water and cook exactly 10 minutes, then shock them in ice water until fully cool so the yolks stay sunny with no gray ring.","Peel and chop the eggs roughly, leaving some yolk chunks the size of dice for a properly rustic texture.","Fold the eggs with the greek yogurt, finely minced onion, lemon juice, and a firm hand of salt and pepper until just combined and creamy.","Toast the bread lightly so it holds its spine against the soft filling.","Lay crisp romaine leaves on two slices, mound the egg salad generously on top, cap with the remaining toast, and press just enough to commit."],"tip":"Chill the egg salad for ten minutes if you can wait; the flavors get friendlier and the sandwich stops sliding around."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_patty_melt', '{"id":"diner_patty_melt","name":"Diner Patty Melt with Deeply Caramelized Onions","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"onion","q":1},{"f":"bread","q":4},{"f":"cheddar","q":80},{"f":"butter","q":25}],"steps":["Slice the onion thin and cook it slowly in a third of the butter over medium-low heat for 12 to 15 minutes, stirring now and then, until it turns the color of caramel and smells sweet.","Shape the beef into two thin, bread-sized patties, season aggressively with salt and pepper, and sear in a hot skillet for about 3 minutes per side until crusty and just cooked through.","Butter the outsides of the bread slices and build each melt with cheddar, a patty, a tangle of onions, more cheddar, and the top slice.","Griddle the sandwiches over medium heat for 3 to 4 minutes per side, pressing with a spatula, until the bread crackles and the cheese fuses everything into one unit.","Slice in half and serve immediately, while the middle is still molten and slightly indecent."],"tip":"Thin patties are the law here; a thick burger turns a patty melt into a construction project."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('blistered_caprese_style_toast', '{"id":"blistered_caprese_style_toast","name":"Blistered Tomato and Mozzarella Toast","emoji":"🍅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"mozzarella","q":150},{"f":"tomato","q":2},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2}],"steps":["Halve the tomatoes and sear them cut-side down in half the olive oil over high heat for 3 to 4 minutes, undisturbed, until the edges blister and blacken in spots.","Meanwhile, toast the bread until deeply golden, then rub each hot slice with the cut garlic clove so it melts invisibly into the crumb.","Tear the mozzarella into ragged pieces and distribute it over the garlic toasts.","Crush the blistered tomatoes gently on top so their hot juices seep into the cheese and bread.","Drizzle with the remaining olive oil, season with flaky salt and black pepper, and serve while the mozzarella is just beginning to slump."],"tip":"Rub the garlic on the toast while it is still hot; cold toast grates the garlic, warm toast absorbs it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_butter_banana_honey_toast', '{"id":"peanut_butter_banana_honey_toast","name":"Griddled Peanut Butter, Banana, and Honey Toast","emoji":"🍌","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","nuts"],"time":10,"servings":2,"ing":[{"f":"bread","q":4},{"f":"peanut_butter","q":80},{"f":"banana","q":2},{"f":"honey","q":20}],"steps":["Toast the bread in a dry skillet over medium heat for 2 to 3 minutes per side until golden and fragrant, which gives a crunchier base than a pop-up toaster.","Spread the peanut butter generously over the hot toast so it loosens and turns glossy.","Slice the bananas into thick coins and shingle them over the peanut butter in overlapping rows.","Return the toasts to the skillet for one minute, covered, so the bananas warm and soften at their edges.","Drizzle with honey, add a small pinch of salt to sharpen the sweetness, and serve while everything is warm and slightly melty."],"tip":"That tiny pinch of salt at the end is the difference between a snack and a dessert you would defend in court."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('whipped_ricotta_walnut_honey_toast', '{"id":"whipped_ricotta_walnut_honey_toast","name":"Whipped Ricotta Toast with Toasted Walnuts and Honey","emoji":"🍯","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"bread","q":4},{"f":"ricotta","q":200},{"f":"honey","q":30},{"f":"walnuts","q":40},{"f":"lemon","q":0.5}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until they smell rich and take on a shade of color, then chop them roughly.","Whip the ricotta vigorously with the lemon zest and a pinch of salt until it turns light, glossy, and spreadable like frosting.","Toast the bread until the surface is crisp and deeply golden but the center still has a little chew.","Swoop the whipped ricotta over each slice in thick, dramatic waves.","Scatter the warm walnuts on top, drizzle with honey, and finish with a few drops of lemon juice to keep the richness honest."],"tip":"Whipping ricotta takes ninety seconds and upgrades it from grainy to cloud; do not skip it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smashed_chickpea_salad_sandwich', '{"id":"smashed_chickpea_salad_sandwich","name":"Smashed Chickpea Salad Sandwich with Lemon and Hummus","emoji":"🌱","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"hummus","q":60},{"f":"lemon","q":0.5},{"f":"onion","q":0.3},{"f":"cucumber","q":0.3},{"f":"olive_oil","q":10},{"f":"bread","q":4},{"f":"spinach","q":30}],"steps":["Smash the chickpeas in a bowl with a fork until about half are crushed into a rough paste and half remain whole, giving the salad both body and bite.","Fold in the hummus, olive oil, lemon juice, finely minced onion, and diced cucumber, then season boldly with salt and pepper.","Taste and adjust; chickpeas drink up lemon and salt, so it usually needs more of both than you expect.","Toast the bread until golden so it can stand up to the hearty filling.","Layer spinach on two slices, pile the chickpea smash high, top with the remaining toast, and press gently before slicing in half."],"tip":"Leave half the chickpeas whole on purpose; a fully smooth mash eats like spackle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_mushroom_parmesan_toast', '{"id":"garlicky_mushroom_parmesan_toast","name":"Garlicky Mushroom Toast with Parmesan and Spinach","emoji":"🍄","cuisine":"American","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"garlic","q":0.3},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"bread","q":4},{"f":"parmesan","q":40},{"f":"spinach","q":60}],"steps":["Slice the mushrooms thick and sear them in the olive oil over high heat in a single layer, resisting the urge to stir for the first 3 minutes so they brown instead of steam.","Once the mushrooms are deeply golden and squeaking has turned to sizzling, add the butter and minced garlic and toss for one fragrant minute.","Pile in the spinach and stir until it just collapses into the buttery mushrooms, then season with salt and plenty of black pepper.","Toast the bread until sturdy and golden, because these toppings show no mercy to flimsy bread.","Heap the mushroom mixture onto the toasts, shower generously with grated parmesan, and serve while the cheese softens into the steam."],"tip":"Crowded mushrooms weep and boil; give them room in the pan or cook them in two proud batches."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_shawarma_pita_pockets', '{"id":"chicken_shawarma_pita_pockets","name":"Weeknight Chicken Shawarma Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"olive_oil","q":20},{"f":"pita","q":2},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.5}],"steps":["Slice the chicken into thin strips and toss with half the olive oil, the juice of half the lemon, two minced garlic cloves, and a bold shower of salt, pepper, and any warm spices you love; let it sit 10 minutes while you prep the vegetables.","Heat a heavy skillet over medium-high until a drop of water skitters across it, then lay the chicken in a single layer and cook undisturbed for 3 minutes until deeply browned at the edges.","Flip and cook 3 to 4 minutes more, until the strips are firm to the touch and the pan juices have reduced to a sticky glaze that coats each piece.","Stir the remaining garlic and lemon juice into the yogurt with a pinch of salt to make a quick white sauce, and dice the cucumber, tomato, and onion.","Warm the pitas directly over a low flame or in the dry skillet for 30 seconds per side until puffed and pliable, then halve them into pockets.","Stuff each pocket with chicken and vegetables, spoon the garlicky yogurt generously over the top, and eat while the bread is still warm."],"tip":"Resist the urge to stir the chicken early — those crusty browned edges are the whole personality of a shawarma."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_street_taco_wraps', '{"id":"smoky_beef_street_taco_wraps","name":"Smoky Skillet Beef Taco Wraps","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":4},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"tomato","q":1},{"f":"cheddar","q":40},{"f":"sour_cream","q":40},{"f":"romaine","q":0.3},{"f":"lime","q":1}],"steps":["Set a wide skillet over medium-high heat, add the beef, and press it flat like a burger; leave it alone for 3 minutes so the underside develops a crackly brown crust.","Break the meat into rubble, stir in the diced onion and minced garlic, and cook 4 minutes more until the onion turns translucent and the kitchen smells like taco night.","Add the chopped tomato with a firm pinch of salt and a smoky spice of your choosing, and simmer 3 to 4 minutes until the mixture is juicy but no longer watery.","Warm the tortillas in a dry pan for 20 seconds per side until they smell toasty and bend without cracking.","Pile the beef down the center of each tortilla, then finish with shredded romaine, grated cheddar, a swipe of sour cream, and a hard squeeze of lime before folding."],"tip":"Char one side of each tortilla just past comfortable — a few black freckles do more for flavor than any extra topping."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_shrimp_wraps', '{"id":"chili_lime_shrimp_wraps","name":"Chili-Lime Shrimp Wraps with Cool Crema","emoji":"🍤","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"tortillas","q":4},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"olive_oil","q":15},{"f":"greek_yogurt","q":80},{"f":"romaine","q":0.3},{"f":"garlic","q":0.2}],"steps":["Pat the shrimp bone-dry with paper towels, then toss them with the olive oil, minced garlic, the zest and juice of one lime, and enough chili-forward seasoning to make them blush.","Whisk the yogurt with the juice of the second lime and a pinch of salt until it is pourable, and shred the romaine into thin ribbons.","Heat a skillet over high until it is smoking faintly, then sear the shrimp in a single layer for 90 seconds per side, until they curl into loose commas and turn opaque pink.","Warm the tortillas in the same pan, letting them soak up the garlicky drippings for a few seconds on each side.","Layer romaine, sliced avocado, and shrimp onto each tortilla, drizzle with the lime crema, and fold while everything is still hot."],"tip":"A shrimp curled into a tight O is overcooked — pull them at the C shape and they will finish in the wrap."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smashed_chickpea_hummus_pitas', '{"id":"smashed_chickpea_hummus_pitas","name":"Smashed Chickpea and Hummus Pita Pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"hummus","q":100},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"pita","q":2},{"f":"spinach","q":60}],"steps":["Tip the drained chickpeas into a wide bowl and crush them with a fork until roughly half are mashed and half are still whole, giving the filling both creaminess and bite.","Fold in the olive oil, the juice and zest of the lemon, the finely diced onion, and a generous pinch of salt and pepper, tasting until it makes you squint happily.","Dice the cucumber and tomato small so they tuck neatly into the pockets rather than tumbling out with the first bite.","Toast the pitas until warm and just barely crisp at the edges, about 1 minute per side in a dry skillet, then slice each into two pockets.","Paint the inside of every pocket with a thick layer of hummus, stuff with spinach, the chickpea smash, and the diced vegetables, and press gently to seal."],"tip":"The hummus is not just flavor, it is mortar — a full coat on both inner walls keeps the pocket from springing a leak."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_glazed_tofu_crunch_wraps', '{"id":"sesame_glazed_tofu_crunch_wraps","name":"Sesame-Glazed Tofu Crunch Wraps","emoji":"🌯","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"maple_syrup","q":15},{"f":"tortillas","q":4},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.2}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes, then cut it into finger-length batons; dry tofu is the difference between crisp and sad.","Whisk the soy sauce, maple syrup, sesame oil, and minced garlic into a glossy glaze.","Sear the tofu in a hot nonstick skillet over medium-high for 3 minutes per side until every face is golden and crackled, then pour in the glaze and toss for 60 seconds as it bubbles down to a lacquer that clings to each baton.","While the tofu cooks, shave the carrots into ribbons with a peeler and slice the cucumber into thin planks for cool crunch.","Warm the tortillas, lay in the glazed tofu and raw vegetables, drizzle any pan syrup over the top, and roll them tight like sleeping bags."],"tip":"If your tofu sticks, your pan was not hot enough or your patience was not long enough — usually the second one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_style_tuna_melt_pitas', '{"id":"diner_style_tuna_melt_pitas","name":"Diner-Style Tuna Melt Pita Pockets","emoji":"🫓","cuisine":"American","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":200},{"f":"cheddar","q":80},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"pita","q":2},{"f":"tomato","q":1}],"steps":["Drain the tuna firmly and flake it into a bowl, then fold in the yogurt, finely minced onion, a squeeze of lemon, and enough black pepper to make it interesting.","Halve the pitas into pockets and slip a thin layer of sliced tomato against one inner wall of each.","Divide the tuna salad among the pockets and tuck the grated cheddar right on top of the filling so it melts into every crevice.","Toast the stuffed pitas in a dry skillet over medium heat for 2 to 3 minutes per side, pressing gently with a spatula, until the bread is crisp and golden and cheese peeks out molten at the seams.","Rest them for one full minute before biting — the interior is lava, and it needs a moment to settle into gooey perfection."],"tip":"Greek yogurt gives you the creaminess of mayo with an alibi, and nobody at the table will file a complaint."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sunrise_pepper_egg_burrito_wraps', '{"id":"sunrise_pepper_egg_burrito_wraps","name":"Sunrise Pepper and Egg Breakfast Wraps","emoji":"🌅","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","high-protein"],"allergens":["eggs","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tortillas","q":2},{"f":"cheddar","q":60},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":60},{"f":"olive_oil","q":10}],"steps":["Warm the olive oil in a nonstick skillet over medium heat and cook the diced bell pepper and onion for 4 to 5 minutes until soft and sweet at the edges.","Add the spinach in handfuls and stir just until it collapses into glossy green ribbons, about 1 minute.","Whisk the eggs with a pinch of salt until uniformly yellow, pour them over the vegetables, and drop the heat to low; drag a spatula slowly through the curds every 20 seconds until they are softly set and still glistening.","Kill the heat and scatter the cheddar over the eggs so it melts on residual warmth while you toast the tortillas.","Spoon the eggs down the center of each warm tortilla, fold the sides in, roll from the bottom, and sear the burritos seam-side down for 1 minute to weld them shut."],"tip":"Take the eggs off the heat when they look one minute underdone — carryover cooking is the ghost chef who always finishes the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_salmon_pitas', '{"id":"lemon_garlic_salmon_pitas","name":"Lemon-Garlic Salmon Pitas with Yogurt Sauce","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"pita","q":2},{"f":"greek_yogurt","q":120},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":15},{"f":"spinach","q":50}],"steps":["Rub the salmon with olive oil, salt, pepper, and the zest of the lemon, and let it sit skin-side down while a skillet heats over medium-high.","Sear the salmon skin-side down for 4 minutes without moving it, until the skin releases easily and the sides turn opaque halfway up the fillet.","Flip and cook 2 to 3 minutes more until the flesh flakes under gentle pressure but still looks blushing at the center, then break it into large chunks.","Grate the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the minced garlic, the lemon''s juice, and a pinch of salt for a two-minute tzatziki.","Warm the pitas, halve them into pockets, and layer in spinach, salmon chunks, and thick spoonfuls of the cucumber-yogurt sauce.","Serve immediately, with napkins standing by, because the good ones always drip."],"tip":"Squeeze that grated cucumber like it owes you money, or your sauce will be a puddle by dinnertime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_avocado_fiesta_wraps', '{"id":"black_bean_avocado_fiesta_wraps","name":"Black Bean and Avocado Fiesta Wraps","emoji":"🥑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":20,"servings":2,"ing":[{"f":"black_beans","q":350},{"f":"avocado","q":1},{"f":"tortillas","q":4},{"f":"lime","q":1},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"spinach","q":50},{"f":"olive_oil","q":10},{"f":"garlic","q":0.2}],"steps":["Warm the olive oil in a skillet over medium heat and cook the diced onion and minced garlic for 3 minutes until fragrant and just golden.","Add the drained black beans with a splash of water and a confident pinch of salt and smoky seasoning, then simmer 5 minutes, mashing about a third of them so the mixture turns thick and spoonable.","Mash the avocado with the lime''s juice and a pinch of salt until creamy with a few proud lumps remaining.","Warm the tortillas until soft and steamy, then spread each with the lime-avocado mash edge to edge.","Spoon the beans down the middle, top with diced tomato and spinach, and roll firmly, tucking the ends so nothing escapes on the first bite."],"tip":"Mashing some beans is not cheating — it is the free glue that separates a wrap from a lap full of beans."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_spiced_chicken_wraps', '{"id":"tandoori_spiced_chicken_wraps","name":"Tandoori-Spiced Yogurt Chicken Wraps","emoji":"🌯","cuisine":"Indian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":40,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"tortillas","q":4},{"f":"onion","q":0.5},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":10}],"steps":["Stir two-thirds of the yogurt with the minced garlic, the juice of half the lemon, salt, and a heavy hand of warm spices — the marinade should be tinted and thick enough to cling.","Cut the chicken into bite-size chunks, coat them completely in the marinade, and let them sit at least 15 minutes while the yogurt quietly tenderizes.","Heat the oil in a skillet over medium-high and cook the chicken in a single layer for 8 to 10 minutes, turning occasionally, until the yogurt coating chars in spots and the pieces feel springy.","Slice the onion paper-thin and toss it with the remaining lemon juice and a pinch of salt for a quick pickle, and slice the cucumber into cool half-moons.","Warm the tortillas until pliable, then load each with charred chicken, pickled onion, cucumber, and dollops of the reserved yogurt before rolling snugly."],"tip":"Those blackened yogurt patches are not mistakes, they are the closest a home skillet gets to a tandoor — chase them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_salad_stuffed_pitas', '{"id":"greek_salad_stuffed_pitas","name":"Greek Salad Stuffed Pita Pockets","emoji":"🇬🇷","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"feta","q":120},{"f":"pita","q":2},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.3},{"f":"romaine","q":0.5},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5},{"f":"hummus","q":80}],"steps":["Chop the cucumber and tomatoes into hearty chunks, slice the onion whisper-thin, and shred the romaine into forkable ribbons.","Toss the vegetables with the olive oil, a hard squeeze of lemon, salt, and pepper, and let them sit 5 minutes so the tomatoes release their sweet juices into the dressing.","Crumble in the feta and fold gently, keeping the pieces craggy rather than pulverized.","Toast the pitas until warm and barely golden, halve them into pockets, and swipe hummus thickly along the inside walls.","Pack the salad into the pockets with a spoon, pressing lightly, and pour any bowl juices over the filling like a tiny finishing sauce."],"tip":"Salting the tomatoes five minutes early turns the bottom of your bowl into a vinaigrette you did not have to make."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_egg_salad_pita_pockets', '{"id":"creamy_egg_salad_pita_pockets","name":"Creamy Lemon Egg Salad Pita Pockets","emoji":"🥚","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"greek_yogurt","q":80},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"romaine","q":0.3},{"f":"pita","q":2}],"steps":["Lower the eggs into boiling water and cook exactly 10 minutes, then plunge them into ice water for 5 minutes so the shells slip off cleanly and the yolks stay sunny, not gray.","Chop the peeled eggs roughly, leaving some yolk pieces large enough to stay creamy islands in the salad.","Fold in the yogurt, finely minced onion, a squeeze of lemon, salt, and enough black pepper that you can see it working.","Warm the pitas briefly so they open without tearing, then halve them into pockets and line each with crisp romaine leaves.","Spoon in the egg salad generously, letting the lettuce act as a crunchy raincoat between bread and filling."],"tip":"The lettuce lining is structural engineering — it keeps the pita crisp long enough to survive a lunchbox."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_style_mozzarella_wraps', '{"id":"caprese_style_mozzarella_wraps","name":"Caprese-Style Mozzarella and Tomato Wraps","emoji":"🍅","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"mozzarella","q":150},{"f":"tomato","q":2},{"f":"spinach","q":60},{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"garlic","q":0.1},{"f":"lemon","q":0.5}],"steps":["Slice the tomatoes thick, salt them well, and let them sit on a plate for 5 minutes so the seasoning draws out their sweetest juice.","Tear the mozzarella into ragged pieces, which grab dressing far better than tidy slices ever will.","Whisk the olive oil with the grated garlic clove, a squeeze of lemon, and cracked pepper into a sharp little dressing.","Warm the tortillas in a dry skillet until soft and faintly blistered, about 20 seconds per side.","Layer spinach, tomatoes, and mozzarella down each tortilla, spoon the dressing over everything, then roll tightly and slice on a sharp diagonal.","Return the wraps to the hot pan for 1 minute per side if you want the cheese warm and the outside crackly."],"tip":"Salt the tomatoes, not the cheese — tomatoes reward seasoning with juice, while mozzarella just gets salty and sulks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_street_tacos', '{"id":"chicken_street_tacos","name":"Charred Chicken Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"tortillas","q":6},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"olive_oil","q":15}],"steps":["Slice the chicken breast into thin strips, toss with half the olive oil, the grated garlic, and the juice of one lime, and let it sit for 10 minutes while you prep everything else.","Heat a cast-iron skillet over high heat until it just begins to smoke, then lay the chicken in a single layer and leave it alone for 3 minutes so it develops deep brown, charred edges.","Flip and cook 2 to 3 minutes more until the juices run clear, then transfer to a board and chop into rough, taco-sized bits.","Wipe the skillet, film it with the remaining oil, and toast the tortillas 30 seconds per side until they puff slightly and pick up leopard spots.","Pile the chicken onto the warm tortillas, top with finely diced onion and slices of avocado, and finish with a hard squeeze of the second lime so every bite is bright and smoky."],"tip":"A screaming-hot dry skillet is your al pastor stand-in — if the chicken sizzles politely instead of roaring, the pan was not ready."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crunchy_beef_tacos_classic', '{"id":"crunchy_beef_tacos_classic","name":"Crunchy Weeknight Beef Tacos","emoji":"🥩","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":352},{"f":"tortillas","q":5.3},{"f":"cheddar","q":52.8},{"f":"romaine","q":0.4},{"f":"tomato","q":0.9},{"f":"sour_cream","q":52.8},{"f":"onion","q":0.4},{"f":"olive_oil","q":8.8}],"steps":["Heat the olive oil in a wide skillet over medium-high, add the diced onion, and cook 3 minutes until translucent and fragrant at the edges.","Crumble in the ground beef and press it flat against the pan, letting it sear undisturbed for 2 minutes before breaking it up so you get crispy browned bits, not gray steam-cooked pebbles.","Season aggressively, splash in a few tablespoons of water, and simmer 5 minutes until the liquid reduces to a glossy coating on the meat.","Meanwhile, drape the tortillas directly over the oven rack at 200C for 4 to 5 minutes so they crisp into taco shells that shatter when you bite them.","Load each shell with hot beef, then layer on shredded romaine, diced tomato, grated cheddar, and a cool spoonful of sour cream in strict bottom-to-top order."],"tip":"Cheese goes directly on the hot meat so it melts into glue that holds the whole precarious operation together."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_tacos_lime_crema', '{"id":"shrimp_tacos_lime_crema","name":"Seared Shrimp Tacos with Lime Crema","emoji":"🍤","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"tortillas","q":6},{"f":"greek_yogurt","q":100},{"f":"lime","q":2},{"f":"romaine","q":0.5},{"f":"avocado","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Stir the greek yogurt with the zest and juice of one lime and a pinch of salt, then park the crema in the fridge to thicken while you cook.","Pat the shrimp bone-dry with paper towels, toss with olive oil and grated garlic, and season well — wet shrimp steam, dry shrimp sear.","Get a skillet ripping hot over high heat and cook the shrimp in a single layer, 90 seconds per side, until they curl into loose Cs with pink, blistered edges.","Warm the tortillas in a dry pan for 30 seconds a side until soft and steamy, stacking them under a towel to stay pliable.","Shred the romaine finely and lay it down first as a crunchy bed, then add shrimp, sliced avocado, a drizzle of crema, and a squeeze from the second lime."],"tip":"Shrimp go from succulent to eraser in about 40 seconds, so pull them the moment they curl and trust the carryover heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_avocado_tacos', '{"id":"salmon_avocado_tacos","name":"Blackened Salmon and Avocado Tacos","emoji":"🐟","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["fish","gluten"],"time":30,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"tortillas","q":6},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Rub the salmon fillets with olive oil and a heavy coat of smoky spices, pressing the seasoning on so it forms a crust rather than falling off in the pan.","Sear the salmon skin-side down in a hot skillet over medium-high for 4 minutes, until the skin crackles and releases without a fight.","Flip and cook 2 to 3 minutes more until the flesh flakes at a gentle nudge but still looks glossy in the center, then break it into big, juicy chunks with a fork.","While the salmon rests, mash the avocado with the juice of one lime and a pinch of salt into a rough, chunky smear.","Toast the tortillas over a gas flame or dry pan until spotted, swipe each with avocado mash, top with salmon and thin-sliced onion, and finish with the second lime cut into wedges."],"tip":"The avocado mash is doing crema''s job for free — spread it edge to edge so no bite goes undressed."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_tacos_2', '{"id":"crispy_tofu_tacos_2","name":"Crispy Golden Tofu Tacos","emoji":"🌱","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"tortillas","q":6},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"onion","q":0.5}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then tear it into rough, craggy chunks — torn edges crisp far better than neat cubes.","Toss the pieces with a spoonful of the olive oil, grated garlic, and plenty of salt and smoky seasoning until every ragged surface is coated.","Heat the remaining oil in a wide skillet over medium-high and fry the tofu 8 to 10 minutes, turning only when each side is deeply golden and audibly crunchy.","Warm the tortillas in a dry pan for 30 seconds per side until soft and steaming, keeping them wrapped in a clean towel.","Fill the tortillas with crispy tofu, sliced avocado, and slivered onion, then squeeze lime generously over the top so the richness gets a sharp counterpoint."],"tip":"Tearing tofu instead of cubing it is the single cheapest texture upgrade in the plant-based universe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_tacos', '{"id":"smoky_black_bean_tacos","name":"Smoky Mashed Black Bean Tacos","emoji":"🫘","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"black_beans","q":480},{"f":"tortillas","q":6},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":1},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a skillet over medium and cook half the onion, diced, for 4 minutes until soft and just starting to caramelize at the edges.","Add the minced garlic and cook 30 seconds until fragrant, then tip in the black beans with a splash of water and a big pinch of smoky spice.","Simmer 5 minutes, then mash roughly with the back of a spoon until the mixture is creamy but still studded with whole beans, loosening with water if it tightens up.","Char the tortillas directly over a flame or in a scorching dry pan until they smell toasty and carry black-flecked blisters.","Spread the beans thickly on each tortilla and top with diced tomato, the remaining raw onion, avocado slices, and a bright squeeze of lime."],"tip":"Refried-ish beans thicken as they sit, so keep them a little looser than seems right — they will meet you in the middle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('breakfast_egg_tacos', '{"id":"breakfast_egg_tacos","name":"Soft-Scrambled Breakfast Tacos","emoji":"🍳","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tortillas","q":6},{"f":"cheddar","q":60},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":10}],"steps":["Dice the tomato and onion and cook them in the olive oil over medium heat for 4 minutes, until the onion softens and the tomato slumps into a loose, jammy salsa.","Whisk the eggs with a pinch of salt until no streaks remain, then pour them into the pan and drop the heat to medium-low.","Push the eggs slowly across the pan with a spatula, letting soft folds form, and pull them off the heat while they still look slightly glossy — they finish cooking on the way to the table.","Fold in the grated cheddar so it melts into molten ribbons through the curds.","Warm the tortillas in a dry skillet for 30 seconds per side, fill with the cheesy eggs, and eat immediately while everything is soft, steamy, and drippy."],"tip":"Eggs cooked to perfection in the pan are overcooked on the plate, so bail out early and let physics finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_taco_salad_bowl', '{"id":"chicken_taco_salad_bowl","name":"Chicken Taco Salad Bowl","emoji":"🥗","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"romaine","q":1},{"f":"tomato","q":2},{"f":"avocado","q":1},{"f":"cheddar","q":50},{"f":"lime","q":2},{"f":"olive_oil","q":20},{"f":"onion","q":0.5}],"steps":["Season the chicken breasts generously with taco spices and sear in half the olive oil over medium-high heat, 5 to 6 minutes per side, until the crust is mahogany and the thickest part reads 74C.","Rest the chicken on a board for 5 full minutes — cutting early sends the juices onto the board instead of into your salad.","Chop the romaine into bite-sized ribbons and toss it in a big bowl with the remaining olive oil, the juice of one lime, and a pinch of salt until every leaf glistens.","Slice the chicken against the grain and arrange it over the greens with diced tomato, slivered onion, and fanned avocado.","Shower the bowl with grated cheddar and serve with wedges of the second lime for squeezing at the table."],"tip":"Salting the lettuce itself, not just the toppings, is what separates a taco salad from sad lettuce with stuff on it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_rice_skillet', '{"id":"beef_taco_rice_skillet","name":"One-Pan Beef Taco Rice Skillet","emoji":"🍚","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"rice","q":120},{"f":"black_beans","q":150},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"cheddar","q":50},{"f":"olive_oil","q":10}],"steps":["Brown the ground beef in the olive oil over medium-high heat for 5 minutes, breaking it into crumbles and letting the bottom crust before you stir.","Add the diced onion, bell pepper, and garlic and cook 4 minutes more until the vegetables soften and the pan smells sweet and toasty.","Stir in the rice, chopped tomato, black beans, taco spices, and 300 ml of water, scraping up the browned bits stuck to the pan — that is the flavor deposit paying out.","Cover, drop the heat to low, and simmer 18 minutes without peeking, until the rice is tender and has drunk up the liquid.","Kill the heat, scatter the cheddar over the top, and re-cover for 2 minutes so it melts into a bubbling blanket before serving straight from the skillet."],"tip":"Every time you lift the lid to check the rice, it adds two minutes and subtracts one friendship with dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_taco_lettuce_cups', '{"id":"shrimp_taco_lettuce_cups","name":"Garlic Shrimp Taco Lettuce Cups","emoji":"🥬","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":1},{"f":"lime","q":2},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20}],"steps":["Separate the romaine into whole leaves, rinse, and dry them thoroughly — a wet cup makes a soggy taco, and the sturdy inner leaves make the best boats.","Pat the shrimp dry, toss with half the olive oil, the minced garlic, and a pinch of chili and salt.","Sear the shrimp in a very hot skillet for about 90 seconds per side, until pink, curled, and flecked with golden garlic bits, then hit them with the juice of one lime right in the pan.","Dice the avocado and tomato and toss them gently with the remaining oil and a squeeze of the second lime for a quick chunky salsa.","Spoon shrimp into each romaine cup, top with the avocado salsa, and serve immediately while the leaves still snap."],"tip":"Double up the romaine leaves per cup unless you enjoy garlic-lime shrimp escaping into your lap."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_feta_tacos', '{"id":"sweet_potato_feta_tacos","name":"Roasted Sweet Potato and Feta Tacos","emoji":"🍠","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":450},{"f":"tortillas","q":6},{"f":"feta","q":70},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Heat the oven to 220C and cut the sweet potatoes into 1.5 cm cubes — small enough to caramelize, big enough not to vanish in a tortilla.","Toss the cubes with olive oil, minced garlic, smoky spices, and salt, then spread them on a sheet pan with breathing room between pieces.","Roast 25 minutes, flipping once halfway, until the edges are burnished and sticky and a fork slides in with no resistance.","While they roast, slice the onion paper-thin and soak it in the lime juice with a pinch of salt to make a two-minute quick pickle.","Warm the tortillas in a dry skillet until pliable, pile in the roasted sweet potatoes, crumble the feta over the top, and finish with the tangy pickled onions."],"tip":"A crowded sheet pan steams instead of roasts — give the sweet potatoes personal space and they will reward you with caramel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zesty_tuna_tacos', '{"id":"zesty_tuna_tacos","name":"Zesty Pantry Tuna Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"tortillas","q":6},{"f":"greek_yogurt","q":80},{"f":"lime","q":2},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"romaine","q":0.5}],"steps":["Drain the tuna well and flake it into a bowl, breaking up any dense chunks so the dressing can reach everything.","Fold in the greek yogurt, the zest and juice of one lime, finely diced onion, and a good pinch of chili and salt until the mixture is creamy but not soupy.","Taste and adjust — canned tuna drinks acid, so it probably wants more lime than you think.","Toast the tortillas in a dry skillet over medium-high for 30 seconds per side until warm, spotted, and flexible.","Layer shredded romaine on each tortilla for crunch, mound the tuna salad on top, add avocado slices, and serve with wedges of the second lime."],"tip":"This is the taco you make when the fridge is empty and dinner is in 15 minutes — keep the canned tuna hidden from your future self."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_taco_soup', '{"id":"chicken_taco_soup","name":"Shredded Chicken Taco Soup","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"broth","q":1000},{"f":"black_beans","q":400},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"lime","q":2},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a soup pot over medium and cook the diced onion and bell pepper for 5 minutes, until soft and starting to catch color at the edges.","Add the minced garlic and a heavy spoonful of taco spices and toast for 60 seconds, until the whole kitchen smells like a taqueria.","Add the chopped tomatoes, black beans, broth, and whole chicken breasts, bring to a boil, then reduce to a gentle simmer for 20 minutes.","Lift out the chicken, shred it with two forks into ragged strands, and return it to the pot for 5 more minutes so it soaks up the smoky broth.","Squeeze in the juice of one lime, taste for salt, and serve steaming with the second lime in wedges — the acid at the end is what makes the flavors snap into focus."],"tip":"Simmer means lazy bubbles, not a rolling boil — boiled chicken breast shreds into packing material instead of soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_enchilada_skillet_2', '{"id":"chicken_enchilada_skillet_2","name":"Skillet Chicken Enchiladas with Charred Tomato Sauce","emoji":"🍗","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"tortillas","q":3},{"f":"cheddar","q":70},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"sour_cream","q":40}],"steps":["Halve the tomatoes and sear them cut-side down in a dry 10-inch skillet over high heat for 4 minutes, until blistered and blackened in spots, then blend them with the garlic and a splash of water into a loose, brick-red sauce.","Wipe out the skillet, heat the olive oil over medium-high, and cook the chicken breast, cut into 2-centimeter chunks, with the sliced onion for 6 to 7 minutes until the edges brown and the onion softens.","Pour in the tomato sauce and simmer for 5 minutes, until it thickens enough to coat the back of a spoon and turns a shade darker.","Tear the tortillas into rough wedges and fold them through the sauce so every piece is slicked and starting to soften, about 2 minutes.","Scatter the cheddar over the top, cover, and let it melt for 3 minutes until glossy and pulling into strands.","Dollop with sour cream straight from the skillet while the cheese is still bubbling at the edges."],"tip":"Tearing the tortillas instead of rolling them is not laziness, it is strategy: more sauce-soaked edges per bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_burrito_rice_bake', '{"id":"chicken_burrito_rice_bake","name":"Cheesy Chicken Burrito Rice Bake","emoji":"🧀","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"rice","q":140},{"f":"black_beans","q":120},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":60},{"f":"olive_oil","q":10},{"f":"broth","q":350}],"steps":["Heat the oven to 200C and film a medium baking dish with the olive oil, tilting it so the corners are coated.","Stir together the rinsed rice, diced tomatoes, chopped onion, minced garlic, black beans, and hot broth in the dish until the rice is evenly submerged.","Nestle the chicken breast, sliced into thick strips, on top so the pieces sit half-buried in the liquid like rafts.","Cover tightly with foil and bake for 35 minutes, until the rice has drunk up the broth and the chicken registers 74C at its thickest point.","Uncover, shower the cheddar over everything, and bake 8 more minutes until the top is molten with a few bronzed patches.","Rest for 5 minutes before serving so the rice sets from soupy to spoonable."],"tip":"Resist peeking under the foil before 35 minutes; every peek costs you steam, and steam is what cooks the rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_burrito_tortilla_bake', '{"id":"beef_burrito_tortilla_bake","name":"Layered Beef Burrito Bake","emoji":"🌯","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":50,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":3},{"f":"black_beans","q":120},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":60},{"f":"sour_cream","q":50}],"steps":["Brown the ground beef in a hot skillet for 6 to 8 minutes, pressing it flat and leaving it alone until a deep crust forms before breaking it up with the onion and garlic.","Add the chopped tomatoes and black beans and simmer for 8 minutes, mashing a few tomatoes against the pan until the mixture is thick, jammy, and no longer weeping liquid.","In a small baking dish, layer one tortilla, half the beef mixture, and a third of the cheddar, then repeat, finishing with the last tortilla like a lid.","Spread the sour cream over the top tortilla and cap it with the remaining cheddar so it bakes into a tangy, golden crown.","Bake at 190C for 18 to 20 minutes, until the edges bubble audibly and the top is freckled brown.","Cool for 5 minutes, then cut into wedges like a savory cake."],"tip":"A watery filling makes a slumpy bake, so simmer the beef until a spoon dragged through it leaves a clean trail."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_enchilada_skillet', '{"id":"beef_enchilada_skillet","name":"Weeknight Beef Enchilada Skillet","emoji":"🥘","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"tortillas","q":3},{"f":"tomato","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":50},{"f":"olive_oil","q":10}],"steps":["Heat the olive oil in a wide skillet over medium-high and sear the ground beef in one flat layer for 4 minutes until deeply browned underneath, then break it apart.","Add the diced onion, bell pepper, and garlic and cook 4 minutes more, until the pepper slumps and the onion turns translucent at the edges.","Grate the tomatoes directly into the pan on the coarse holes of a box grater, discarding the skins, and simmer 6 minutes until the sauce thickens and stains everything red.","Slice the tortillas into ribbons and stir them in, letting them soften for 2 minutes so they go silky like fresh noodles.","Top with the cheddar, cover, and cut the heat, letting residual warmth melt the cheese into pools for 3 minutes.","Serve straight from the skillet while the edges still sizzle."],"tip":"Grating tomatoes into the pan gives you instant enchilada sauce and leaves the skins behind in your hand, not your dinner."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_enchilada_skillet', '{"id":"sweet_potato_black_bean_enchilada_skillet","name":"Sweet Potato and Black Bean Enchilada Skillet","emoji":"🍠","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":300},{"f":"black_beans","q":240},{"f":"tortillas","q":3},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Cut the sweet potatoes into 1-centimeter cubes and sizzle them in the olive oil over medium heat for 10 minutes, stirring only occasionally so they caramelize at the corners.","Add the chopped onion and garlic and cook 3 minutes until fragrant, then stir in the diced tomatoes and a splash of water, scraping up any stuck browned bits.","Fold in the black beans and simmer 5 minutes, until the sweet potatoes yield to a fork and the sauce clings rather than pools.","Tear in the tortillas and toss for 2 minutes so they soak up the sauce and soften into pliable ribbons.","Kill the heat and finish with fanned avocado slices and a hard squeeze of lime over the whole pan.","Taste one cube of sweet potato before serving; it should be creamy inside with a toasted, candy-like edge."],"tip":"Crowd the pan and your sweet potatoes will steam sadly instead of caramelizing, so give them elbow room."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_burrito_rice_bake', '{"id":"black_bean_burrito_rice_bake","name":"Black Bean Burrito Bake with Crispy Cheddar Top","emoji":"🫘","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"black_beans","q":300},{"f":"rice","q":120},{"f":"tomato","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":80},{"f":"sour_cream","q":50},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C and sweat the onion, bell pepper, and garlic in the olive oil in an ovenproof skillet for 5 minutes, until soft and sweet-smelling.","Add the rinsed rice, chopped tomatoes, black beans, and 300 milliliters of water, stir once, and bring to a lively simmer.","Cover the skillet and slide it into the oven for 25 minutes, until the rice is tender and has absorbed the liquid completely.","Uncover, blanket the surface with cheddar, and bake 10 minutes more until the cheese sets into a crackly, amber-edged crust.","Rest 5 minutes, then serve big spoonfuls with cool dollops of sour cream melting into the heat.","Scrape up the browned cheese at the skillet edge; that lacy frico is the cook''s rightful bonus."],"tip":"The person who washes the skillet gets first claim on the crispy cheese edges, so plan your household negotiations accordingly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_enchilada_tortilla_bake', '{"id":"turkey_enchilada_tortilla_bake","name":"Turkey and Spinach Enchilada Bake","emoji":"🦃","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":50,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"tortillas","q":3},{"f":"spinach","q":100},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"mozzarella","q":70},{"f":"olive_oil","q":10}],"steps":["Brown the ground turkey in the olive oil over medium-high heat for 6 minutes, letting it sit undisturbed at first so it picks up color instead of just going gray.","Add the onion and garlic and cook 3 minutes, then stir in the chopped tomatoes and simmer 8 minutes until the sauce is thick enough to mound on a spoon.","Fold in the spinach by the handful, letting each addition collapse and darken before adding the next.","Layer torn tortillas and the turkey mixture in a small baking dish, ending with sauce, then scatter the mozzarella over the top.","Bake at 190C for 18 minutes, until the cheese is blistered and the sauce bubbles up around the edges like lava at the rim.","Let it stand 5 minutes so the layers firm up enough to serve in tidy scoops."],"tip":"Turkey is a flavor sponge, so season the meat aggressively at the browning stage, not apologetically at the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_burrito_bowl_skillet', '{"id":"turkey_burrito_bowl_skillet","name":"One-Pan Turkey Burrito Skillet with Rice and Beans","emoji":"🍚","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"rice","q":130},{"f":"black_beans","q":120},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"broth","q":300},{"f":"greek_yogurt","q":60},{"f":"lime","q":1}],"steps":["Brown the ground turkey with the chopped onion and garlic in a deep skillet over medium-high heat for 6 minutes, until no pink remains and the pan bottom is glazed brown.","Stir in the rinsed rice and toast it for 1 minute so the grains turn faintly chalky and smell nutty.","Add the diced tomatoes, black beans, and hot broth, scrape the bottom clean, then cover and simmer on low for 18 minutes without stirring.","Check that the rice is tender and the liquid absorbed; if it still slurps, cover and give it 3 more minutes.","Rest off-heat for 5 minutes, then fluff, squeeze the lime over, and crown each portion with a cold spoonful of Greek yogurt.","The contrast of steaming rice and cool tangy yogurt is the whole point, so do not stir it in prematurely."],"tip":"Stirring simmering rice is how you make risotto by accident; hands off until the timer says so."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_enchilada_skillet', '{"id":"shrimp_enchilada_skillet","name":"Shrimp Enchilada Skillet with Zucchini","emoji":"🦐","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"tortillas","q":3},{"f":"zucchini","q":1},{"f":"tomato","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"mozzarella","q":60},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Heat the olive oil in a wide skillet over high heat and sear the shrimp for 90 seconds per side, just until they curl into loose commas, then lift them out.","In the same pan, soften the onion, garlic, and half-moons of zucchini for 4 minutes, until the zucchini edges turn golden but the centers stay firm.","Add the chopped tomatoes and simmer 6 minutes, crushing them with the spoon until they slump into a rustic, pulpy sauce.","Fold in torn tortillas to soak for 2 minutes, then return the shrimp and any pooled juices to the pan.","Scatter the mozzarella over, cover, and let it melt off the heat for 3 minutes so the shrimp finish gently without toughening.","Finish with lime squeezed over the top; the acid wakes up everything."],"tip":"Shrimp go from succulent to rubber bands in about a minute, so pull them early and let the cheese-melting rest finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_sofritas_burrito_bake', '{"id":"tofu_sofritas_burrito_bake","name":"Crispy Tofu Sofritas Burrito Bake","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":50,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":120},{"f":"black_beans","q":150},{"f":"tomato","q":3},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"avocado","q":1}],"steps":["Press the tofu between paper towels for 10 minutes, then crumble it into rough, craggy chunks with your hands rather than cutting neat cubes.","Fry the crumbles in the olive oil over medium-high heat for 8 minutes, undisturbed in stretches, until the edges are golden and crisp like scrambled eggs left to brown.","Add the onion, bell pepper, garlic, and chopped tomatoes and simmer 6 minutes until the vegetables collapse into a chunky, spoon-coating sauce.","Spread the cooked rice and black beans in a baking dish, spoon the sofritas mixture over the top, and bake at 190C for 15 minutes until the surface is sizzling and lightly browned.","Rest for 5 minutes, then fan avocado slices over each portion so they soften slightly in the rising steam.","Serve hot; the crisp tofu edges against the creamy avocado is the bite to chase."],"tip":"Crumbled tofu has more surface area than cubed, and surface area is just a math word for crispiness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('breakfast_burrito_egg_skillet', '{"id":"breakfast_burrito_egg_skillet","name":"Breakfast Burrito Skillet with Eggs and Beans","emoji":"🍳","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["eggs","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"tortillas","q":2},{"f":"black_beans","q":150},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"cheddar","q":50},{"f":"olive_oil","q":10},{"f":"avocado","q":1}],"steps":["Warm the olive oil in a medium skillet over medium heat and soften the chopped onion for 3 minutes until translucent.","Add the diced tomatoes and black beans and simmer 5 minutes, mashing a few beans to thicken the mixture into a loose, saucy hash.","Slice the tortillas into strips, stir them in, and cook 2 minutes so they half-crisp, half-soften like chilaquiles.","Press four wells into the mixture with the back of a spoon and crack an egg into each one.","Scatter the cheddar around the eggs, cover, and cook 4 to 5 minutes until the whites are set but the yolks still shudder when you nudge the pan.","Top with sliced avocado and serve immediately, yolks intact for maximum drama at the table."],"tip":"The lid is doing the cooking here, so if your yolks keep overcooking, blame your peeking, not your stove."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quinoa_pepper_burrito_skillet', '{"id":"quinoa_pepper_burrito_skillet","name":"Smoky Quinoa and Pepper Burrito Skillet","emoji":"🫑","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"quinoa","q":140},{"f":"black_beans","q":180},{"f":"bell_pepper","q":2},{"f":"zucchini","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Char the bell peppers, cut into wide strips, in the olive oil over high heat for 5 minutes until their skins blister black in spots, then add the onion, zucchini, and garlic for 3 minutes more.","Stir in the rinsed quinoa and chopped tomatoes with 300 milliliters of water and bring to a boil, scraping the charred bits into the liquid.","Cover and simmer on low for 15 minutes, until the quinoa uncurls its little tails and the water is gone.","Fold in the black beans and let them heat through for 3 minutes with the lid back on.","Rest 5 minutes off the heat, then fluff and finish with diced avocado and lime squeezed over everything.","Taste and add another squeeze of lime if it does not make you blink slightly."],"tip":"Those blackened pepper spots are not a mistake, they are the smoky backbone of the whole dish, so let them happen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chilaquiles_style_egg_tortilla_bake', '{"id":"chilaquiles_style_egg_tortilla_bake","name":"Chilaquiles-Style Baked Eggs in Tortilla Tomato Sauce","emoji":"🍅","cuisine":"Mexican","meal":["breakfast","dinner"],"diets":["vegetarian"],"allergens":["eggs","gluten","dairy"],"time":45,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":4},{"f":"tomato","q":4},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"spinach","q":80},{"f":"cheddar","q":60},{"f":"olive_oil","q":15}],"steps":["Cut the tortillas into triangles, toss with half the olive oil, and bake at 200C for 8 minutes until they crisp into pale-gold chips.","Meanwhile, cook the onion and garlic in the remaining oil for 3 minutes, add the chopped tomatoes, and simmer 10 minutes until the sauce is thick, glossy, and reduced by a third.","Wilt the spinach into the sauce, then fold in the baked chips so they soften at the edges but keep some crunch in the middle.","Transfer everything to a baking dish, make four hollows, and crack an egg into each.","Scatter the cheddar between the eggs and bake at 190C for 10 to 12 minutes, until the whites are opaque but the yolks still glow and wobble.","Serve within minutes, because the chips are on a countdown from crisp to tender and the sweet spot is now."],"tip":"Chilaquiles are a texture race against time, so have the table set before this bake leaves the oven."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_ragu_penne', '{"id":"beef_ragu_penne","name":"Weeknight Beef Ragu with Penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":225},{"f":"penne","q":150},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"parmesan","q":20},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a wide skillet over medium-high heat and brown the ground beef hard for 6 to 7 minutes, breaking it into rubble and leaving it alone long enough to develop crusty, deeply browned edges.","Add the diced onion and minced garlic and cook 4 minutes more, scraping the fond off the bottom, until the onion turns translucent and the pan smells sweet.","Pour in the crushed tomatoes with the oregano, salt, and pepper, then lower the heat and let the ragu burble gently for 20 minutes until it thickens enough to hold a spoon-trail.","Meanwhile, boil the penne in well-salted water until just shy of al dente, about 9 minutes, and reserve a cup of the starchy cooking water before draining.","Toss the penne into the ragu with a splash of pasta water and simmer 1 minute so the sauce clings glossily to every tube.","Serve showered with grated parmesan and torn basil leaves."],"tip":"The splash of pasta water is not optional — it is the glue that turns sauce-next-to-pasta into an actual ragu."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cacciatore', '{"id":"chicken_cacciatore","name":"Hunter''s Chicken Cacciatore","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"chicken_thigh","q":700},{"f":"crushed_tomatoes","q":500},{"f":"bell_pepper","q":2},{"f":"mushrooms","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"broth","q":200},{"f":"oregano","q":3},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Pat the chicken thighs bone-dry, season generously with salt and pepper, and sear them in the olive oil over medium-high heat for 5 minutes per side until the skin side is burnished mahogany; transfer to a plate.","In the same fat, saute the sliced onion, bell peppers, and mushrooms for 8 minutes, until the mushrooms have released their liquid and everything is picking up brown edges.","Stir in the minced garlic and oregano for 30 seconds until fragrant, then pour in the broth and scrape up every dark bit stuck to the pan.","Add the crushed tomatoes, nestle the chicken back in along with any accumulated juices, and simmer partially covered over low heat for 25 minutes until the thighs are fork-tender and the sauce has thickened to a rustic gravy.","Taste for salt, then scatter chopped parsley over the top and serve straight from the pan."],"tip":"Crowded chicken steams instead of sears, so brown in two batches even when your patience files a formal complaint."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_fra_diavolo', '{"id":"shrimp_fra_diavolo","name":"Shrimp Fra Diavolo Spaghetti","emoji":"🦐","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["shellfish","gluten"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"spaghetti","q":160},{"f":"crushed_tomatoes","q":350},{"f":"garlic","q":0.4},{"f":"olive_oil","q":25},{"f":"chili_powder","q":4},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toss the shrimp with the chili powder and a pinch of salt, then sear them in half the olive oil over high heat for barely 1 minute per side, until pink and curled but not fully cooked; scoop them out.","Lower the heat, add the remaining oil and the sliced garlic, and cook 1 minute until the edges turn pale gold and the kitchen smells dangerous.","Pour in the crushed tomatoes and oregano and simmer briskly for 10 minutes, until the sauce darkens a shade and loses its raw tang.","Meanwhile, boil the spaghetti in salted water until 1 minute shy of al dente and drag it straight into the sauce with tongs, letting some pasta water come along for the ride.","Return the shrimp and finish everything together for 2 minutes, then hit it with a squeeze of lemon and a handful of chopped parsley before serving."],"tip":"Fra diavolo means brother devil, so if your nose is not tingling from the chili, go back and add more."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
